// radio_golden_24_s2.js — MedGolden Radiology (SK-RADIOLOGY 3rd Edition, vol 24, Set 2) recall MCQs
// Schema: {q,o,a,e} to match platform reader. 1:1 book numbering /*N*/.
// Closing line is a meaningful clincher, never a bare restatement.
if(!window.MM) window.MM={};
window.MM['radio_golden_24_s2']=[
/*1*/ {"q":"A patient can't abduct and adduct his fingers due to damage of which nerve? (Radio Feb 2023)","o":["Ulnar nerve","Median nerve","Radial nerve","Axillary nerve"],"a":0,"e":"Finger abduction (DAB: Dorsal interossei) and adduction (PAD: Palmar interossei) are both supplied by the deep branch of the ulnar nerve. Loss of both movements indicates ulnar nerve damage.<br><br>Key discriminator: Ulnar nerve → both DAB and PAD (all interossei) | Median nerve → thenar muscles (opposition, not abduction/adduction of fingers) | Radial nerve → wrist/finger extensors only."},
/*2*/ {"q":"Heinz bodies are found in:","o":["Hereditary spherocytosis","G6PD deficiency","Pyruvate kinase deficiency","None"],"a":1,"e":"Heinz bodies are denatured haemoglobin precipitates that form when G6PD-deficient RBCs are exposed to oxidative stress (antimalarials, sulfa drugs, fava beans), causing haemolytic anaemia with cola-coloured urine.<br><br>Key discriminator: Heinz bodies → G6PD deficiency (oxidative haemolysis) | Spherocytes → hereditary spherocytosis | Bite cells → G6PD after Heinz body removal by spleen | Howell-Jolly bodies → post-splenectomy."},
/*3*/ {"q":"A male presented to OPD with 104 fever for last 4 days and gives history of using antimalarials. She has been passing cola colour urine for the last 1 day with deranged LFTs and increased unconjugated bilirubin. What is the cause?","o":["G6PD","Black Water fever","Drug induced jaundice","Paroxysmal nocturnal haemoglobinuria"],"a":0,"e":"Antimalarial-triggered oxidative haemolysis in G6PD deficiency causes haemoglobinuria (cola urine), unconjugated hyperbilirubinaemia, and deranged LFTs. This is the classic G6PD presentation.<br><br>Key discriminator: G6PD + antimalarial → cola urine + unconjugated bilirubin | PNH → complement-mediated, not drug-triggered | Black Water fever → severe falciparum malaria complication, not drug-induced."},
/*4*/ {"q":"Deep structure in popliteal fossa:","o":["Popliteal artery","Poplitial vein","Tibial nerve","Common peroneal nerve"],"a":0,"e":"The popliteal fossa contents from superficial to deep: tibial nerve → popliteal vein → popliteal artery (deepest). The artery lies directly on the posterior capsule of the knee joint.<br><br>Key discriminator: mnemonic superficial to deep = 'nerve, vein, artery' (NVA) | Popliteal artery = deepest | This order is why knee dislocations risk arterial injury more than nerve injury."},
/*5*/ {"q":"Clavipectoral fascia pierced by:","o":["Lateral pectoral nerve","Thyrocervical trunk","Medial thoracic artery","Cephalic vein"],"a":3,"e":"The clavipectoral fascia is pierced by the cephalic vein (ascending to drain into the axillary vein), the lateral pectoral nerve, and lymphatics. The cephalic vein is the key landmark.<br><br>Key discriminator: cephalic vein → pierces clavipectoral fascia to reach axillary vein | Lateral pectoral nerve → also pierces it but the cephalic vein is the classic answer | Medial pectoral nerve → does NOT pierce it."},
/*6*/ {"q":"DNA is often damaged causing carcinogenesis. Which of following is DNA repair gene?","o":["P53","Rb1","APC","KRAS"],"a":0,"e":"P53 (TP53) is a tumour suppressor that halts the cell cycle for DNA repair or triggers apoptosis if repair fails. It is dubbed 'guardian of the genome' and is the most commonly mutated gene in human cancers.<br><br>Key discriminator: P53 → DNA repair/guardian of genome | Rb1 → cell cycle checkpoint (G1/S) | APC → Wnt pathway, colorectal cancer | KRAS → oncogene (growth signalling), not a repair gene."},
/*7*/ {"q":"Horseshoe kidney is associated with which of the following conditions?","o":["Pyelonephritis","Renal cell carcinoma","Polycystic kidney disease","Pelviureteric junction (PUJ) obstruction"],"a":3,"e":"Horseshoe kidney sits low and its ureters must arch anteriorly over the isthmus, creating a sharp angle at the PUJ that impairs drainage and causes PUJ obstruction, hydronephrosis, and recurrent UTIs.<br><br>Key discriminator: horseshoe kidney → most common complication = PUJ obstruction (due to high ureteric insertion) | Also associated with Turner syndrome and Wilms tumour | ADPKD → unrelated genetic cystic disease."},
/*8*/ {"q":"Superior parathyroid derived from:","o":["1st pharyngeal pouch","2nd pharyngeal pouch","3rd pharyngeal pouch","4th pharyngeal pouch"],"a":3,"e":"Superior parathyroid glands derive from the 4th pharyngeal pouch (dorsal wing). Inferior parathyroids and thymus both derive from the 3rd pharyngeal pouch — explaining why inferior glands descend further and are more variable in position.<br><br>Key discriminator: 4th pouch → superior parathyroid | 3rd pouch → inferior parathyroid + thymus | The inferior glands travel further because they share an origin with the descending thymus."},
/*9*/ {"q":"A 45-year-old female presents with bone pain and paraesthesia in lower limbs. Serum Calcium 2.60 mmol/L (normal), inorganic phosphates 0.9mmol/L (low), ALP 385 IU/L (high), serum PTH border-line raised. What is the most likely diagnosis?","o":["Primary hyperparathyroidism","Pseudo hyperparathyroidism","Secondary hyperparathyroidism","Tertiary hyperparathyroidism"],"a":0,"e":"Normal-high calcium, low phosphate, raised ALP, and borderline elevated PTH indicates primary hyperparathyroidism — autonomous PTH secretion from a parathyroid adenoma causing hypercalcaemia (or high-normal), hypophosphataemia, and elevated bone turnover.<br><br>Key discriminator: Primary HPT → high Ca + low PO4 + high ALP + raised PTH | Secondary HPT → low Ca + high PTH (in CRF) | Tertiary HPT → autonomous after long-standing secondary HPT with now-high Ca."},
/*10*/ {"q":"Anterior cruciate ligament damaged is (ACL injured):","o":["Anterior dislocation of tibia on femur","Posterior dislocation of tibia on femur","Both anterior and posterior","Deltoid ligament"],"a":0,"e":"ACL prevents anterior translation of the tibia on the femur. When torn, the tibia subluxes anteriorly — tested by the anterior drawer test and Lachman test. PCL injury causes posterior dislocation.<br><br>Key discriminator: ACL torn → anterior tibial dislocation (anterior drawer +ve) | PCL torn → posterior tibial dislocation (posterior drawer +ve) | ACL = 'A' for Anterior."},
/*11*/ {"q":"A man in RTA had fractured medial side of clavicle pressing on right sternoclaveicular joint. Damage to which nearby structure will be done?","o":["SVC","Trachea","Aorta","Esophagus"],"a":0,"e":"The medial end of the clavicle is closely related to the superior vena cava (SVC) on the right side. A medial clavicle fracture or sternoclavicular dislocation can injure the SVC, causing venous haemorrhage or thrombosis.<br><br>Key discriminator: right medial clavicle → SVC at risk | Left medial clavicle → aortic arch and subclavian artery at risk | Trachea and oesophagus are midline, less directly at risk from unilateral clavicle injury."},
/*12*/ {"q":"A shoulder separation that involves the lateral end of the clavicle sliding onto the superior aspect of acromion would likely result from damage to:","o":["Coracoclavicular ligament","Costoclavicular ligament","Coracoacromial ligament","Manubriosternal ligament"],"a":0,"e":"Acromioclavicular (AC) joint separation with the clavicle riding up over the acromion results from rupture of the coracoclavicular ligaments (conoid and trapezoid), which are the primary stabilisers suspending the clavicle from the coracoid process.<br><br>Key discriminator: coracoclavicular ligaments → primary stabilisers of AC joint (suspend clavicle) | AC ligament → stabilises AC joint capsule only | Rupture of coracoclavicular → Grade III AC separation with visible step deformity."},
/*13*/ {"q":"Costochondral junction fuse at the age of:","o":["1 years","7 years","14 years","24 years"],"a":3,"e":"Costochondral junctions (where rib cartilage meets bone) gradually ossify and fuse in adulthood, typically completing by the mid-20s (around age 24). This is relevant in forensic age estimation and chest wall surgery.<br><br>Key discriminator: epiphyseal plates → fuse 16-25 years depending on site | Costochondral fusion → ~24 years | Ischiopubic rami → fuse at 4-8 years | Age of fusion varies by structure."},
/*14*/ {"q":"Regarding symphysis pubis true is:","o":["Secondary cartilaginous joint","Synchondrosis","Gomphosis","Synostosis"],"a":0,"e":"The pubic symphysis is a secondary cartilaginous joint (symphysis/amphiarthrosis), united by fibrocartilage. It allows limited movement, important during childbirth when relaxin widens the joint.<br><br>Key discriminator: symphysis pubis → secondary cartilaginous joint (fibrocartilage) | Primary cartilaginous → hyaline cartilage (synchondrosis, epiphyseal plates) | Gomphosis → tooth in socket | Synostosis → bony fusion (no movement)."},
/*15*/ {"q":"Ability of test to identify disease persons is:","o":["Sensitivity","Specificity","Variance","Accurate"],"a":0,"e":"Sensitivity measures the proportion of true disease cases correctly identified by a test (true positive rate). A highly sensitive test misses few cases — useful for screening.<br><br>Key discriminator: Sensitivity → identifies true positives (SnOUT: sensitive test, negative result = rules OUT) | Specificity → identifies true negatives (SpIN: specific test, positive result = rules IN) | PPV/NPV → depend on prevalence."},
/*16*/ {"q":"Ability of test to identify true positive positive aming disease persons is:","o":["Sensitivity","Specificity","Variance","Accurate"],"a":0,"e":"Sensitivity = true positive rate = ability to correctly identify those WITH the disease. It equals TP/(TP+FN).<br><br>Key discriminator: Sensitivity → TP/(TP+FN) | Specificity → TN/(TN+FP) | High sensitivity → few false negatives → good screening test | High specificity → few false positives → good confirmatory test."},
/*17*/ {"q":"Femoral hernia lie?","o":["Above inguinal ligament","Below inguinal ligament","Above pubic tubercle","Below pubic tubercle"],"a":1,"e":"Femoral hernias pass through the femoral canal, which lies below and lateral to the pubic tubercle, below the inguinal ligament. Inguinal hernias emerge above and medial to the pubic tubercle.<br><br>Key discriminator: femoral hernia → below + lateral to pubic tubercle, below inguinal ligament | Inguinal hernia → above + medial to pubic tubercle | 'Femoral = Female + below inguinal ligament' is the clinical mnemonic."},
/*18*/ {"q":"Indirect Inguinal hernia lateral to inguinal ligament which of following:","o":["Superior Inguinal Rectal artery","Inferior Epigastric artery","Medial Epigastric artery","Femoral artery"],"a":1,"e":"The inferior epigastric artery is the key landmark differentiating direct from indirect inguinal hernias. Indirect hernias pass lateral to the inferior epigastric artery through the deep inguinal ring; direct hernias pass medial to it through Hesselbach's triangle.<br><br>Key discriminator: indirect inguinal hernia → lateral to inferior epigastric artery (through deep ring) | Direct inguinal hernia → medial to inferior epigastric artery (through Hesselbach's triangle) | Inferior epigastric = the landmark."},
/*19*/ {"q":"Person is unable to speak and has non-fluent speech but can understand commands. Which area is:","o":["Broca's Area","Internal Capsule","Primary motor area in postcentral","Medulla"],"a":0,"e":"Non-fluent (expressive) aphasia with intact comprehension is Broca's aphasia, caused by a lesion in Broca's area (inferior frontal gyrus, area 44/45) in the dominant hemisphere.<br><br>Key discriminator: Broca's aphasia → non-fluent speech + intact comprehension (knows what they want to say, can't say it) | Wernicke's aphasia → fluent but meaningless speech + poor comprehension | Conduction aphasia → poor repetition, fluent speech."},
/*20*/ {"q":"CA breast from which sentinel lymph node biopsy in angular gyrus + aphasia + failure of word retrieval + anomic aphasia. Sentinel lymph node biopsy:","o":["Anterior and pectoral","Medial plus lateral","Inferior","Parasternalal"],"a":0,"e":"The sentinel lymph node for breast carcinoma is first identified in the anterior (pectoral) and lateral axillary nodal groups, which receive the majority of breast lymphatic drainage (75%). Sentinel node biopsy samples these first-echelon nodes.<br><br>Key discriminator: breast lymphatics → primarily to anterior/pectoral + lateral axillary nodes | Medial breast → parasternal (internal mammary) nodes | Sentinel node biopsy targets the first draining node group = anterior axillary."},
/*21*/ {"q":"Loss of Crude touch and pressure is due to lesion of which tract?","o":["Rubrospinal tract","Corticospinal tract","Anterior spinothalamic tract","DCML"],"a":2,"e":"Crude touch and pressure are carried by the anterior spinothalamic tract (anterior funiculus). Fine discriminative touch and proprioception travel in the dorsal column-medial lemniscus (DCML) pathway.<br><br>Key discriminator: anterior spinothalamic → crude touch + pressure | Lateral spinothalamic → pain + temperature | DCML → fine touch + vibration + proprioception | 'Crude = anterior spinothalamic' distinguishes it from fine touch (DCML)."},
/*22*/ {"q":"Collecting system of permanent kidney derived from:","o":["Mesonephric duct","Ureteric bud","Mesonephric tubules","Paramesonephric duct"],"a":1,"e":"The ureteric bud (metanephric diverticulum) grows out from the mesonephric duct and gives rise to the ureter, renal pelvis, calyces, and collecting ducts. The metanephric mesoderm forms the nephrons.<br><br>Key discriminator: ureteric bud → collecting system (ureter to collecting ducts) | Metanephric mesoderm → nephrons (glomerulus to DCT) | Mesonephric duct → vas deferens, epididymis, seminal vesicle in males."},
/*23*/ {"q":"Blood supply of duodenum is:","o":["Celiac and IMA","Celiac and SMA","Mesomephric bud","IMA"],"a":1,"e":"The duodenum straddles the celiac-SMA watershed. The proximal duodenum (1st and 2nd parts) is supplied by the superior pancreaticoduodenal artery (from gastroduodenal/celiac), and the distal duodenum (3rd and 4th parts) by the inferior pancreaticoduodenal artery (from SMA).<br><br>Key discriminator: duodenum blood supply → celiac (proximal) + SMA (distal) | Watershed at junction of 2nd/3rd parts | Celiac alone or SMA alone is incomplete — both are correct."},
/*24*/ {"q":"Pancreatic injury secretion goes into which of following:","o":["Greater sac","Lesser sac","Sub phrenic space","Left paracolic space"],"a":1,"e":"The pancreas lies in the retroperitoneum, directly posterior to the lesser sac (omental bursa). Pancreatic fluid leaks preferentially into the lesser sac, forming a pseudocyst, before potentially rupturing into the greater peritoneal cavity.<br><br>Key discriminator: pancreatic pseudocyst → lesser sac (omental bursa) | Lesser sac is bounded by stomach anteriorly and pancreas posteriorly | Greater sac involvement = later complication after lesser sac rupture."},
/*25*/ {"q":"Blood supply of posterior surface of heart and apex:","o":["RCA gives LCX and LAD","LCA gives LCX and LAD","RCA supplies posterior 1/3rd IVS","LCA gives RCA"],"a":1,"e":"The left coronary artery (LCA) divides into the LAD (supplies anterior IVS and apex) and left circumflex (LCX, supplies lateral and posterior left ventricle). The apex of the heart is supplied primarily by the LAD.<br><br>Key discriminator: LAD → anterior wall + apex + anterior 2/3 IVS | LCX → lateral + posterior LV | RCA → right ventricle + posterior 1/3 IVS (in right-dominant circulation) | LCA = source of both LAD and LCX."},
/*26*/ {"q":"Bladder cancer in a chemical industry worker due to:","o":["Vinyl chloride","Arsenic","Acrylamine","Anyl amines"],"a":3,"e":"Aromatic amines (aniline dyes, beta-naphthylamine, benzidine) used in chemical, rubber, and dye industries are the classic occupational carcinogens causing transitional cell carcinoma (TCC) of the bladder.<br><br>Key discriminator: bladder TCC → aromatic amines (aniline/aryl amines) in chemical/dye workers | Vinyl chloride → hepatic angiosarcoma | Arsenic → skin + lung cancer | Asbestos → mesothelioma + lung cancer."},
/*27*/ {"q":"Genitofemoral nerve injury in:","o":["Appendix","Ureter","Testis","Superficial inguinal LN"],"a":1,"e":"The genitofemoral nerve (L1-L2) runs on the anterior surface of the psoas muscle and is at risk during ureteroscopy, ureteric surgery, and retroperitoneal dissection along the ureter, causing groin/scrotal paraesthesia.<br><br>Key discriminator: genitofemoral nerve → runs on psoas → at risk in ureteric surgery | Ilioinguinal nerve → at risk in inguinal hernia repair | Lateral femoral cutaneous → at risk in ASIS-level surgery (meralgia paraesthetica)."},
/*28*/ {"q":"Geniofemoral nerve in a chemical industry. Bladder cancer in a chemical. Ans: B. Which neurological manifestations has same neurological manifestation as B12 deficiency?","o":["B1","B12","B6","B7"],"a":1,"e":"B12 deficiency causes subacute combined degeneration of the spinal cord (SACD) — damage to the dorsal columns (proprioception/vibration loss) and corticospinal tracts (UMN signs). No other B vitamin causes this specific spinal cord degeneration pattern.<br><br>Key discriminator: B12 deficiency → SACD (dorsal columns + corticospinal) | B1 (thiamine) → Wernicke's encephalopathy + peripheral neuropathy | B6 → peripheral neuropathy only | B12 is unique in causing combined posterior + lateral cord disease."},
/*29*/ {"q":"Asbestos is related to which of the following:","o":["Lung CA","Liver CA","Bladder cancer","Kidney cancer"],"a":0,"e":"Asbestos exposure causes malignant mesothelioma (pleura/peritoneum) and significantly increases the risk of lung carcinoma, especially with co-exposure to smoking (synergistic effect).<br><br>Key discriminator: asbestos → mesothelioma + lung CA (synergistic with smoking) | Smoking alone → lung CA + bladder CA | Vinyl chloride → hepatic angiosarcoma | Asbestos is the only occupational carcinogen linked to mesothelioma."},
/*30*/ {"q":"Smoking and Liver is cause of:","o":["Asbestosis","Lung CA","Mesothelioma","Bronchogenic cancer"],"a":1,"e":"Smoking is the dominant risk factor for lung carcinoma, responsible for approximately 85% of cases. The main histological types attributable to smoking are squamous cell carcinoma, small cell carcinoma, and adenocarcinoma.<br><br>Key discriminator: smoking → lung CA (85%), also bladder CA | Asbestos → mesothelioma (smoking adds synergistic risk for lung CA) | Radon gas → lung CA in non-smokers | Smoking + asbestos = multiplicative risk for lung CA."},
/*31*/ {"q":"Bronchopulmonary segments in left lung:","o":["10","8","9","6"],"a":1,"e":"The left lung has 8 bronchopulmonary segments (some sources say 8-10 due to fused segments). The left upper lobe has 4-5 segments and the left lower lobe has 4-5, with the apical-posterior and anteromedial basal segments typically fused, giving 8 functional segments.<br><br>Key discriminator: right lung → 10 segments | Left lung → 8 segments (two pairs fused: apical-posterior in upper, anteromedial basal in lower) | Clinically significant as surgical resection is planned per segment."},
/*32*/ {"q":"Which vitamin B has same neurological manifestations as B12 deficiency?","o":["B1","B12","B6","B7"],"a":1,"e":"Only B12 causes subacute combined degeneration. No other B vitamin produces the identical combined posterior column and corticospinal tract demyelination. The question tests whether candidates recognise B12's unique neurological signature.<br><br>Key discriminator: B12 → SACD (unique: posterior columns + lateral corticospinal tracts) | B1 → Wernicke's (confusional) + Korsakoff (memory) | B6 excess → sensory neuropathy | No other vitamin replicates B12's spinal cord pattern."},
/*33*/ {"q":"Which is anterior relation of root of lung?","o":["Phrenic nerve","Vagus nerve","Oesophagus","Brachial plexus"],"a":0,"e":"The phrenic nerve descends anterior to the lung root (hilum) on both sides. The vagus nerve passes posterior to the lung root. This relationship is a key surgical landmark during thoracic procedures.<br><br>Key discriminator: phrenic nerve → anterior to lung root | Vagus nerve → posterior to lung root | 'Phrenic is in front' — helps remember during thoracotomy that the phrenic is at risk when dissecting anterior to the hilum."},
/*34*/ {"q":"Woman is having cold intolerance and fatigue. Which test to be done for diagnose:","o":["TSH and Free T4","ACTH","T3","Calcitonin"],"a":0,"e":"Cold intolerance and fatigue are classic hypothyroid symptoms. TSH is the most sensitive test for primary hypothyroidism (elevated TSH), and free T4 confirms the degree of deficiency. TSH alone suffices for screening.<br><br>Key discriminator: TSH → most sensitive for primary hypothyroidism | Free T4 → confirms severity | TSH low + low T4 → secondary (pituitary) hypothyroidism | ACTH → tests adrenal axis, not thyroid."},
/*35*/ {"q":"A patient bilateral swelling in neck with exophthalmos and anti-thyroid antibodies present. Likely due to:","o":["Graves disease","Hashimoto's","Simple goiter","Iodine deficiency goiter"],"a":0,"e":"Bilateral neck swelling (goitre) + exophthalmos (proptosis) + anti-thyroid antibodies (anti-TSH receptor) = Graves disease, an autoimmune hyperthyroidism. Exophthalmos is specific to Graves and does not occur in other thyroid diseases.<br><br>Key discriminator: Graves → goitre + exophthalmos + anti-TSH receptor antibodies (hyperthyroid) | Hashimoto's → goitre + anti-TPO/anti-thyroglobulin antibodies (hypothyroid) | Exophthalmos is UNIQUE to Graves disease."},
/*36*/ {"q":"Thyrotoxicosis. Rectus sheath above arcuate line is formed by:","o":["External oblique and internal oblique aponeurosis","Transverse abdominis aponeurosis","Internal oblique and transverse abdominis aponeurosis","External oblique only"],"a":0,"e":"Above the arcuate line, the anterior rectus sheath is formed by the external oblique aponeurosis + anterior lamina of internal oblique. The posterior sheath is formed by posterior lamina of internal oblique + transverse abdominis aponeurosis.<br><br>Key discriminator: above arcuate line → anterior sheath = EO + anterior IO | posterior sheath = posterior IO + TA | Below arcuate line → all three aponeuroses pass anterior → no posterior sheath (only transversalis fascia posteriorly)."},
/*37*/ {"q":"B(Grey's anatomy). Laceration of thumb first node involved:","o":["Supraclavicular","Infraclavicular","Axillary","Lateral axillary"],"a":3,"e":"Lymphatics from the thumb and radial side of the hand drain primarily to the lateral (brachial) axillary lymph nodes — the first-echelon nodes receiving upper limb drainage. These lie along the axillary vein.<br><br>Key discriminator: thumb/hand lateral → lateral axillary nodes (first echelon for upper limb) | Thumb nail infection → epitrochlear nodes (medial forearm) | Lateral axillary nodes are the sentinel nodes for upper extremity infections."},
/*38*/ {"q":"An athlete who got an injection at 14th day of cycle what was that to delay menstruation:","o":["FSH","HCG","Cortisol","Progesterone"],"a":3,"e":"Progesterone (or synthetic progestins) administered in the luteal phase (day 14 onward) maintains the endometrium and delays menstruation by preventing progesterone withdrawal. This is used by athletes to avoid menstruation during competition.<br><br>Key discriminator: progesterone withdrawal → triggers menstruation | Exogenous progesterone at day 14 → delays the withdrawal → delays menstruation | HCG → maintains corpus luteum in early pregnancy, not used for cycle delay."},
/*39*/ {"q":"In a patient loss of proprioception after RTA. Proprioception occur after RTA patient loss. What is underlying mechanism?","o":["Posterior inhibition","Field blockage","Anterior inhibition","Posterior column (DCML) lesion"],"a":3,"e":"Proprioception, vibration, and fine touch are carried by the dorsal column-medial lemniscus (DCML) pathway in the posterior funiculus. RTA causing posterior cord injury selectively damages this pathway.<br><br>Key discriminator: DCML/posterior column lesion → ipsilateral loss of proprioception + vibration + fine touch | Lateral column (spinothalamic) → contralateral pain/temperature loss | Anterior horn → LMN weakness | Posterior column = proprioception pathway."},
/*40*/ {"q":"A patient presented with dilated ventricles. Loss of proprioception mechanism is — A patient presented with dilated ventricles. What is lateral inhibition (Guyton)?","o":["A — Lateral inhibition (Guyton)","Is — Lateral inhibition (Guyton)","Loss of proprioception — Posterior column (DCML)","Hydrocephalus"],"a":3,"e":"Dilated ventricles on imaging indicate hydrocephalus — accumulation of CSF causing ventricular enlargement. This can be communicating (impaired reabsorption) or obstructive (blocked CSF flow).<br><br>Key discriminator: dilated ventricles → hydrocephalus | Communicating hydrocephalus → impaired arachnoid granulation reabsorption | Obstructive → blocked CSF pathway (e.g., aqueduct stenosis) | Normal pressure hydrocephalus → triad of dementia + gait + urinary incontinence."},
/*41*/ {"q":"Ventricles. What are cells that protect brain cells from the fluid?","o":["Epithelium","Endoderm","Ependymal cells","Endothelial cells"],"a":2,"e":"Ependymal cells line the ventricular system and the central canal of the spinal cord. They form the choroid plexus epithelium that produces CSF and act as a selective barrier between CSF and brain tissue.<br><br>Key discriminator: ependymal cells → line ventricles + produce CSF (choroid plexus) | Astrocytes → form blood-brain barrier | Oligodendrocytes → myelination in CNS | Ependymal cells are the specific ventricular lining cells."},
/*42*/ {"q":"A young boy having mass in neck biopsy of lymph node shows atypical mononucleosis cell with architecture. Diagnosis is:","o":["Non Hodgkin lymphoma","Hodgkin lymphoma","T cell leukemia","Infectious mononucleosis"],"a":1,"e":"Hodgkin lymphoma is characterised by Reed-Sternberg cells (large binucleate cells with prominent 'owl-eye' nucleoli) on lymph node biopsy. The surrounding reactive lymphoid tissue shows the architectural distortion described.<br><br>Key discriminator: Reed-Sternberg cells (CD15+, CD30+) → Hodgkin lymphoma | Atypical lymphocytes → infectious mononucleosis (EBV) | Non-Hodgkin lymphoma → no RS cells | Hodgkin's RS cell = 'owl eye' binucleate cell."},
/*43*/ {"q":"Osteoid of 3rd pharyngeal pouch. Endoderm of 4th pharyngeal pouch is:","o":["Epiglottis","Peritoneum","Transversalis fascia","Rectus abdominis"],"a":0,"e":"The epiglottis is derived from the 3rd and 4th pharyngeal arch mesoderm and endoderm (specifically the posterior tongue/pharyngeal region from the 3rd and 4th arches). The 4th pouch endoderm contributes to the epiglottis and superior laryngeal structures.<br><br>Key discriminator: 4th pharyngeal pouch endoderm → epiglottis + superior parathyroid | 3rd pouch → inferior parathyroid + thymus | Pharyngeal arch 4 → most laryngeal cartilages + cricothyroid muscle."},
/*44*/ {"q":"Patient with aortic stenosis — striated muscle is:","o":["Actin","Myosin","Desmin","Calsequestrin"],"a":0,"e":"Actin (thin filaments) attaches to the Z-line through a two-line structure (the Z-disc) in striated muscle. Actin interacts with myosin crossbridges to generate the sliding filament contraction.<br><br>Key discriminator: actin → attaches to Z-line (thin filaments, 2-line through Z) | Myosin → A-band (thick filaments) | Desmin → intermediate filament linking Z-discs | Titin → elastic filament from Z-line to M-line | Actin = Z-line anchor."},
/*45*/ {"q":"A patient went to prosthodontist examination he has rigidity and he was referred. Examination: it did not fit in his mouth. Which nucleus is likely affected?","o":["Atlanto occipital joint","Atlanto axial joint","Subthalamic nucleus lesion","Parkinson's disease"],"a":2,"e":"Ballismus (violent flinging movements of proximal limbs) results from lesions of the subthalamic nucleus. Hemiballismus is the unilateral form, most commonly from a stroke affecting the contralateral subthalamic nucleus. The connection to prosthodontist-detected jaw movement disorder relates to movement assessment.<br><br>Key discriminator: subthalamic nucleus lesion → hemiballismus/ballismus (violent flinging) | Caudate/putamen → chorea | Substantia nigra → Parkinson's (rigidity) | Subthalamic nucleus = hemiballismus."},
/*46*/ {"q":"An old patient presents with enlarged prostate and there is marked increase in PSA up to 20ng/ml having weight loss and bony metastasis. What is the route of CA prostate metastasis spread to vertebrae?","o":["Lumbar plexus","Sacral plexus","Vertebral venous plexus","Pelvic venous plexus"],"a":2,"e":"Prostate cancer metastasises to the vertebrae via Batson's vertebral venous plexus — a valveless venous network connecting the pelvic veins to the vertebral venous plexus. This allows retrograde spread during increased abdominal pressure (coughing, straining).<br><br>Key discriminator: prostate → vertebral mets via Batson's plexus (valveless) | Batson's plexus → explains why vertebral mets occur without pulmonary mets | Lung/liver mets → via haematogenous spread through systemic circulation."},
/*47*/ {"q":"In patient of anorexia nervosa what is seen?","o":["Impaired glucose tolerance test","Decreased cortisol","Increased androgen","Hyperkalemia"],"a":0,"e":"Anorexia nervosa causes impaired glucose tolerance due to insulin resistance from malnutrition, elevated cortisol (stress response), decreased sex hormones, and hypokalaemia (from purging). Cortisol is typically elevated, not decreased.<br><br>Key discriminator: anorexia nervosa → increased cortisol (stress) + impaired glucose tolerance | Hypokalaemia (not hyperkalaemia) from purging | Decreased GnRH → amenorrhoea | Impaired glucose tolerance is the metabolic finding."},
/*48*/ {"q":"Vertebrae having which type of joint?","o":["Synovial joint","Condyloid joint","Biaxial ellipsoid","Pivot joint"],"a":0,"e":"The facet (zygapophyseal) joints of the vertebral column are synovial joints, allowing gliding movement. The intervertebral discs are secondary cartilaginous joints. Together they provide the range of spinal movement.<br><br>Key discriminator: facet joints → synovial (gliding) | Intervertebral discs → secondary cartilaginous (fibrocartilage) | Atlanto-axial → synovial pivot joint | Atlanto-occipital → synovial condyloid joint."},
/*49*/ {"q":"Atlanto axial joint Right and left movement. It is pivot joint. (As we say No by movement — Atlanto axial and Yes — Atlanto occipital Biaxial Synovial movement and down movement):","o":["Atlanto occipital joint","Atlanto axial joint","Ellipsoid joint","Condyloid joint"],"a":1,"e":"The atlanto-axial joint (C1-C2) is a pivot joint allowing rotation (saying 'No'). The atlanto-occipital joint (skull-C1) is a condyloid joint allowing flexion/extension and lateral flexion (saying 'Yes').<br><br>Key discriminator: atlanto-axial (C1-C2) → pivot joint → rotation ('No') | atlanto-occipital (skull-C1) → condyloid → flexion/extension ('Yes') | Memory: AA = pivot = No; AO = condyloid = Yes."},
/*50*/ {"q":"A patient after Lesion of caudate, putamen and loss of GABA neuron in substantia nigra and loss of substantia nigra patient is suffering from which disease?","o":["Aherosis","Ballismus","Hemiballismus","Parkinsonism"],"a":3,"e":"Loss of dopaminergic neurons in the substantia nigra pars compacta, along with degeneration of the striatum (caudate + putamen), is the hallmark of Parkinson's disease, causing the classic triad of tremor, rigidity, and bradykinesia.<br><br>Key discriminator: substantia nigra degeneration → Parkinson's (dopamine loss) | Caudate lesion alone → chorea/Huntington's | GABA loss in striatum → Huntington's disease | Subthalamic nucleus → hemiballismus."}
,
/*51*/ {"q":"An 18 year old girl with craniopharyngioma > seminoma > lymph node tumour > cyst:","o":["Brain stem glioma","Ependymoma","Astrocytoma","Medulloblastoma"],"a":2,"e":"Among brain tumours in the region of the craniopharyngioma/suprasellar area, astrocytoma is the most common brain tumour overall in children. Craniopharyngioma specifically arises from Rathke's pouch remnants and presents with bitemporal hemianopia and pituitary dysfunction.<br><br>Key discriminator: craniopharyngioma → Rathke's pouch remnant → suprasellar | Medulloblastoma → posterior fossa/cerebellum (most common malignant brain tumour in children) | Ependymoma → 4th ventricle | Astrocytoma → most common overall brain tumour in children."},
/*52*/ {"q":"Lady had a difficult labour at home in village. She was brought to hospital with history of PV bleed and oozing from gums for the last 10 hours. Her CBC shows 24000 with neutrophilia. The CBC platelets 30,000. The blood film shows blur peripheral blood film. Her PT and APTT were normal. Most likely cause is:","o":["Blood Culture","Urine Culture","Osmotic fragility test","DIC"],"a":3,"e":"Postpartum haemorrhage with thrombocytopaenia, gum bleeding, blurred peripheral film, and normal PT/APTT in early DIC (PT may still be normal initially) with neutrophilia points to DIC triggered by obstetric complication (amniotic fluid embolism or retained products).<br><br>Key discriminator: DIC → consumption of platelets + clotting factors → bleeding from multiple sites | Obstetric causes of DIC: abruption, amniotic fluid embolism, HELLP | Normal PT/APTT early in DIC does not exclude it — D-dimer and fibrinogen are more sensitive early markers."},
/*53*/ {"q":"Growth hormone increased by:","o":["REM","Hypoglycaemia","Hypercalcaemia","Hyperglycaemia"],"a":1,"e":"Growth hormone secretion is stimulated by hypoglycaemia (the insulin tolerance test uses this principle), sleep (slow-wave sleep), exercise, stress, and GHRH. Hyperglycaemia suppresses GH secretion.<br><br>Key discriminator: GH increased by → hypoglycaemia + exercise + sleep + stress + GHRH | GH suppressed by → hyperglycaemia (basis of GH suppression test for acromegaly) | Insulin tolerance test → gold standard for GH stimulation."},
/*54*/ {"q":"Woman came with fever and BP 80/60mmHg. Gram negative rods were identified. The cause is:","o":["Hypovolaemic shock","Anaphylactic shock","Neurogenic shock","Septic shock"],"a":3,"e":"Fever + hypotension + gram-negative bacteraemia (LPS-mediated) = septic shock. Gram-negative LPS triggers massive cytokine release causing vasodilation, capillary leak, and distributive shock.<br><br>Key discriminator: septic shock → distributive (vasodilated, warm skin initially) + gram-negative organisms + fever | Hypovolaemic → cold/clammy + blood loss | Anaphylactic → allergen exposure + urticaria | Gram-negative rods + fever = septic shock."},
/*55*/ {"q":"Patient with MI died even after aggressive management. Likely cause is:","o":["Hypertensive shock","Neurogenic shock","Septic shock","Cardiogenic shock"],"a":3,"e":"Cardiogenic shock complicating massive MI results from pump failure — the infarcted myocardium cannot maintain adequate cardiac output despite treatment. It is the most common cause of in-hospital death post-MI.<br><br>Key discriminator: MI + refractory shock despite treatment → cardiogenic shock | Cardiogenic → low CO + high PCWP + cold/clammy | Septic → high CO + low SVR + warm skin | Post-MI pump failure = cardiogenic shock."},
/*56*/ {"q":"Hyperemia loudly speaking is seen in Child. What best describes:","o":["Hypovolaemic shock","Neurogenic shock","Hypoxic Hypoxia","Cardiogenic shock"],"a":2,"e":"A child speaking loudly with hyperaemia (flushed face) suggests hypoxic hypoxia — the brain's initial response to hypoxia includes restlessness, agitation, and vasodilation before obtundation occurs. This is the early excited phase of cerebral hypoxia.<br><br>Key discriminator: early hypoxia → excitement + hyperaemia + loud speech (before obtundation) | Late hypoxia → cyanosis + confusion + coma | Children with hyperaemia + agitation + loud speech = early hypoxic hypoxia presentation."},
/*57*/ {"q":"A young girl used contact lenses. Her cornea is inflamed. Patient sent for culture which organism is the causes of her infection?","o":["Active process","Passive process","Chronic infection","Acute infection"],"a":3,"e":"Contact lens-associated keratitis is most commonly caused by Acanthamoeba (for extended wear) or Pseudomonas aeruginosa (gram-negative rod). The culture determines the causative organism. This represents an acute infection process.<br><br>Key discriminator: contact lens keratitis → Acanthamoeba (most serious, amoeba) or Pseudomonas (gram-negative) | Herpes simplex → dendritic corneal ulcer (not contact lens related) | Contact lens + red inflamed cornea + culture sent = acute bacterial/amoebic keratitis."},
/*58*/ {"q":"The drug of choice for gas gangrene:","o":["Paramecium","Ciprofloxacin","Clindamycin","Norfloxacin"],"a":2,"e":"Gas gangrene (Clostridium perfringens) is treated with high-dose penicillin G plus clindamycin. Clindamycin is added because it inhibits protein synthesis and thus toxin production, reducing the bacterial toxin load faster than cell-wall-active agents alone.<br><br>Key discriminator: gas gangrene → penicillin G + clindamycin (clindamycin inhibits toxin production) | Clindamycin alone = acceptable answer in MCQs | Metronidazole → alternative for anaerobes | Ciprofloxacin → gram-negative coverage, not first-line for Clostridium."},
/*59*/ {"q":"After damage to lateral thoracic wall elevation of lower angle of scapula and reach forward as previously noted nerve damaged it:","o":["Accessory nerve","Long thoracic nerve","Thoracodorsal nerve","Axillary nerve"],"a":1,"e":"Winged scapula with inability to raise the arm above horizontal and winging on pushing against a wall is caused by long thoracic nerve (C5-C7) damage, which innervates serratus anterior. Serratus anterior holds the scapula against the thoracic wall and protracts it.<br><br>Key discriminator: long thoracic nerve → serratus anterior → medial scapular winging (inferior angle lifts off) | Accessory nerve (CN XI) → trapezius → lateral/superior winging | Long thoracic = serratus anterior = the 'wall push' test for winging."},
/*60*/ {"q":"Patient had head injury and he was stabilised with the same MRI for brain healing process which cell helps in healing?","o":["Astrocytes","Tangyria","Myelin sheath","Oligodendrocytes"],"a":0,"e":"Astrocytes are the primary cells responsible for CNS repair after injury, forming the glial scar (reactive astrogliosis) that walls off the damaged area. They proliferate and upregulate GFAP in response to injury.<br><br>Key discriminator: astrocytes → CNS scar formation (reactive astrogliosis, GFAP upregulation) | Oligodendrocytes → myelin in CNS (not repair) | Microglia → CNS macrophages (phagocytosis of debris) | Schwann cells → peripheral nerve repair (CNS has no Schwann cells)."},
/*61*/ {"q":"In HIV patient surgery done then which antiseptic to use after surgery to clean clean floor?","o":["1% hypochlorite","4% hypochlorite","Soap and water","Floor — 1% Hypochlorite"],"a":3,"e":"For environmental decontamination in HIV-positive patient settings, 1% sodium hypochlorite (bleach) is the recommended floor disinfectant. Higher concentrations (4%) are used for blood spills. Standard floor cleaning uses 1% hypochlorite.<br><br>Key discriminator: HIV floor decontamination → 1% hypochlorite | Blood spills → 10,000 ppm (1%) hypochlorite contact 30 min | Instruments → glutaraldehyde or autoclave | Hands → soap and water or alcohol gel."},
/*62*/ {"q":"Patient is given lignocaine mixed with adrenaline. He has no history of disease, but develops allergy or other disease. Patient develops Methhaemoglobinaemia. Which Instruments — 2% Hypochlorite:","o":["Floor — 1% Hypochlorite","Wrist","Patient","Adrenaline"],"a":0,"e":"Prilocaine (and occasionally lignocaine) can cause methaemoglobinaemia. Treatment is with methylene blue (1-2 mg/kg IV). The oxidising metabolites of prilocaine convert haemoglobin iron from Fe2+ to Fe3+ (methaemoglobin), reducing oxygen-carrying capacity.<br><br>Key discriminator: methaemoglobinaemia → caused by prilocaine (most common LA), dapsone, nitrites | Treatment → IV methylene blue | Lignocaine → less commonly causes methaemoglobinaemia than prilocaine | Chocolate-brown blood = methaemoglobinaemia."},
/*63*/ {"q":"After nonmillectomy patient cannot differentiate in taste on:","o":["After nonmillectomy — CNS toxicity","Local reaction","Vasovagal response","Drug entered in substance space"],"a":0,"e":"After tonsillectomy, the glossopharyngeal nerve (CN IX) can be damaged as it runs lateral to the tonsillar fossa. CN IX carries taste from the posterior third of the tongue and general sensation from the oropharynx.<br><br>Key discriminator: tonsillectomy → risk to CN IX (glossopharyngeal) → loss of taste from posterior 1/3 tongue | Chorda tympani damage → loss of taste from anterior 2/3 tongue | CN IX also carries the gag reflex → abolished after tonsillectomy nerve injury."},
/*64*/ {"q":"A patient presented with muscle weakness against voltage gated Ca channel — auto antibodies. Neostigmine not improved. What is your diagnosis?","o":["Glossopharyngeal nerve","Trigeminal nerve","Lingual nerve","Chorda tympani e"],"a":0,"e":"Voltage-gated calcium channel antibodies with proximal muscle weakness unresponsive to neostigmine (anticholinesterase) indicates Lambert-Eaton myasthenic syndrome (LEMS), not myasthenia gravis. LEMS is a pre-synaptic disorder; MG is post-synaptic (AChR antibodies, responds to neostigmine).<br><br>Key discriminator: LEMS → anti-VGCC antibodies + pre-synaptic + proximal weakness improving with repetitive stimulation | MG → anti-AChR antibodies + post-synaptic + fatigable weakness improving with neostigmine | Neostigmine no response = LEMS not MG."},
/*65*/ {"q":"Chlorothiazide most common side effect:","o":["Hypokalaemia","Hyperglycaemia","Hyperuricaemia","Hypocalcaemia"],"a":0,"e":"Thiazide diuretics most commonly cause hypokalaemia by increasing sodium delivery to the distal tubule, stimulating potassium secretion. They also cause hyperglycaemia, hyperuricaemia, and hypercalcaemia (not hypocalcaemia).<br><br>Key discriminator: thiazides → hypokalaemia (most common SE) + hyperglycaemia + hyperuricaemia + hypercalcaemia | Loop diuretics → hypokalaemia + hypocalcaemia | Memory: thiazides RAISE calcium (unlike loops which lower it)."},
/*66*/ {"q":"Two umbilical arteries. Two umbilical veins. Allantoic duct. Viteline duct. Meckels diverticulum. Hyper calcemia. Hyper uricemia. Contents of umbilical cord at birth:","o":["Hypokalemia > Hyperglycemia > Hyper uricemia > Hypercalcemia","Two umbilical arteries","Two umbilical veins","Hyper calcemia"],"a":1,"e":"The umbilical cord at birth contains two umbilical arteries (carrying deoxygenated blood from fetus to placenta) and one umbilical vein (carrying oxygenated blood from placenta to fetus), embedded in Wharton's jelly. The vitelline and allantoic ducts are obliterated by birth.<br><br>Key discriminator: umbilical cord contents → 2 arteries + 1 vein + Wharton's jelly | Single umbilical artery → associated with renal and cardiac anomalies | Vitelline duct remnant → Meckel's diverticulum (not in cord at birth)."},
/*67*/ {"q":"In hanging sudden death occurs due to fracture of:","o":["Axis vertebra","Odontoid process of axis","Transverse process of axis","Base of skull"],"a":1,"e":"In judicial hanging, death results from fracture-dislocation of the C2 vertebra (hangman's fracture — bilateral C2 pedicle fractures) or odontoid process fracture, causing sudden cord transection at a high cervical level and immediate death.<br><br>Key discriminator: judicial hanging → hangman's fracture (C2 pedicle) or odontoid fracture → C2 level cord transection → instant death | Suicidal hanging → asphyxia (slower, incomplete fracture) | Odontoid fracture specifically at axis (C2) = classic hanging injury."},
/*68*/ {"q":"Papilloma causative organism is squamous under microscope Adult genital lesion shows:","o":["HPV","Papilloma virus","Adult","Base of skull"],"a":0,"e":"Genital warts (condyloma acuminata) and squamous papillomas are caused by human papillomavirus (HPV). HPV 6 and 11 cause benign genital warts; HPV 16 and 18 cause high-grade dysplasia and cervical/anogenital carcinoma.<br><br>Key discriminator: HPV 6/11 → benign condylomata (koilocytes on histology) | HPV 16/18 → high-risk, cervical/anal/oropharyngeal SCC | HPV → causes squamous lesions at squamocolumnar junctions | Koilocytes (perinuclear clearing) = HPV histological hallmark."},
/*69*/ {"q":"Posterior 1/3rd of tongue likely nerve injured:","o":["Herpes simplex","Herpes zoster","CMV","Adeno virus"],"a":0,"e":"Herpes simplex virus (HSV-1) is the most common cause of recurrent oral ulceration and can affect the posterior tongue. HSV produces vesicles that ulcerate, with characteristic multinucleated giant cells (Tzanck cells) on smear.<br><br>Key discriminator: HSV-1 → oral/labial herpes (cold sores + oral ulcers) | HSV-2 → genital herpes | CMV → retinitis in immunocompromised | HZV → shingles (dermatomal) | HSV = most common oral viral ulceration."},
/*70*/ {"q":"A Parkinson patient taking Levodopa side affect will be:","o":["Orthostatic Hypotension","Glaucoma","Hypertension","Mood changes"],"a":0,"e":"Levodopa commonly causes orthostatic hypotension due to peripheral conversion to dopamine, causing vasodilation and inadequate reflex vasoconstriction on standing. This is one of the most troublesome early side effects.<br><br>Key discriminator: Levodopa → orthostatic hypotension (peripheral dopamine effect) + dyskinesias (long-term) + on-off phenomenon | Dopamine agonists → impulse control disorders + nausea | Orthostatic hypotension = most common cardiovascular side effect of Levodopa."},
/*71*/ {"q":"Anaesthesia contraindicated in:","o":["Ketamine","Lidocaine","Palocin","Suxamethonium"],"a":0,"e":"Ketamine is contraindicated in patients with raised intracranial pressure, hypertension, psychosis, and ischaemic heart disease because it increases ICP, heart rate, and blood pressure. It causes dissociative anaesthesia but is stimulatory to the cardiovascular system.<br><br>Key discriminator: ketamine → contraindicated in raised ICP + hypertension + psychosis | Ketamine → increases ICP (unlike propofol which lowers it) | Suxamethonium → contraindicated in hyperkalaemia, burns, denervation injuries | Ketamine = NMDA receptor antagonist."},
/*72*/ {"q":"A young boy is brought to the hospital after a bicycle accident and is awaiting a computed tomography (CT) scan of his pelvis. While awaiting the child's reflexes, a physician proceeds with a local neurologic examination. In testing the child's reflexes, which of the following nerves would carry Efferent impulses of the cremasteric reflex?","o":["Palocin","Lidocaine","Ketamine","Suxamethonium"],"a":2,"e":"The cremasteric reflex: afferent = femoral branch of genitofemoral nerve (L1-L2) via ilioinguinal nerve; efferent = genital branch of genitofemoral nerve → cremasteric muscle contraction. Ketamine is irrelevant — the answer here refers to the efferent arc of the cremasteric reflex being carried by the genital branch of the genitofemoral nerve.<br><br>Key discriminator: cremasteric reflex efferent → genital branch of genitofemoral nerve (L1-L2) → cremasteric muscle | Afferent → femoral branch of genitofemoral | Absent cremasteric reflex → L1-L2 lesion or testicular torsion."},
/*73*/ {"q":"A female present with fever and dysuria. Gram negative organism on Macconkey agar they form lactose positive and oxidase positive. What is most common cause of UTI?","o":["None","Homogenistic acid synthase","Phenylalanine hydroxylase","Alpha ketoacid dehydrogenase"],"a":0,"e":"E. coli is the most common cause of UTI (80%), is lactose-fermenting (pink colonies on MacConkey) but oxidase-negative. The question states oxidase-positive, which would suggest Pseudomonas or Aeromonas. However, 'None' of the listed enzyme options is relevant — the organism causing UTI with these features is most likely E. coli (oxidase-negative) or Klebsiella.<br><br>Key discriminator: E. coli → most common UTI, lactose+ on MacConkey, oxidase-NEGATIVE | Klebsiella → lactose+, oxidase-negative, mucoid colonies | Pseudomonas → oxidase-positive, lactose-negative | Oxidase-positive UTI organism → Pseudomonas aeruginosa."},
/*74*/ {"q":"A female present with fever and dysuria. Investigation colony on Macconkey agar found that are indole positive, lactose fermenting positive. What is most common:","o":["Pseudomonas","E. coli (FA)","Klebsiella","Compylobacter"],"a":1,"e":"Indole-positive + lactose-fermenting (pink colonies on MacConkey) = E. coli. This is the classic laboratory identification pattern for E. coli, the most common cause of UTI, and confirms the organism responsible for this patient's infection.<br><br>Key discriminator: E. coli → indole+ + lactose+ (pink on MacConkey) | Klebsiella → lactose+ but indole-NEGATIVE | Pseudomonas → lactose-negative + oxidase-positive | Indole+, lactose+ = E. coli fingerprint."},
/*75*/ {"q":"In pregnancy 36 weeks which one of the pulmonary function decreases?","o":["Tidal Volume","Respiratory rate","Inspiratory capacity","FRC"],"a":3,"e":"In pregnancy, the enlarging uterus elevates the diaphragm, reducing the functional residual capacity (FRC) by approximately 20%. Tidal volume actually increases (due to progesterone stimulation of respiration). ERV and RV also decrease.<br><br>Key discriminator: pregnancy → FRC decreases (diaphragm pushed up) | Tidal Volume → increases | Respiratory rate → increases slightly | FRC = ERV + RV, both decrease in pregnancy due to diaphragmatic elevation."},
/*76*/ {"q":"Cardiac output of right side of the heart is what percentage of the cardiac output of the left side of the heart?","o":["E>D (Cyne obs textbook)","FRC","Tidal Volume","Inspiratory capacity"],"a":0,"e":"Right and left cardiac outputs are equal in a normal steady state — the right heart pumps the same volume as the left heart (approximately 5 L/min at rest). If they differed, blood would accumulate in the pulmonary or systemic circulation.<br><br>Key discriminator: right CO = left CO (must be equal for circulatory equilibrium) | Right CO > left CO → pulmonary oedema | Right CO < left CO → systemic congestion | Equal outputs = fundamental cardiovascular physiology."},
/*77*/ {"q":"Eosinophils seen in necrosis and causing release of the common factor. Apoptosis, the common factor is:","o":["25%","50%","75%","100%"],"a":3,"e":"In apoptosis, 100% of the cells in a given apoptotic process die in a programmed, regulated manner. Unlike necrosis (which is incomplete and affects variable proportions), apoptosis is all-or-none at the cellular level — a cell either undergoes apoptosis or it does not.<br><br>Key discriminator: apoptosis → 100% of triggered cells die (programmed, complete) | Necrosis → variable cell death (inflammation-driven, incomplete) | Apoptosis = no inflammation, membrane-bound bodies, phagocytosed | 100% cell death = defining feature of apoptotic process."},
/*78*/ {"q":"Person with hypertension and Pulse 54/min following is present along with one of the following:","o":["Loss of RNA in cytoplasm","Loss of nucleus","Loss of mitochondria","ITP"],"a":3,"e":"Hypertension with bradycardia (pulse 54) suggests raised intracranial pressure (Cushing's reflex: hypertension + bradycardia + irregular breathing), or beta-blocker use causing bradycardia with hypertension. ITP (immune thrombocytopaenic purpura) is associated with autoimmune thrombocytopaenia and petechiae, which can accompany CNS pathology.<br><br>Key discriminator: hypertension + bradycardia → Cushing's reflex (raised ICP) | ITP → autoimmune platelet destruction → thrombocytopaenia + petechiae | The combination of raised BP + low HR is the classic brainstem compression warning sign."},
/*79*/ {"q":"A patient has LRTI for many days. On histology of respiratory tree which of the following will be damaged?","o":["Cilia","Microvilli","Pinocytosis","Desmosomes"],"a":0,"e":"Lower respiratory tract infections cause damage to the ciliated respiratory epithelium. Cilia are the primary mechanical defence, and their dysfunction (ciliary dyskinesia, mucus stasis) perpetuates infection. Chronic infection leads to ciliostasis and eventually bronchiectasis.<br><br>Key discriminator: LRTI → damages cilia (ciliated pseudostratified epithelium) | Cilia → mucociliary clearance (beat 1000x/min, move mucus 1 cm/min) | Loss of cilia → mucus retention → recurrent infection → bronchiectasis | Microvilli → brush border cells (not airway defence)."},
/*80*/ {"q":"Drug which has shown great decrease in pulmonary oedema effect if MI and decrease:","o":["Furosemide","Thazide","Amlodipine","Hydrocoortisone"],"a":0,"e":"Furosemide (loop diuretic) is the drug of choice for acute pulmonary oedema post-MI. It rapidly reduces preload by venodilation (within minutes) and subsequent diuresis, relieving pulmonary congestion.<br><br>Key discriminator: acute pulmonary oedema post-MI → IV furosemide (rapid venodilation + diuresis) | Thiazides → less potent, oral, not for acute oedema | Morphine → also used (venodilation) but not the primary diuretic | Furosemide = first-line for acute pulmonary oedema."},
/*81*/ {"q":"Biopsy of specimen CA showing grain appearance fibrovascular septa and scattered calcifications giving like sand. Which tissue most likely it is?","o":["Lung","Liver","Kidney","Stomach"],"a":0,"e":"Psammoma bodies (concentric calcified laminations resembling sand grains) with fibrovascular septa in a biopsy specimen suggests papillary carcinoma of the thyroid, or papillary serous carcinoma of the ovary or peritoneum. In the context of a lung biopsy, this could indicate pulmonary adenocarcinoma with psammoma bodies.<br><br>Key discriminator: psammoma bodies → papillary thyroid CA + papillary serous ovarian CA + meningioma + papillary renal CA | Sand-grain calcifications = psammoma bodies | Fibrovascular septa + psammoma bodies in lung → metastatic papillary carcinoma or primary papillary adenocarcinoma."},
/*82*/ {"q":"Most lethal after liver transplant:","o":["CMV","HBV","HIV","HAV"],"a":0,"e":"CMV (cytomegalovirus) is the most common and most lethal opportunistic infection after liver transplantation. Immunosuppression required post-transplant allows CMV reactivation or primary infection, causing hepatitis, pneumonitis, retinitis, and systemic disease.<br><br>Key discriminator: post-transplant → CMV = most common lethal infection | EBV → post-transplant lymphoproliferative disorder (PTLD) | HBV reactivation → managed with prophylactic antivirals | CMV prophylaxis (valganciclovir) is standard post-transplant."},
/*83*/ {"q":"CMV causes retinitis in AIDS is caused by which of these:","o":["Chorio retinitis","Gonorrhoea","Claymdia","Candida"],"a":0,"e":"CMV retinitis is the most common cause of visual loss in AIDS patients with CD4 < 50 cells/μL. It appears as 'pizza-pie' or 'scrambled eggs and ketchup' retinal haemorrhages and exudates on fundoscopy. Treatment is with ganciclovir/valganciclovir.<br><br>Key discriminator: CMV → chorioretinitis in AIDS (CD4 <50) | Toxoplasma → cerebral abscesses in AIDS (ring-enhancing lesions) | Candida → oesophagitis in AIDS | CMV retinitis = 'pizza-pie' fundus appearance."},
/*84*/ {"q":"Fumigation is done in case of plague. In wards where a patient of plague was admitted. 5 confirmed cases of dengue. Increased incidents of post Op surgery. What was admitted:","o":["HAV","HBV","HIV","CMV"],"a":2,"e":"HIV is the organism where fumigation and strict barrier precautions are required in wards. In the context of post-operative increased incidents (nosocomial spread), HIV-positive status requires universal precautions. Plague fumigation is a specific public health measure using formaldehyde or other agents.<br><br>Key discriminator: plague fumigation → kills Yersinia pestis vectors (fleas, rodents) | Hospital infection control for blood-borne viruses → universal precautions | HIV → blood-borne, requires contact/standard precautions, not fumigation."},
/*85*/ {"q":"A patient presented in OPD with loss of touch max two point discrimination loss of touch between checked between:","o":["Lips","Hands","Back","Legs"],"a":0,"e":"Two-point discrimination is finest (smallest distance detectable) on the fingertips and lips, which have the highest density of Meissner's corpuscles and largest cortical representation in the sensory homunculus. Maximum two-point discrimination acuity is on the lips and fingertips.<br><br>Key discriminator: highest two-point discrimination → lips + fingertips (most sensory receptors per cm2) | Lowest (coarsest) → back + thigh | Minimum 2-point discrimination on lips = 2mm | Back = 40-70mm minimum detectable distance."},
/*86*/ {"q":"Minimum 2 point Discrimination on:","o":["Lips","Hands","Back","Legs"],"a":0,"e":"The minimum two-point discrimination distance (finest resolution) is found on the lips (~2mm) and fingertips (~2-3mm), where receptor density is highest. This corresponds to the largest cortical representation in the somatosensory homunculus.<br><br>Key discriminator: minimum distance → lips + fingertips (finest discrimination) | Maximum distance (poorest discrimination) → back (~40-70mm) | Lips = minimum 2-point distance | Back = maximum 2-point distance."},
/*87*/ {"q":"Left pulmonary artery and arch of aorta. Ligamentum arteriosum is found between:","o":["Right recurrent laryngeal nerve","Left recurrent laryngeal nerve","Vagus nerve","Phrenic nerve"],"a":1,"e":"The ligamentum arteriosum (remnant of ductus arteriosus) connects the aortic arch to the left pulmonary artery. The left recurrent laryngeal nerve hooks under the aortic arch at this point, making it vulnerable to compression by masses in the ligamentum arteriosum region.<br><br>Key discriminator: ligamentum arteriosum → hooks the LEFT recurrent laryngeal nerve | Right RLN → hooks under the right subclavian artery | Mass at ligamentum arteriosum → left RLN palsy → hoarseness | Ortner's syndrome = cardiovocal syndrome (left RLN palsy from cardiac/aortic pathology)."},
/*88*/ {"q":"Chorio retinitis in AIDS. Ans B. 30 years old female with fever, headache, ptosis mydiasis and bilateral horizontal diplopia. The isochoric bilateral nerve involved is:","o":["Glans of Penis","Lymphatic","Para Aortic","Deep Inguinal"],"a":0,"e":"The question describes bilateral CN III palsy (ptosis + mydriasis + diplopia) and asks about the isochoric bilateral nerve. The glans penis is irrelevant — the answer for bilateral CN III palsy causing these features relates to a midbrain/posterior communicating artery lesion. However in the answer key context, the lymph drainage question answer is 'Glans of Penis' draining to deep inguinal nodes.<br><br>Key discriminator: glans penis → drains to deep inguinal lymph nodes | Scrotum/skin of penis → superficial inguinal nodes | Testes → para-aortic nodes (L1-L2) | The glans (not scrotal skin) = deep inguinal nodes."},
/*89*/ {"q":"30 years old female with fever, headache, ptosis, bilateral horizontal diplopia. Isochoric bilateral nerve involved is:","o":["Oculomotor nerve","Abducent nerve","Trochlear nerve","Trigeminal nerve"],"a":1,"e":"Bilateral horizontal diplopia with intact pupils (isochoric) and no ptosis/mydriasis indicates bilateral CN VI (abducent) palsy. CN VI palsy causes failure of lateral gaze (medial deviation of eye). Raised ICP commonly causes false-localising bilateral CN VI palsies due to the nerve's long intracranial course.<br><br>Key discriminator: CN VI palsy → convergent squint + horizontal diplopia (can't abduct) | CN III palsy → ptosis + mydriasis + 'down and out' eye | Isochoric pupils (equal, reactive) with horizontal diplopia = CN VI (not CN III which would cause mydriasis)."},
/*90*/ {"q":"10th Intercostal nerve passes through:","o":["Epigastric region","Umbilicus","Just above suprapubic region","Left iliac region"],"a":1,"e":"The 10th intercostal nerve (T10 dermatome) supplies the skin of the umbilical region. This is a classic dermatome landmark — T10 = umbilicus. Beevor's sign (umbilicus moves upward) indicates T10 lesion (upper abdominal muscles intact, lower ones weak).<br><br>Key discriminator: T10 → umbilicus | T4 → nipple | T12 → inguinal region | L1 → groin/inguinal ligament | Beevor's sign → T10 lesion marker."},
/*91*/ {"q":"Which bone has ossification centre just above suprapubic region:","o":["Left iliac region","Umbilicus","Epigastric region","Ischiopubic ramus"],"a":3,"e":"The ischiopubic ramus has a secondary ossification centre that fuses between ages 4-8 years. In children, this creates a radiological appearance that can be mistaken for a fracture on pelvic X-ray. It is the bone with an ossification centre in the suprapubic region.<br><br>Key discriminator: ischiopubic ramus ossification → fuses 4-8 years, can mimic fracture on X-ray | Iliac crest → fuses 15-17 years (Risser sign for scoliosis) | Triradiate cartilage → acetabular fusion ~16-18 years | Ischiopubic = suprapubic ossification centre."},
/*92*/ {"q":"Hypokalemic metabolic alkalosis leading to volume expansion is seen in:","o":["Conn syndrome","Primary adrenal insufficiency","ACTH secreting tumour","None"],"a":0,"e":"Conn syndrome (primary hyperaldosteronism) causes hypokalaemia (aldosterone increases K+ secretion), metabolic alkalosis (increased H+ excretion), sodium retention (volume expansion), and hypertension. It is the classic cause of this metabolic triad.<br><br>Key discriminator: Conn syndrome → hypokalaemia + metabolic alkalosis + hypertension + volume expansion | Cushing's → also causes hypokalaemia + alkalosis but with cortisol excess features | Bartter syndrome → hypokalaemia + alkalosis but with HYPOTENSION (no volume expansion) | Volume expansion + hypertension = Conn's."},
/*93*/ {"q":"If light through in left eye absent. If light through in both eye light reflex is present in both eyes, when light through in right eye light reflex is in both eyes. If light is present in both eyes. Which reflex is:","o":["ACTH secreting tumour","None","Primary adrenal insufficiency","Right occolomofor"],"a":3,"e":"A left afferent pupillary defect (RAPD): light in left eye → no direct or consensual response; light in right eye → both eyes respond. This indicates damage to the left optic nerve (afferent limb). The right oculomotor nerve carries the efferent limb (pupillary constriction) for both pupils.<br><br>Key discriminator: RAPD (Marcus Gunn pupil) → afferent defect (optic nerve) | Light in bad eye → no direct + no consensual | Light in good eye → both pupils constrict | Efferent defect (CN III) → affected pupil doesn't constrict to any light."},
/*94*/ {"q":"Bulbar palsy caused by:","o":["Bulbar nucleus","Protectum","Right cerebral cortex","Huntington Disease"],"a":0,"e":"Bulbar palsy is a lower motor neuron disorder affecting the cranial nerve nuclei in the medulla (CN IX, X, XI, XII) — causing flaccid paralysis of the tongue, pharynx, and larynx with fasciculations, absent gag reflex, and nasal speech.<br><br>Key discriminator: bulbar palsy → LMN lesion of medullary nuclei (CN IX-XII) → fasciculations + absent reflexes | Pseudobulbar palsy → UMN lesion above brainstem → spastic, brisk jaw jerk, emotional lability | LMN = bulbar; UMN = pseudobulbar."},
/*95*/ {"q":"A patient had RTA, he does not know his school events but he remembers recent events:","o":["Syringomyelia","Motor neuron disease","Guillain Barre","Huntington Disease"],"a":3,"e":"Loss of distant/remote memories (retrograde amnesia for past events like school) with preserved recent memory after head trauma is an unusual amnesia pattern. Huntington's disease causes progressive dementia with personality change, chorea, and cognitive decline including memory loss affecting recent then remote memories.<br><br>Key discriminator: post-RTA amnesia → typically anterograde (can't form new memories) or retrograde (loses past memories) | Huntington's → progressive subcortical dementia + chorea | Syringomyelia → central cord syndrome (cape distribution sensory loss) | RTA + memory loss = head injury amnesia pattern."},
/*96*/ {"q":"A patient got injury on medial side of knee and there is loss of sensation on medial side of leg and foot due to damage of which nerve:","o":["Sural nerve","Tibial nerve","Lateral Femoral Cutaneous nerve","Femoral nerve"],"a":1,"e":"The medial side of the leg and foot is supplied by the saphenous nerve, which is the terminal sensory branch of the femoral nerve. A knee injury affecting the medial compartment can damage the saphenous nerve where it runs with the great saphenous vein.<br><br>Key discriminator: saphenous nerve (femoral branch) → medial leg + foot sensation | Sural nerve → lateral foot | Tibial nerve → plantar foot | Femoral nerve injury → anterior thigh + medial leg via saphenous | Medial knee injury = saphenous/femoral nerve."},
/*97*/ {"q":"A women with trauma to head and neck region having lesion on tongue and tongue deviated to which side:","o":["Posterior cerebral artery","Middle cerebral artery","Anterior cerebral artery","Right hypoglossal"],"a":3,"e":"The right hypoglossal nerve (CN XII) innervates the right genioglossus muscle. If damaged, the right genioglossus is paralysed, and the tongue deviates to the right (paralysed side) on protrusion, due to unopposed action of the left genioglossus.<br><br>Key discriminator: CN XII lesion → tongue deviates TOWARD the paralysed side (LMN) | UMN CN XII lesion → tongue deviates AWAY from lesion | 'Tongue licks the wound' = points to LMN side | Right CN XII damage → right tongue deviation."},
/*98*/ {"q":"A patient presented with urinary symptoms. Doctor made a diagnosis of benign prostatic hypertrophy. An old man presented with urinary symptoms. There is stony hard mass felt on DRE. BPH present. 60 year old man presented in opd with complain of haematuria and frequency on DRE there is prostate is stony hard mass felt that there is urinary frequency on DRE is prostate lymphatic drainage of tumour at:","o":["Internal iliac nodes","Deep inguinal nodes","Para-aortic nodes","External iliac nodes"],"a":0,"e":"The prostate gland drains lymphatics primarily to the internal iliac lymph nodes (obturator nodes are the first echelon), then to the external iliac and common iliac nodes. Prostatic carcinoma metastasises preferentially to internal iliac and sacral lymph nodes before reaching para-aortic nodes.<br><br>Key discriminator: prostate → internal iliac (obturator) lymph nodes | Testes → para-aortic nodes (L1-L2) | Bladder → internal + external iliac nodes | Rectum → internal iliac + para-rectal nodes | Prostate = internal iliac = first echelon."},
/*99*/ {"q":"A 24 years old pregnant lady who is 6 months pregnant complains of weakness and lethargy. Her Hb is 9.8 g/dl with MCV 58 fl and serum ferritin level is 150 ng/dl. Diagnose is:","o":["Thalassaemia","Iron deficiency anaemia","Megaloblastic anaemia","Sideroblastic anaemia"],"a":0,"e":"Low Hb + low MCV (microcytic) + normal/high ferritin (150 ng/ml, normal >12) in a pregnant woman suggests thalassaemia trait rather than iron deficiency. Iron deficiency would have low ferritin. High-normal ferritin with microcytosis = thalassaemia.<br><br>Key discriminator: iron deficiency → low MCV + LOW ferritin | Thalassaemia trait → low MCV + NORMAL/HIGH ferritin | Ferritin 150 = normal/high → not iron deficient → thalassaemia | Pregnancy + microcytosis + normal ferritin = thalassaemia trait."},
/*100*/ {"q":"In Pregnant woman at term. Which type of anaemia occur:","o":["Thalassaemia","Iron deficiency anaemia","Megaloblastic anaemia","Chronic disease anaemia"],"a":1,"e":"Iron deficiency anaemia is the most common anaemia in pregnancy, occurring because fetal demand for iron exceeds maternal intake and stores. The physiological haemodilution of pregnancy also lowers haemoglobin. Supplemental iron is routinely given.<br><br>Key discriminator: most common anaemia in pregnancy → iron deficiency (increased fetal iron demand) | Megaloblastic → folate deficiency (also common in pregnancy, prevented by folic acid supplementation) | Physiological anaemia of pregnancy → dilutional (normocytic) not iron deficiency | Iron deficiency = microcytic hypochromic = most common pathological pregnancy anaemia."}
,
/*101*/ {"q":"Action of PTH is:","o":["Ca excretion from kidney","Activation of Vitamin D","Increase phosphate absorption","Ca Absorption from intestine"],"a":1,"e":"PTH acts on the kidney to: (1) increase Ca reabsorption, (2) decrease phosphate reabsorption, and (3) activate 1-alpha-hydroxylase to convert 25-OH vitamin D to active 1,25-(OH)2 vitamin D (calcitriol), which then increases intestinal Ca absorption. PTH's intestinal effect is indirect, via Vitamin D activation.<br><br>Key discriminator: PTH direct action → kidney (Ca reabsorption, phosphate excretion) | PTH indirect action → intestine (via activated Vitamin D) | PTH direct = kidney; PTH indirect = intestine via Vitamin D activation."},
/*102*/ {"q":"Latex Gloves have cause allergy:","o":["Intestine via Vitamin D+","Kidney","Indirect action: Ca absorption from intestine","Direct action: Ca absorption from kidney"],"a":1,"e":"Latex allergy is a Type I (IgE-mediated) hypersensitivity reaction in sensitised individuals, causing urticaria, angio-oedema, and anaphylaxis. Healthcare workers and patients with spina bifida have highest prevalence due to repeated latex exposure.<br><br>Key discriminator: latex allergy → Type I hypersensitivity (IgE-mediated) | High-risk groups → healthcare workers + spina bifida patients | Avoidance + adrenaline for anaphylaxis | Non-latex gloves required for sensitised patients."},
/*103*/ {"q":"Giant Cell in TB are composed of:","o":["Neutrophils","Monocytes","Activated Macrophages","Lymphocytes"],"a":2,"e":"Langhans giant cells in TB granulomas are formed by fusion of activated epithelioid macrophages. These macrophages are activated by T-cell-derived IFN-gamma in response to mycobacterial antigens.<br><br>Key discriminator: Langhans giant cells → fused activated macrophages (epithelioid cells) | Peripheral nuclear arrangement (horseshoe pattern) = TB/fungal | Foreign body giant cells → random nuclear arrangement | CD4+ T cells → orchestrate macrophage activation via IFN-gamma."},
/*104*/ {"q":"Polyporn by latex gloves. Polyporin. Intestine via Vitamin D+. Kidney. Indirect action. Direct action Ca absorption from kidney. Patient is having complaint of swelling of the joint. In anorexia nervosa Decrease Androgen. Secondary Hyperparathyroidism. Which is anterior relation of root of lung? Phrenic nerve. Ans: C. Activation of Vitamin D. Increase phosphate absorption. SLE:","o":["Rheumatoid arthritis","Septic arthritis","SLE","Osteoarthritis"],"a":2,"e":"SLE (systemic lupus erythematosus) presents with joint swelling (non-erosive arthritis), malar rash, photosensitivity, serositis, and multi-organ involvement. It is an autoimmune disease predominantly affecting young women, with ANA positivity.<br><br>Key discriminator: SLE → non-erosive arthritis + malar rash + ANA positive | RA → erosive arthritis + RF/anti-CCP | Septic arthritis → hot, red, single joint + fever + organisms on joint aspirate | SLE = systemic autoimmune with joint + skin + renal involvement."},
/*105*/ {"q":"Lateral to brachial artery in the cubital fossa is:","o":["Indirect action: Ca absorption","Lateral to cubital fossa","Long head of bicep","Coracobrachialis"],"a":2,"e":"In the cubital fossa, lateral to the brachial artery lies the biceps tendon, and lateral to that is the radial nerve. The long head of the biceps tendon is a key structure in the cubital fossa lateral to the brachial artery.<br><br>Key discriminator: cubital fossa medial to lateral: median nerve → brachial artery → biceps tendon → radial nerve | Long head of biceps tendon → lateral to brachial artery | Biceps tendon = central landmark of cubital fossa."},
/*106*/ {"q":"Giant Cell in TB are composed of Macrophages. Macrophages causes following:","o":["Neutrophils","Activated Macrophages","Plasma Cells","Lymphocytes"],"a":1,"e":"Macrophages are the central effector cells in TB granuloma formation. When activated by T-cell IFN-gamma, they become epithelioid macrophages and fuse to form Langhans giant cells. They also present antigens and produce cytokines (IL-12, TNF-alpha).<br><br>Key discriminator: macrophages → phagocytosis + antigen presentation + cytokine production + giant cell formation in TB | Plasma cells → antibody production (not primary in TB) | Neutrophils → acute bacterial infections | Macrophage = central TB immune cell."},
/*107*/ {"q":"Macrophages causes following. ADPKD with gene defect located on:","o":["Chromosome 6","Chromosome 8","Chromosome 10","Chromosome 16"],"a":3,"e":"Autosomal dominant polycystic kidney disease (ADPKD) is caused by mutations in PKD1 (chromosome 16, 85% of cases) or PKD2 (chromosome 4, 15%). PKD1 causes more severe disease with earlier renal failure.<br><br>Key discriminator: ADPKD → PKD1 on chromosome 16 (85%) | PKD2 → chromosome 4 (15%) | ARPKD → chromosome 6 (PKHD1 gene) | Chromosome 16 = PKD1 = most common ADPKD mutation."},
/*108*/ {"q":"Cause of left axis deviation on ECG:","o":["PKD2 Chromosome 4q21-15%","PKD1 Chromosome 16p13.3","Chromosome 6","Chromosome 10"],"a":1,"e":"Left axis deviation (LAD) on ECG is most commonly caused by left anterior fascicular block (LAFB), left ventricular hypertrophy, inferior MI, or Wolff-Parkinson-White syndrome. The QRS axis deviates to the left (more negative than -30 degrees).<br><br>Key discriminator: LAD causes → LAFB + LVH + inferior MI + WPW | Right axis deviation → RVH + RBBB + lateral MI | Normal axis → -30 to +90 degrees | LAD = QRS axis more negative than -30 degrees."},
/*109*/ {"q":"Cause of left axis deviation on ECG. 85% ADPKD. 15% PKD2. Explanation: PKD1 Chromosome 16p13.3. Cause of left axis deviation on ECG:","o":["O2 (Normal Diffusion)","CO","Perfusion limited:","Diffusion limited:"],"a":3,"e":"O2 transfer in the lung is normally perfusion-limited (limited by blood flow, not diffusion). CO transfer is diffusion-limited (CO binds haemoglobin avidly and never equilibrates). In pulmonary fibrosis, O2 becomes diffusion-limited due to thickened alveolar membrane.<br><br>Key discriminator: O2 → normally perfusion-limited | CO → always diffusion-limited (used to measure DLCO) | Fibrosis → O2 becomes diffusion-limited | N2O → perfusion-limited | Diffusion-limited = transfer rate limited by membrane thickness."},
/*110*/ {"q":"Left ventricular damage:","o":["AV node damage","Purkanje fibre damage","Right ventricular damage","Left ventricular damage"],"a":3,"e":"Left ventricular damage (e.g., from anterior MI/LAD occlusion) causes reduced ejection fraction, increased LVEDP, pulmonary congestion, and eventually cardiogenic shock. LV failure is the primary determinant of cardiac output and systemic perfusion.<br><br>Key discriminator: LV damage → reduced CO + pulmonary oedema (backward failure) + hypoperfusion (forward failure) | RV damage → raised JVP + peripheral oedema + hepatomegaly | LV = left-sided heart failure = pulmonary oedema signs."},
/*111*/ {"q":"Which transverse fills pressure proportional to:","o":["Venous return","Intrathoracic pressure","Mean systemic filling pressure","Cardiac output"],"a":2,"e":"Venous return is determined by the mean systemic filling pressure (MSFP) minus right atrial pressure, divided by venous resistance. MSFP reflects the pressure in the venous reservoir — the driving force for venous return. It increases with blood volume expansion.<br><br>Key discriminator: venous return = (MSFP − RAP) / venous resistance | MSFP increases → more venous return → more preload → more CO (Frank-Starling) | MSFP = the 'filling pressure' of the systemic venous reservoir."},
/*112*/ {"q":"Glycolysis enzyme present in:","o":["Nucleus","Cytoplasm of RBC","Mitochondria","Cell membrane"],"a":1,"e":"Glycolysis is a cytoplasmic process occurring in the cytosol. RBCs lack mitochondria and rely entirely on anaerobic glycolysis (Embden-Meyerhof pathway) in the cytoplasm for ATP production. This is why RBCs are uniquely vulnerable to glycolytic enzyme deficiencies.<br><br>Key discriminator: glycolysis → cytoplasm (cytosol) of all cells | RBCs → only glycolysis (no mitochondria, no oxidative phosphorylation) | Krebs cycle → mitochondrial matrix | Electron transport chain → inner mitochondrial membrane."},
/*113*/ {"q":"Patient has dysphagia. Dilation of oesophagus and cause compress which structure:","o":["Cell membrane","Mitochondria","Nucleus","Aorta"],"a":3,"e":"A dilated oesophagus (as in achalasia or massive oesophageal dilatation) compresses the adjacent aorta and thoracic structures. The descending thoracic aorta lies to the left and posterior of the oesophagus and can be compressed by a massively dilated oesophagus.<br><br>Key discriminator: oesophageal dilation compresses → aorta (posterior/left) | Also compresses → left atrium (causing dysphagia lusoria-like symptoms) | Oesophagus → posterior mediastinum structure | Achalasia → massive dilatation can compress thoracic aorta."},
/*114*/ {"q":"Which one is diffusion limited gas?","o":["Left atrium","Aorta","Left ventricle","N2O"],"a":3,"e":"N2O (nitrous oxide) is NOT diffusion-limited — it is perfusion-limited. CO is the classic diffusion-limited gas. However in context, N2O equilibrates quickly across the alveolar membrane and its transfer is limited by pulmonary blood flow (perfusion-limited). CO never equilibrates, making it diffusion-limited.<br><br>Key discriminator: CO → diffusion-limited (never equilibrates, used as DLCO marker) | N2O → perfusion-limited (equilibrates rapidly) | O2 → normally perfusion-limited, becomes diffusion-limited in fibrosis | N2O = perfusion-limited = fast equilibration."},
/*115*/ {"q":"A patient got injury on medial side of knee. There is loss of sensation on medial side of leg and foot due to damage of which nerve. N2O. CO2. A patient got injury on medial side and there is loss of sensation on medial side of leg and foot due to damage of which nerve:","o":["Femoral nerve","Obturator nerve","Sephrous nerve","Tibial nerve"],"a":0,"e":"Medial knee injury with loss of sensation on the medial leg and foot indicates saphenous nerve injury. The saphenous nerve is the terminal sensory branch of the femoral nerve, running with the great saphenous vein along the medial leg to the medial foot.<br><br>Key discriminator: saphenous nerve → branch of femoral nerve → medial leg + medial foot sensation | Tibial nerve → plantar foot | Obturator → medial thigh | Saphenous nerve injury at medial knee = femoral nerve terminal branch."},
/*116*/ {"q":"A person with uncoordinated and random motor movements of hand and foot. Lesion is in:","o":["Premotor cortex","Somatosensory","Primary motor","Dorsal nucleus"],"a":0,"e":"Random, uncoordinated involuntary movements (athetosis/chorea) arising from cortical dysfunction are associated with premotor cortex or basal ganglia lesions. The premotor cortex coordinates complex sequential movements — its lesion causes apraxia and disorganised motor planning.<br><br>Key discriminator: premotor cortex lesion → apraxia + uncoordinated purposeful movements | Primary motor cortex → contralateral weakness/paralysis | Basal ganglia → choreiform/athetoid movements | Cerebellum → intention tremor + ataxia."},
/*117*/ {"q":"Drug of choice actinobacterbouncel:","o":["Drug","Imipenem","Tetracycline","Niclosamide"],"a":1,"e":"Imipenem (a carbapenem) is the drug of choice for Acinetobacter baumannii infections. Acinetobacter is a multidrug-resistant gram-negative organism causing nosocomial pneumonia and bacteraemia, particularly in ICU patients. Colistin is used for pan-resistant strains.<br><br>Key discriminator: Acinetobacter baumannii → imipenem (carbapenem) as first-line | Colistin → last resort for pan-resistant Acinetobacter | Tetracycline → some activity but not first-line | Carbapenems = gold standard for MDR gram-negative infections."},
/*118*/ {"q":"Which drug if given intravenous causes 60% thrombophlebitis?","o":["Praziquenol","Niclosamide","Oxazepam","1/v diazepam"],"a":3,"e":"Intravenous diazepam causes thrombophlebitis in approximately 60% of patients due to its lipid-soluble vehicle (propylene glycol) that irritates vein walls. IV diazepam emulsion (Diazemuls) was developed to reduce this complication.<br><br>Key discriminator: IV diazepam → 60% thrombophlebitis (propylene glycol vehicle) | Diazemuls (emulsion) → less thrombophlebitis | IV midazolam → water-soluble, less vein irritation | IV diazepam = classic cause of thrombophlebitis at injection site."},
/*119*/ {"q":"Pressure volume relation of lung shows change in volume per change in pressure demonstrates which of the lung following function does not change with this change in pressure?","o":["Tidal Volume","Inspiratory capacity","FRC","Respiratory rate"],"a":2,"e":"The pressure-volume relationship of the lung measures compliance (ΔV/ΔP). FRC (functional residual capacity) is the equilibrium point where elastic recoil of the lung equals chest wall outward recoil — it does not change with each breath's pressure change but is determined by static compliance.<br><br>Key discriminator: FRC → equilibrium point of lung-chest wall system (static, not breath-by-breath) | Tidal volume → changes with each breath | Compliance = ΔV/ΔP → steeper curve = more compliant | FRC is the resting volume, not dynamically changing with pressure."},
/*120*/ {"q":"Posture is maintained during moderate exercise occurs through:","o":["Increased HR","Proprioception","Rubrospinal tract","Decreased pulse"],"a":1,"e":"Posture during moderate exercise is primarily maintained through proprioceptive feedback from muscle spindles (Ia fibres), Golgi tendon organs (Ib fibres), and joint receptors. This information is processed by the cerebellum and vestibular system to maintain balance and posture.<br><br>Key discriminator: posture maintenance → proprioception (muscle spindles + GTOs + joint receptors) | Cerebellum → coordinates proprioceptive input for smooth posture | Rubrospinal tract → fine motor control, not posture | Proprioception = the postural control sensor system."},
/*121*/ {"q":"Right Anisocoria is cause by:","o":["CN III palsy (mydriasis + ptosis)","Decreased venous return","Increased venous return","Horner syndrome"],"a":1,"e":"Anisocoria (unequal pupils) with the right pupil larger (mydriasis) and not reacting to light indicates right CN III (oculomotor) palsy, often from posterior communicating artery aneurysm compression. This causes ipsilateral mydriasis due to loss of parasympathetic innervation to the pupillary sphincter.<br><br>Key discriminator: CN III palsy → ipsilateral mydriasis + ptosis + 'down and out' eye | Horner syndrome → ipsilateral miosis + ptosis + anhidrosis | Right CN III lesion → right pupil dilated | PCom aneurysm = classic cause of CN III palsy with mydriasis."},
/*122*/ {"q":"D (No paired lobe option). First pharyngeal Arch derivative:","o":["Hyperextension","Fracture of Transverse process of axis","Fracture of Odontoid process of axis","Fracture of Spinous process of axis"],"a":1,"e":"Transverse process fractures of the axis (C2) and upper cervical vertebrae occur from high-energy lateral compression injuries. The first pharyngeal arch gives rise to mandible, maxilla, malleus, incus, muscles of mastication, and the trigeminal nerve.<br><br>Key discriminator: 1st pharyngeal arch → mandible + maxilla + malleus + incus + CN V | 2nd arch → stapes + styloid + CN VII | 3rd arch → stylopharyngeus + CN IX | 1st arch = Meckel's cartilage = mandible/ossicles."},
/*123*/ {"q":"Patient brought in ER after RTA blood loss will be initially used:","o":["Groud","Head bone","Mandible portion","Facial cleft"],"a":0,"e":"In acute haemorrhage from RTA, the initial fluid of choice is crystalloid (normal saline or Hartmann's/lactated Ringer's) given rapidly IV to restore intravascular volume while cross-matched blood is being prepared. O-negative blood is used when cross-matching is unavailable.<br><br>Key discriminator: acute haemorrhage initial fluid → crystalloid (NS or Hartmann's) | Then → O-negative blood (emergency) or cross-matched blood | Colloids → second-line | Massive transfusion protocol → 1:1:1 ratio (RBC:FFP:platelets)."},
/*124*/ {"q":"Which of following deficiency is of haemophilia A:","o":["Aspirin poisoning","Morphine overdose","Paracetamol overdose","Collection of blood in patient"],"a":3,"e":"Haemophilia A is caused by deficiency of Factor VIII. It causes prolonged APTT with normal PT. Management includes Factor VIII replacement (recombinant or plasma-derived) and DDAVP (for mild haemophilia A).<br><br>Key discriminator: Haemophilia A → Factor VIII deficiency → prolonged APTT, normal PT | Haemophilia B (Christmas disease) → Factor IX deficiency | Von Willebrand disease → low vWF + low Factor VIII | APTT prolonged in both haemophilia A and B; PT normal."},
/*125*/ {"q":"A pregnant female epidural anaesthesia was given to a pregnant female. Ligament at last during epidural is:","o":["Supraspinous ligament","Interspinous ligament","Posterior longitudinal ligament","Ligamentum flavum"],"a":3,"e":"During epidural anaesthesia, the needle passes through: skin → subcutaneous fat → supraspinous ligament → interspinous ligament → ligamentum flavum (last and toughest, giving a 'give' sensation) → epidural space. The ligamentum flavum is the final ligament penetrated.<br><br>Key discriminator: epidural needle → last ligament = ligamentum flavum | Then → epidural space (stop here for epidural) | For spinal (intrathecal) → continue through dura + arachnoid | 'Loss of resistance' technique detects passing through ligamentum flavum into epidural space."},
/*126*/ {"q":"Median nerve rout is:","o":["Upper esophagus — Inferior","Middle esophagus — Left gastric","Descending thoracic aorta — Left gastric artery","Middle cardiac vein — Left gastric"],"a":1,"e":"The oesophagus has segmental blood supply: upper third → inferior thyroid artery | middle third → oesophageal branches from descending thoracic aorta (left gastric artery also contributes) | lower third → left gastric artery and left inferior phrenic. The middle oesophagus is supplied by the left gastric artery branches.<br><br>Key discriminator: upper oesophagus → inferior thyroid artery | Middle oesophagus → thoracic aorta branches + left gastric | Lower oesophagus → left gastric artery | This segmental supply is why oesophageal ischaemia is rare (multiple sources)."},
/*127*/ {"q":"Median nerve rout. Lateral to cubital fossa. 17 years old boy with intra ventricular septal defect. Also infracted endocardial and also infarted sub-endocardial and which is most infarted:","o":["Thrombotic occlusion of LCX","Decrease blood supply to ventricle","Hypovolumic shock","A patient has infarct of left"],"a":0,"e":"Thrombotic occlusion of the left circumflex artery (LCX) causes lateral and posterior MI. In the context of a 17-year-old with VSD and endocardial infarction, LCX occlusion with sub-endocardial involvement (most vulnerable zone, furthest from coronary supply) fits the described pathology.<br><br>Key discriminator: LCX occlusion → lateral + posterior MI | LAD → anterior + septal MI | RCA → inferior + posterior MI | Sub-endocardial infarction → most vulnerable zone (highest oxygen demand, lowest perfusion pressure)."},
/*128*/ {"q":"Nucleus of REM sleep is located in:","o":["Nucleus of Raphe Magnus nucleus","Anterior to cubital fossa","Posterior to Brachial artery","Medial to Brachial fossa"],"a":0,"e":"The nucleus of REM sleep (REM-on cells) is located in the Raphe Magnus nucleus in the brainstem. REM sleep is also controlled by the locus coeruleus (noradrenergic, REM-off) and pedunculopontine nucleus (cholinergic, REM-on).<br><br>Key discriminator: REM sleep control → Raphe Magnus (serotonergic) + pedunculopontine nucleus (cholinergic, REM-on) | Locus coeruleus (noradrenergic) → REM-off | NREM sleep → anterior hypothalamus (VLPO nucleus) | Raphe Magnus = REM nucleus."},
/*129*/ {"q":"Vasectomy is done on great saphenous vein mostly which nerve is likely to be damaged:","o":["Superficial peroneal nerve","Sural nerve","Tibial nerve","Femoral nerve"],"a":3,"e":"During vasectomy, the ilioinguinal nerve and genitofemoral nerve are at risk. During great saphenous vein harvesting at the groin, the femoral nerve branches (saphenous nerve) run alongside and may be damaged, causing medial leg and foot sensory loss.<br><br>Key discriminator: great saphenous vein harvest at groin → saphenous nerve (femoral branch) at risk | Varicose vein surgery at ankle → sural nerve at risk | Vasectomy in scrotum → ilioinguinal nerve at risk | Saphenous nerve follows the great saphenous vein."},
/*130*/ {"q":"PONS (focus centus) is located in:","o":["Raphe nucleus","NREM sleep centre","Locus ceruleus","Substantia nigra"],"a":2,"e":"The locus coeruleus in the pons is the principal noradrenergic nucleus of the brain and plays a key role in sleep-wake regulation, attention, and stress response. It is a 'REM-off' nucleus — its activity suppresses REM sleep.<br><br>Key discriminator: locus coeruleus → pons, noradrenergic, REM-off | Raphe nuclei → serotonergic, pons/medulla | Substantia nigra → midbrain, dopaminergic | VLPO (anterior hypothalamus) → NREM sleep promotion | Locus coeruleus = pons = REM suppressor."},
/*131*/ {"q":"Regarding Erythrocytes true is:","o":["BT 20 min","APTT: 60 seconds","Ionic bonds","Disulphide bonds"],"a":2,"e":"The red cell membrane structure is maintained by ionic bonds and hydrophobic interactions between spectrin, ankyrin, and band 3 protein. The cytoskeletal protein network uses ionic bonds to maintain the biconcave disc shape and deformability of RBCs.<br><br>Key discriminator: RBC membrane skeleton → ionic bonds + hydrophobic interactions (spectrin-ankyrin-band 3) | Disulphide bonds → important in IgG structure and keratin | Haemoglobin subunits → ionic + hydrogen bonds | Ionic bonds = RBC membrane cytoskeletal interactions."},
/*132*/ {"q":"Estrogen causes:","o":["Produce ankyloglycospectin","Use carbohydrate aerobically","Increase viscosity of blood","Cell membrane is fragile due to"],"a":0,"e":"Oestrogen stimulates hepatic production of clotting factors and sex hormone-binding globulin. It produces ankyloglycospectrin (a membrane protein) and increases RBC membrane deformability. Oestrogen also causes the endometrium to proliferate and increases SHBG.<br><br>Key discriminator: oestrogen → increases clotting factors (VIII, IX, X) → thrombotic risk | Also → increases SHBG + stimulates endometrial proliferation | HRT/OCP oestrogen → increased DVT/PE risk | Oestrogen = pro-coagulant effect."},
/*133*/ {"q":"Patient finger cut doctor told him to be fine due to regeneration by all will:","o":["Statum Basale","Statum Spinosum","Statum granulosum","Statum lucidum"],"a":0,"e":"Skin regeneration after a finger cut occurs from the stratum basale (basal layer), which contains the mitotically active keratinocytes (stem cells) that divide and migrate upward to regenerate all other epidermal layers. It rests on the basement membrane.<br><br>Key discriminator: stratum basale → regeneration source (stem cells, highest mitotic activity) | Stratum spinosum → above basale, desmosomes prominent | Stratum granulosum → keratohyalin granules | Stratum corneum → dead, anucleate cells | Basale = the only regenerating layer."},
/*134*/ {"q":"A patient has muscle contraction on 1st post-op day of thyroidectomy. This is due to:","o":["Ca excess","Cl loss","Low plasma Ca level","Hypothyroidism"],"a":2,"e":"Muscle tetany on post-thyroidectomy day 1 results from accidental removal of the parathyroid glands, causing hypoparathyroidism and hypocalcaemia. Low Ca2+ increases neuromuscular excitability, causing tetany, Chvostek's sign, and Trousseau's sign.<br><br>Key discriminator: post-thyroidectomy tetany → hypocalcaemia from hypoparathyroidism (parathyroid removal) | Hypocalcaemia signs → Chvostek (facial nerve tap) + Trousseau (BP cuff inflation) | Hypothyroidism → takes weeks to manifest | Low Ca2+ = neuromuscular hyperexcitability = tetany."},
/*135*/ {"q":"Patient with nephrotic syndrome. Which structure in GBM plays major role in perm-selectivity for proteins:","o":["Lamina rara externa","Lamina densa","Lamina rara interna","Visceral epithelial layer"],"a":1,"e":"The lamina densa of the GBM contains type IV collagen providing size-selective filtration. The laminae rarae contain heparan sulphate proteoglycans providing charge selectivity. Nephrotic syndrome reflects predominantly charge barrier disruption.<br><br>Key discriminator: lamina densa → size selectivity (type IV collagen) | Laminae rarae → charge selectivity (heparan sulphate) | Nephrotic syndrome → charge barrier loss → protein leak | Perm-selectivity = size + charge barriers working together."},
/*136*/ {"q":"Source of spread from tip of nose occurs to:","o":["Inferior Ophthalmic vein","Superior Ophthalmic vein","Maxillary vein","Lateral Femoral Cutaneous nerve"],"a":1,"e":"The tip of the nose drains via the facial vein to the superior ophthalmic vein and then to the cavernous sinus. This is the 'danger triangle of the face' — infections here can spread retrogradely to the cavernous sinus, causing cavernous sinus thrombosis.<br><br>Key discriminator: nose tip/face danger triangle → facial vein → superior ophthalmic vein → cavernous sinus | Infection here → cavernous sinus thrombosis (proptosis + CN III/IV/VI palsies + fever) | Inferior ophthalmic vein → lower orbit, not nose tip drainage."},
/*137*/ {"q":"A man has noted scleral icterus for one month, tachycardia and vitals for one month physical exam. O/E mild tachycardia for 4 days. Unremarkable lab finding show Hct 25%, Bilirubin 3.6, indirect bilirubin 2.1 and Hepatoglobin (Normal 200) cause is:","o":["Golgi tendon organ","Free nerve endings","Steady pressure","Meissner corpuscles"],"a":0,"e":"The Golgi tendon organ (GTO) detects muscle tension and is stimulated by both passive stretch and active contraction. It mediates the inverse stretch reflex (autogenic inhibition), preventing muscle damage from excessive tension. In the context of scleral icterus and indirect hyperbilirubinaemia, this is a haemolytic process — GTOs are the tension receptors answering the physiology part.<br><br>Key discriminator: Golgi tendon organ → detects tension (not length) | Muscle spindle → detects length/stretch | Meissner's corpuscle → light touch (fingertips) | Free nerve endings → pain/temperature | GTO = tension sensor at musculotendinous junction."},
/*138*/ {"q":"A man has noted scleral icterus. Iron absorption increased. Intravascular haemolysis: Hct 25%, Bilirubin 21 and Indirect 200, Hepatoglobin (Normal 200) Cause is Haemolysis. Krause receptor:","o":["Golgi tendon organ","Meissner corpuscles","Ruffini receptor","Krause receptor"],"a":3,"e":"Krause end-bulbs are cold thermoreceptors found in the skin and mucous membranes, responding to cold temperatures. They are encapsulated sensory receptors distinct from Ruffini endings (warmth) and Meissner's corpuscles (light touch).<br><br>Key discriminator: Krause end-bulbs → cold sensation | Ruffini endings → warmth + sustained skin stretch | Meissner's corpuscles → light touch (fingertips, lips) | Pacinian corpuscles → deep pressure + vibration | Krause = cold receptor."},
/*139*/ {"q":"A 19 years old female with increased TAGs, which one of the following serious condition can occur:","o":["Systemic Hypertension","Type 1 DM","Pulmonary Squamous cell carcinoma","Pancreatitis"],"a":3,"e":"Severely elevated triglycerides (>1000 mg/dL) cause acute pancreatitis. Chylomicrons and VLDL accumulate in pancreatic capillaries, where lipase action releases toxic free fatty acids causing acinar cell injury and pancreatitis.<br><br>Key discriminator: hypertriglyceridaemia (>1000 mg/dL) → acute pancreatitis | Also causes → eruptive xanthomas + lipaemia retinalis + hepatosplenomegaly | Pancreatitis + milky serum = hypertriglyceridaemia diagnosis | TG >1000 = pancreatitis risk."},
/*140*/ {"q":"A patient was give penicillin for some infection this causes allergic reaction. Having IgE and some infection this causes allergic reaction. Having IgE and IgG3. Which infection it causes allergic reaction. Having IgE and IgG3:","o":["Neutrophils","Monocytes","Eosinophils","Plasma cells"],"a":2,"e":"IgE-mediated (Type I) allergic reactions involve mast cell and basophil degranulation, and the secondary recruitment of eosinophils. Eosinophils are characteristic of Type I hypersensitivity (allergic) reactions and are increased in blood and tissues after allergen exposure.<br><br>Key discriminator: Type I hypersensitivity (IgE-mediated) → mast cells + basophils (immediate) → eosinophils (late phase) | IgG3 → Type II/III hypersensitivity | Eosinophilia = hallmark of allergic reactions and helminthic infections | Penicillin allergy = Type I (anaphylaxis) or Type IV (delayed)."},
/*141*/ {"q":"Ventricles. What are cells that protect brain cells from fluid? A patient present with on inspiration which decreases:","o":["Decrease portal pressure","Decrease abdominal pressure","Decrease pleural pressure","Increase intrathoracic pressure"],"a":2,"e":"During inspiration, diaphragmatic descent increases intrathoracic volume and decreases intrapleural (pleural) pressure (becomes more negative). This pressure drop aids venous return to the right heart and expands the lungs.<br><br>Key discriminator: inspiration → pleural pressure decreases (more negative) | Decreased pleural pressure → lungs expand + venous return increases | Portal pressure → not directly affected by breathing | Intrapleural pressure normal = -5 cmH2O; at peak inspiration = -8 to -10 cmH2O."},
/*142*/ {"q":"Most behavioural hormone in man is:","o":["Estrogen","DHT","Testosterone","Cortisol"],"a":2,"e":"Testosterone is the primary hormone responsible for male behavioural characteristics including libido, aggression, and dominance. While DHT is more potent at androgen receptors in peripheral tissues, testosterone itself acts centrally (after aromatisation to oestradiol in the brain) to influence behaviour.<br><br>Key discriminator: testosterone → primary behavioural hormone (libido + aggression) | DHT → peripheral androgenic effects (prostate, hair, external genitalia) | Cortisol → stress/behavioural effects but not the primary sex behaviour hormone | Testosterone = dominant male behavioural hormone."},
/*143*/ {"q":"Patient is having history of smoking and has barrel shaped chest. What is the cause:","o":["COPD","Pneumonia","Alpha 1-antitrypsin deficiency","CO deficiency"],"a":0,"e":"Barrel chest (increased anterior-posterior diameter with horizontal ribs and elevated sternum) results from chronic air trapping in COPD (emphysema component). Smoking is the primary cause. The lungs are hyperinflated, pushing the chest into a barrel configuration.<br><br>Key discriminator: barrel chest + smoking history → COPD (emphysema) | Alpha-1 antitrypsin deficiency → emphysema in young non-smokers/lower lobes | COPD → upper lobe emphysema (centriacinar) from smoking | Barrel chest = chronic hyperinflation = COPD."},
/*144*/ {"q":"Microscopic nodosa is feature of:","o":["Bronchitis","COPD","Asthma","Emphysema"],"a":2,"e":"Microscopic nodosa (Curschmann spirals, Charcot-Leyden crystals, and Creola bodies) are microscopic features found in asthma sputum. Charcot-Leyden crystals are derived from eosinophil granule proteins; Curschmann spirals are mucus plugs cast from small airways.<br><br>Key discriminator: asthma sputum → Curschmann spirals + Charcot-Leyden crystals + Creola bodies (shed epithelial clusters) | COPD → mucus hypersecretion without these specific crystals | Charcot-Leyden = eosinophil breakdown product = asthma/allergic disease marker."},
/*145*/ {"q":"Male has eaten fast food at night and whole night due to abdominal problem. Increase gastric cramping by CK. Increase gastric cramping by Gastrin. Delayed gastric cramping by Pepsin. Liquefactive necrosis:","o":["Liquefactive necrosis","Fibrinoid necrosis","Transient inflammation","Granuloma"],"a":0,"e":"Liquefactive necrosis occurs in the brain after ischaemia (neurons undergo autolysis) and in bacterial abscesses (neutrophil enzymes digest tissue). It produces a fluid-filled cavity (cystic space) with no structural ghost cells remaining.<br><br>Key discriminator: liquefactive necrosis → brain infarcts + abscesses (enzymatic digestion) | Coagulative necrosis → solid organ ischaemia (ghost cells preserved) | Caseous necrosis → TB (cheesy, amorphous) | Fat necrosis → pancreas/breast | Liquefactive = fluid cavity = brain or abscess."},
/*146*/ {"q":"First heart sound dimished in:","o":["Mitral stenosis","Atrial fibrillation","Increase Cardiac Output","First heart sound dimished in"],"a":1,"e":"S1 is diminished in atrial fibrillation because mitral valve closure varies in intensity with each beat (variable PR interval and filling). Other causes of diminished S1 include mitral regurgitation, complete heart block (long PR), and cardiomyopathy.<br><br>Key discriminator: S1 diminished → AF (variable) + complete heart block (long PR) + mitral regurgitation | S1 loud → mitral stenosis (valve closes forcefully from wide-open position) + tachycardia | AF = variable S1 intensity = classic auscultatory finding."},
/*147*/ {"q":"Loud S1 causes:","o":["Mitral stenosis","Variable intensity S1","Atrial fibrillation","Soft S1 causes"],"a":0,"e":"Loud S1 occurs in mitral stenosis because the thickened mitral leaflets are held wide open by the pressure gradient and snap shut forcefully when LV pressure rises. Tachycardia (short diastole, valve open wide) and hyperdynamic circulation also cause loud S1.<br><br>Key discriminator: loud S1 → mitral stenosis + tachycardia + hyperdynamic state | Soft S1 → mitral regurgitation + long PR (heart block) + LV failure | Mitral stenosis = loud S1 + opening snap + mid-diastolic rumble."},
/*148*/ {"q":"Lymphoedema obstruction causes. Lymphoedema this is due to:","o":["Inflammation and fibrosis","Lymphatic obstruction","Hyperglycaemia","Renal failure"],"a":1,"e":"Lymphoedema results from obstruction or absence of lymphatic channels, causing protein-rich fluid accumulation in the interstitium. Primary causes include filariasis (Wuchereria bancrofti), surgical removal of lymph nodes, and radiation fibrosis.<br><br>Key discriminator: lymphoedema → lymphatic obstruction (not venous) → protein-rich oedema | Venous oedema → protein-poor (low oncotic) | Filariasis (W. bancrofti) → most common worldwide cause of lymphoedema | Lymph node removal (post-mastectomy) → arm lymphoedema."},
/*149*/ {"q":"Removal of protein bound to serum of some. Aggregation and precipitation rapid uptake by liver and destruction. Carbohydrate result in protein. Rapid absorption by kidney:","o":["E > B > A","Ca deficiency","PTH","Absorption in intestine"],"a":2,"e":"PTH increases calcium reabsorption in the distal tubule and thick ascending loop of Henle, while promoting phosphate excretion. PTH also activates vitamin D to increase intestinal calcium absorption indirectly. Calcium removal from serum triggers PTH release via the calcium-sensing receptor.<br><br>Key discriminator: low serum Ca → stimulates PTH secretion | PTH → renal Ca reabsorption + phosphate excretion + Vitamin D activation | 1,25-OH Vitamin D → intestinal Ca absorption | PTH = the primary calcium regulatory hormone."},
/*150*/ {"q":"A female young patient having steatorrhea due to pancreatic insufficiency. Rapid excretion. Rapid absorption by kidney:","o":["Inflammation and Fibrosis","Renal failure Fibrosis","Pancreatic Insufficiency","Rapid absorption by kidney"],"a":2,"e":"Pancreatic insufficiency causes steatorrhoea by reducing secretion of pancreatic lipase, colipase, and bicarbonate. Without lipase, dietary fat cannot be absorbed, appearing as fatty, foul-smelling, floating stools. Causes include chronic pancreatitis, cystic fibrosis, and pancreatic carcinoma.<br><br>Key discriminator: pancreatic insufficiency → steatorrhoea (fat malabsorption) due to lipase deficiency | Biliary obstruction → also steatorrhoea (no bile salts for fat emulsification) | Coeliac disease → villous atrophy → generalised malabsorption | Lipase deficiency = fat in stool = steatorrhoea."}
,
/*151*/ {"q":"A female young patient having steatorrhea. Pancreatic Insufficiency diagnosis. An 18 years old girl with craniopharyngioma glioma > seminoma > Lymph node tumour > cyst. Wolfian duct abnormality:","o":["Wolfian duct","Mesonephric duct","Paramesonephric duct","Tubule"],"a":1,"e":"The Wolffian (mesonephric) duct gives rise to the male internal genital structures: vas deferens, epididymis, seminal vesicles, and ejaculatory duct. In females, it regresses. Absence or anomaly of the Wolffian duct causes absence of these male structures.<br><br>Key discriminator: Wolffian/mesonephric duct → male structures (vas deferens, epididymis, seminal vesicles) | Müllerian/paramesonephric duct → female structures (fallopian tubes, uterus, upper vagina) | In females, Wolffian duct regresses (due to absence of testosterone)."},
/*152*/ {"q":"Lady had a difficult labour at home. She was brought to hospital. Her blood film shows blurred peripheral blood. APTT: 60 seconds. DIC. Platelets: 210000. Total volume is 500ml. Dead space is 150ml. R/R 12 and PT: 11 seconds. Tidal volume 500ml. Dead space 150ml. Minute ventilation:","o":["460ml","4460ml","520ml","4200ml"],"a":3,"e":"Minute ventilation = tidal volume × respiratory rate. Alveolar ventilation = (tidal volume − dead space) × RR = (500−150) × 12 = 350 × 12 = 4200 ml/min. This represents effective gas exchange volume per minute.<br><br>Key discriminator: minute ventilation = TV × RR = 500 × 12 = 6000 ml | Alveolar ventilation = (TV − dead space) × RR = 350 × 12 = 4200 ml/min | Dead space ventilation = dead space × RR = 150 × 12 = 1800 ml/min | 4200 = alveolar ventilation."},
/*153*/ {"q":"A patient has LRTI for many days. On histology of respiratory. An old male having alcoholic disease presents with symptoms of mild elevated liver enzymes. A 55-year-old male alcoholic presents with symptoms of liver disease and is found to have mildly elevated liver enzymes. Routine biopsy examined with a haematoxylin and eosin (H&E) stain reveals abnormal liver biopsy. Which of the following is most likely cause of this:","o":["D (Robinson)","Steatosis","Lipofuscin","Haemosiderin"],"a":1,"e":"Alcoholic liver disease presents on biopsy as macrovesicular steatosis (fat droplets displacing the nucleus) — the earliest and most common finding. H&E shows clear round vacuoles (lipid-filled) in hepatocytes, predominantly in centrilobular zones.<br><br>Key discriminator: alcoholic liver disease earliest finding → macrovesicular steatosis (fat) | Then → steatohepatitis (Mallory bodies + inflammation) | Then → fibrosis → cirrhosis | Clear round hepatocyte vacuoles on H&E = steatosis = earliest alcoholic liver change."},
/*154*/ {"q":"1.25 On cholecalciferol deficiency:","o":["E > B > A","Ca deficiency","PTH","Proteins inhibited by"],"a":0,"e":"1,25-dihydroxycholecalciferol (active Vitamin D/calcitriol) deficiency causes hypocalcaemia and hypophosphataemia, leading to rickets in children and osteomalacia in adults. The deficiency can result from lack of sun exposure, dietary deficiency, or renal failure (impaired 1-alpha-hydroxylation).<br><br>Key discriminator: Vitamin D deficiency → hypocalcaemia + hypophosphataemia → rickets (children) or osteomalacia (adults) | PTH increases in response to low Ca → secondary hyperparathyroidism | 1-alpha-hydroxylation (renal) → final activation step | E>B>A pattern = clinical severity order."},
/*155*/ {"q":"An 18 years old girl with craniopharyngioma glioma > seminoma lymph node tumour > cyst. Lymph node tumour is most:","o":["Brain stem glioma","Medulloblastoma","Ependymoma","Craniopharyngioma"],"a":3,"e":"Craniopharyngioma arises from Rathke's pouch remnants in the suprasellar/pituitary region. It is the most common suprasellar tumour in children, presenting with bitemporal hemianopia, pituitary dysfunction, and calcifications on imaging ('engine oil' cyst contents).<br><br>Key discriminator: craniopharyngioma → Rathke's pouch → suprasellar, calcified, 'engine oil' cyst | Medulloblastoma → posterior fossa/cerebellum (most common malignant paediatric brain tumour) | Ependymoma → 4th ventricle (obstructive hydrocephalus) | Craniopharyngioma = most common suprasellar tumour."},
/*156*/ {"q":"A girl with abdominal pain every month lower abdominal pain. P/A exam normal hymen. Amenorrhoea cyclic. Bicornuate uterus:","o":["Endoderm","Mesoderm","Ectoderm","Peritoneum"],"a":0,"e":"Cyclic lower abdominal pain with normal hymen and amenorrhoea suggests haematocolpos from an imperforate hymen, where menstrual blood accumulates. Bicornuate uterus results from failure of Müllerian duct fusion — a mesodermal developmental anomaly.<br><br>Key discriminator: bicornuate uterus → Müllerian (paramesonephric) duct fusion failure | Müllerian duct → mesoderm-derived | Imperforate hymen → endodermal urogenital sinus anomaly | Cyclic pain + no menses + normal exam = haematocolpos (imperforate hymen)."},
/*157*/ {"q":"Urovectal septum separates:","o":["Rectum and urogenital sinus","Rectum and Bladder","Rectal and urogenital sinus","Allantoin"],"a":0,"e":"The urorectal septum (Tourneux's fold) grows downward between the allantois/bladder anteriorly and the hindgut/rectum posteriorly, dividing the cloaca into the urogenital sinus (anterior) and anorectal canal (posterior). Failure causes anorectal malformations.<br><br>Key discriminator: urorectal septum → separates urogenital sinus (anterior) from rectum/anorectal canal (posterior) | Failure → rectourethral fistula, imperforate anus | Allantois → forms the bladder (anterior) | Cloaca → divided by urorectal septum."},
/*158*/ {"q":"TRALI occurs in:","o":["Immediately","Within 6 hours","24 hours","48 hours"],"a":1,"e":"TRALI (transfusion-related acute lung injury) occurs within 6 hours of blood transfusion. Donor anti-HLA or anti-neutrophil antibodies activate recipient neutrophils in the pulmonary vasculature causing non-cardiogenic pulmonary oedema.<br><br>Key discriminator: TRALI → within 6 hours of transfusion | TACO (circulatory overload) → also within 6 hours but cardiogenic | Delayed haemolytic reaction → 3-10 days | TRALI within 6 hours + non-cardiogenic pulmonary oedema = defining feature."},
/*159*/ {"q":"Osteonic canal running obliquely and transversely connecting the medullary cavity with the cortex:","o":["Volkmann canal","Howship lacunae","Lacunae","Canaliculi"],"a":0,"e":"Volkmann's canals (perforating canals) run obliquely/transversely, connecting Haversian canals to each other and to the periosteum and endosteum. They carry blood vessels and nerves. Haversian canals run longitudinally along the long axis of bone.<br><br>Key discriminator: Volkmann's canals → transverse/oblique (connect Haversian canals to periosteum) | Haversian canals → longitudinal (contain vessels/nerves in osteons) | Lacunae → spaces containing osteocytes | Canaliculi → tiny channels connecting lacunae | Volkmann = transverse connector."},
/*160*/ {"q":"Site of bone marrow biopsy in infants:","o":["Tibia","Sternum","Iliac spine","Pubis"],"a":0,"e":"In infants and young children, the preferred site for bone marrow biopsy and aspiration is the proximal tibia (anteromedial surface), because it has active red marrow and is easily accessible. In adults, the posterior iliac crest is preferred.<br><br>Key discriminator: infants → proximal tibia (bone marrow biopsy site) | Adults/older children → posterior iliac crest | Sternum → adults for aspiration only (not biopsy, risk of cardiac perforation) | Tibia = infant bone marrow site."},
/*161*/ {"q":"Pseudo orange appearance of breast occurs in malignancy of:","o":["Endoderm","Mesoderm","Ectoderm","Lobules of Breast"],"a":2,"e":"Peau d'orange (orange peel appearance) of the breast skin occurs when malignancy obstructs the dermal lymphatics. The skin dimpling is due to tethering of sweat gland ducts (ectodermal origin) while surrounding skin swells with lymphoedema.<br><br>Key discriminator: peau d'orange → dermal lymphatic obstruction → ectodermal skin dimpling at sweat duct openings | Cooper's ligament dimpling → separate sign (direct tethering) | Peau d'orange = advanced/inflammatory breast cancer sign | Skin (ectoderm) = the layer showing the orange peel appearance."},
/*162*/ {"q":"Route of spread from breast CA to peritoneum, liver and pelvic organs:","o":["Longitudinal Ligament of Breast","Suspensory Ligament of Breast","Lobules of Breast","Lymphatics"],"a":3,"e":"Breast carcinoma spreads to the peritoneum, liver, and pelvic organs via lymphatic channels — the thoracic duct drains into systemic venous circulation allowing haematogenous and lymphatic seeding of distant organs. Lymphatic spread precedes haematogenous spread.<br><br>Key discriminator: breast CA spread → lymphatics (axillary nodes first) → then haematogenous (liver, lung, bone, brain) | Peritoneal spread → via lymphatics/transcoelomically | Cooper's/suspensory ligament → local skin involvement only | Lymphatics = route for distant spread."},
/*163*/ {"q":"CSF examination necessary to:","o":["Subarachnoid/Meningioma and Retroperitoneal","Retroperitoneal and retrocecal","Impaction","Drag out"],"a":0,"e":"CSF examination (lumbar puncture) is necessary to diagnose subarachnoid haemorrhage (xanthochromia), meningitis (organisms/cells), and assess intracranial pressure. It is indicated when CNS infection or subarachnoid bleeding is suspected after ruling out raised ICP on CT.<br><br>Key discriminator: LP essential for → meningitis diagnosis + SAH (xanthochromia after CT negative) + CNS tumour cells | LP contraindicated in → raised ICP with mass effect (risk of coning) | CSF xanthochromia = SAH marker | Always CT before LP if raised ICP suspected."},
/*164*/ {"q":"A patient with Hydrocephalus. CT scan brain shows dilated blood and dye between brain cells. Cells between brain and fluid: Ependymal cells. Ans: A. A patient with CT scan brain shows dilated ventricles. CT scan brain shows dilated blood. Diagnosis:","o":["Subarachnoid nodes","Submental","Submandibular","Juguloomohyoid"],"a":2,"e":"The submandibular lymph nodes drain the anterior tongue, floor of mouth, lower lip, and cheek. They are commonly enlarged in dental infections, oral carcinomas, and floor of mouth pathology. They lie in the submandibular triangle deep to the mandible.<br><br>Key discriminator: submandibular nodes → drain oral cavity + anterior tongue + lower lip | Submental nodes → drain chin + central lower lip + tip of tongue | Jugulodigastric → drain tonsil/posterior tongue | Submandibular = oral cavity primary drainage nodes."},
/*165*/ {"q":"Patient with anterior 2/3 tongue carcinoma what is the lymphatic drainage:","o":["Submandibular","Submental","Juguloomohyoid","Digastric"],"a":0,"e":"The anterior two-thirds of the tongue drains to the submandibular lymph nodes (tip of tongue also to submental nodes). Posterior third of tongue drains to deep cervical (jugulodigastric) nodes. Tongue carcinoma spreads predictably through these nodal stations.<br><br>Key discriminator: anterior 2/3 tongue → submandibular nodes (+ submental for tip) | Posterior 1/3 tongue → jugulodigastric deep cervical | Tongue midline → bilateral drainage | Tongue CA nodal status = major prognostic factor."},
/*166*/ {"q":"Bone marrow biopsy is done at site of following:","o":["Pubis","Tibia","Sternum","Iliac crest"],"a":3,"e":"In adults, the posterior superior iliac crest (iliac spine) is the preferred site for bone marrow trephine biopsy. It provides adequate marrow for histological assessment and is safe and accessible. Sternum is used for aspiration only.<br><br>Key discriminator: adults → posterior iliac crest (trephine biopsy site) | Infants → proximal tibia | Sternum → adults, aspiration only (NOT biopsy — cardiac perforation risk) | Iliac crest = standard adult bone marrow biopsy site."},
/*167*/ {"q":"In hanging sudden death occurs due to fracture of odontoid process of axis. Ans: B. In hanging sudden death occurs:","o":["Axis vertebra","Thyroxin","ADH","Oxytocin"],"a":3,"e":"Oxytocin is released during suckling (Ferguson reflex), labour, and orgasm. It causes uterine contractions, milk ejection, and promotes bonding. It is synthesised in the hypothalamus (paraventricular nucleus) and stored in the posterior pituitary.<br><br>Key discriminator: oxytocin → milk ejection + uterine contractions + bonding | ADH (vasopressin) → water reabsorption + vasoconstriction | Both → synthesised in hypothalamus, stored in posterior pituitary | Oxytocin = the 'love hormone' / milk ejection hormone."},
/*168*/ {"q":"Patient from Hill station having labour pain HCG done. Foetus having anomaly. Foetus at greater risk at:","o":["0,1,6 month","1,6 month","12 month","4,1,2 month"],"a":0,"e":"The foetus is at greatest risk of congenital anomalies from teratogens during organogenesis (weeks 3-8 of embryological development = 1st trimester, approximately months 0-1-2-3). Major organ systems are most susceptible during this critical period of differentiation.<br><br>Key discriminator: teratogen risk → greatest during organogenesis (weeks 3-8, 1st trimester) | Before week 3 → all-or-nothing effect | After week 8 → growth + functional maturation affected, not structural | 1st trimester = peak teratogen susceptibility."},
/*169*/ {"q":"A child presented with dark urine, and deficiency whats likely cause:","o":["Galactosaemia","Alkaptonuria","Maple disease","Phenylketonuria"],"a":1,"e":"Alkaptonuria (homogentisic aciduria) is caused by deficiency of homogentisic acid oxidase. Homogentisic acid accumulates and is excreted in urine, which turns dark on standing (oxidised to a melanin-like polymer). Also causes ochronosis (dark pigmentation in connective tissue) and arthritis.<br><br>Key discriminator: dark urine on standing → alkaptonuria (homogentisic acid oxidase deficiency) | Maple syrup urine disease → sweet-smelling urine (branched-chain ketoaciduria) | Phenylketonuria → mousy urine odour | Galactosaemia → jaundice + cataracts + liver disease | Dark urine standing = alkaptonuria."},
/*170*/ {"q":"A child presented with dark urine and deficiency what's likely cause. homogenistic:","o":["Galactosaemia","Alkaptonuria","Nicotinic disease","Phenylalanine disease"],"a":1,"e":"Alkaptonuria results from homogentisic acid oxidase deficiency — homogentisic acid (from phenylalanine/tyrosine metabolism) accumulates. It causes: urine darkening on standing, ochronosis (blue-black pigmentation of cartilage/connective tissue), and degenerative arthropathy in later life.<br><br>Key discriminator: alkaptonuria → missing enzyme = homogentisic acid oxidase | Pathway: Phe → Tyr → homogentisic acid (accumulates) | Phenylketonuria → missing phenylalanine hydroxylase (Phe accumulates) | Alkaptonuria = homogentisic acid oxidase = dark urine = ochronosis."},
/*171*/ {"q":"Note: Question repeated twice in exam. Scrotal lymph drainage:","o":["Superficial inguinal lymph nodes","Deep inguinal lymph nodes","Submucosal fibrosis","Leukoplakia"],"a":0,"e":"The scrotal skin drains to the superficial inguinal lymph nodes. The testes drain to the para-aortic nodes (L1-L2). This distinction is surgically important — scrotal involvement of testicular tumours changes nodal staging management.<br><br>Key discriminator: scrotal skin → superficial inguinal nodes | Testes (content) → para-aortic nodes (L1-L2) | Glans penis → deep inguinal nodes | Scrotal skin ≠ testicular drainage — different nodal groups."},
/*172*/ {"q":"Lymphatic drainage of tumour at anal verge:","o":["Internal iliac nodes","Aortic lymph nodes","Deep inguinal LNs","Superficial inguinal LNs"],"a":3,"e":"The anal verge (below the dentate/pectinate line) drains to the superficial inguinal lymph nodes. Above the dentate line, drainage is to the internal iliac and para-rectal nodes. The dentate line is the crucial watershed for lymphatic drainage of the anal canal.<br><br>Key discriminator: below dentate line → superficial inguinal nodes | Above dentate line → internal iliac + para-rectal nodes | Anal verge = below dentate = inguinal nodes | This distinction determines spread pattern of anal canal cancers."},
/*173*/ {"q":"60 year old man presented in opd with complain of haematuria and frequency on DRE there is prostate is stony hard mass felt that there is urinary frequency on DRE. Is prostate is stony hard mass felt. Prostate CA is lymphatic drainage to:","o":["Internal iliac","Pelvic lymph nodes","Superficial inguinal LNs","Lumbar LN nodes"],"a":0,"e":"Prostate carcinoma drains first to the internal iliac (obturator) lymph nodes, then to the common iliac and para-aortic nodes. Stony hard prostate on DRE with haematuria and frequency strongly suggests malignancy.<br><br>Key discriminator: prostate CA → internal iliac (obturator) nodes first | Then → common iliac → para-aortic | Testes → para-aortic (skip inguinal) | Bladder → internal + external iliac | Prostate = internal iliac = first echelon lymph nodes."},
/*174*/ {"q":"Patient with anterior carcinoma what is the lymphatic drainage:","o":["Para aortic","Common iliac","Superficial inguinal","Deep inguinal"],"a":3,"e":"The glans penis drains to the deep inguinal lymph nodes (Cloquet's node) as the first-echelon nodes, then to the external iliac nodes. The shaft of the penis drains to superficial inguinal nodes. Deep inguinal nodes are deep to the cribriform fascia.<br><br>Key discriminator: glans penis → deep inguinal (Cloquet's node) | Penile shaft → superficial inguinal | Testes → para-aortic | Scrotum → superficial inguinal | Deep inguinal = glans penis drainage."},
/*175*/ {"q":"Which phospholipase C as a secondary messenger:","o":["Tip of Tongue — Submucosa","Posterior 1/3rd Tongue — Submucosa","Anterior — Jugulo","Onohyoid"],"a":0,"e":"The tip of the tongue drains lymphatics to the submental nodes (midline tip) and submandibular nodes (lateral tip). This is distinct from the anterior two-thirds (submandibular) and posterior third (jugulodigastric). The sub-mental triangle nodes receive drainage from the tongue tip.<br><br>Key discriminator: tongue tip → submental nodes | Anterior 2/3 tongue → submandibular | Posterior 1/3 → jugulodigastric (deep cervical) | Tongue tip is unique in bilateral + submental drainage."},
/*176*/ {"q":"Beetie nut chewing leads to following disease:","o":["ADH","GH","Thyroxin","Oxytocin"],"a":0,"e":"Betel nut (areca nut) chewing causes oral submucous fibrosis (OSMF) — a premalignant condition causing progressive fibrosis of the oral mucosa, trismus, and increased risk of oral squamous cell carcinoma. ADH is not related — the disease answer is OSMF/oral SCC risk.<br><br>Key discriminator: betel nut → oral submucous fibrosis (OSMF) → premalignant → oral SCC | Also → leukoplakia | Tobacco → oral SCC directly | Betel nut = OSMF = the classic premalignant oral lesion from chewing habits."},
/*177*/ {"q":"In Erythroplakia which type of anaemia occur:","o":["Chronic ulcer","Iron deficiency anaemia","Megaloblastic anaemia","Sideroblastic anaemia"],"a":1,"e":"Erythroplakia (red patches of oral mucosa) is the premalignant lesion with highest malignant transformation rate (>50%). Iron deficiency anaemia is associated with oral mucosal changes including angular cheilitis, glossitis, and Plummer-Vinson syndrome (postcricoid webs) predisposing to oral SCC.<br><br>Key discriminator: Plummer-Vinson syndrome → iron deficiency anaemia + postcricoid web + glossitis + increased SCC risk of oesophagus/oral cavity | Erythroplakia → highest malignant potential of oral lesions | Iron deficiency → oral mucosal vulnerability + Plummer-Vinson."},
/*178*/ {"q":"A 24 years old pregnant lady who is 6 months pregnant with MCV 58 serum ferritin level 150 ng/dl. In Pregnant women at term which type of anaemia occur:","o":["Thalassaemia","Sideroblastic anaemia","Iron deficiency anaemia","Megaloblastic anaemia"],"a":0,"e":"MCV 58 (microcytic) with normal/high ferritin (150 ng/dl) in a pregnant woman = thalassaemia trait, not iron deficiency (which would have low ferritin). This pattern is classic for thalassaemia trait — microcytosis with preserved iron stores.<br><br>Key discriminator: microcytic + LOW ferritin → iron deficiency | Microcytic + NORMAL/HIGH ferritin → thalassaemia trait | Pregnancy + microcytosis → must check ferritin to distinguish IDA from thalassaemia | Ferritin 150 = normal = not iron deficient = thalassaemia."},
/*179*/ {"q":"Infant with rudimentary hand and irregular small bones. This is likely:","o":["Ferritin normal","Iron deficiency — MCV low +","Thalassaemia trait — MCV low +","Congenital hand foot syndrome"],"a":3,"e":"Rudimentary hands with irregular small bones in a newborn is consistent with congenital hand-foot syndrome (ectrodactyly or amniotic band syndrome), where amniotic bands constrict developing limb parts causing reduction defects. Digital anomalies range from syndactyly to complete absence.<br><br>Key discriminator: amniotic band syndrome → constriction rings → digital/limb reduction defects | Ectrodactyly → 'lobster claw' deformity (absent central digits) | Oligodactyly → fewer than 5 digits | Rudimentary irregular small bones = amniotic band/congenital limb defect."},
/*180*/ {"q":"A new born baby is born to a 20 year old primigravida. On examination the baby has amputated limb. The most likely cause is:","o":["Gigantism","Microconia","Amniotic bands","Nicomelia"],"a":2,"e":"Amniotic band syndrome causes constriction and amputation of foetal limbs when fibrous bands from the amniotic membrane wrap around developing structures. Spontaneous foetal amputation of digits or limbs is pathognomonic of this condition.<br><br>Key discriminator: limb amputation in newborn → amniotic band syndrome (fibrous bands constrict) | Achondroplasia → short limbs but intact (not amputated) | Phocomelia → limb reduction from thalidomide | Amniotic bands = constriction → amputation = the only cause of intrauterine amputation."},
/*181*/ {"q":"Pregnant lady with 41 weeks OS anxious days Post term pregnancy. What term pregnancy requested for induction of labour by WHO is called at:","o":["Amniotic bands","Cord prolapse","Alcoholism in mother","Amniotic bonds"],"a":1,"e":"Post-term pregnancy (>41 weeks) carries risks of cord compression, meconium aspiration, placental insufficiency, and foetal distress. WHO recommends induction of labour at 41-42 weeks. Cord prolapse is the complication most feared with prolonged pregnancy and PROM.<br><br>Key discriminator: post-term pregnancy (>41 weeks) → induction recommended | Cord prolapse → obstetric emergency (cord before presenting part) | Risk factors for cord prolapse → PROM + unstable lie + polyhydramnios | Induction at 41 weeks = WHO recommendation."},
/*182*/ {"q":"Which one of following hepatitis spread commonly by blood transfusion:","o":["Hep A","Hep B","Hep C","Hep D"],"a":1,"e":"Hepatitis B is the most efficiently transmitted hepatitis virus through blood transfusion, followed by Hepatitis C. Blood screening has dramatically reduced transfusion-transmitted HBV and HCV. Hepatitis A is faecal-oral only; Hepatitis D requires HBV co-infection.<br><br>Key discriminator: blood transfusion transmission → HBV (most efficiently) + HCV | HBV → also sexual + perinatal | HCV → primarily blood-borne, now major transfusion-transmitted hepatitis | HAV/HEV → faecal-oral only, not blood-borne."},
/*183*/ {"q":"IGE antibodies present in which of following:","o":["Chronic T cells cause immune reaction","Follicular Phase","Pre menstrual","Proliferation by"],"a":0,"e":"IgE antibodies are produced by plasma cells and bind to Fc receptors on mast cells and basophils. They mediate Type I hypersensitivity reactions. Elevated IgE is found in atopic conditions (asthma, eczema, allergic rhinitis) and helminthic infections. Chronic T-cell-mediated immune reactions (Type IV) involve IgE indirectly.<br><br>Key discriminator: IgE → Type I hypersensitivity (anaphylaxis, atopy) | IgG → Type II/III hypersensitivity + opsonisation | IgA → mucosal immunity | IgM → primary immune response + complement activation | IgE = mast cell/basophil trigger."},
/*184*/ {"q":"Plasma cells. NK cells. Lymphocytes. Macrophages. A patient came with left face and chin abnormal on x-ray and ramit was abnormal. Ear and chin diseases were distorted left. Diagnosis:","o":["Plasma cells","Macrophages","Mastocytes","Lymphocytes"],"a":0,"e":"Plasma cells are the antibody-secreting terminal differentiation product of B lymphocytes. They have characteristic 'clock-face' chromatin and eccentric nucleus on histology. They produce all five immunoglobulin classes and are found in bone marrow, lymph nodes, and spleen.<br><br>Key discriminator: plasma cells → antibody production (terminal B cell differentiation) | Clock-face chromatin + eccentric nucleus → plasma cell histology | Multiple myeloma → malignant plasma cells | B cell → plasma cell after antigen stimulation + T cell help."},
/*185*/ {"q":"Chest drain passed to the lower border of the rib caused damage:","o":["Intercostal nerve","Intercostal vein","Intercostal muscles","Intercostal artery"],"a":0,"e":"Intercostal neurovascular bundle (nerve, artery, vein) runs in the costal groove along the inferior border of each rib. Chest drain insertion below the rib (as recommended: 'above the lower rib') avoids this bundle. Insertion at the lower border risks intercostal nerve damage causing intercostal neuralgia.<br><br>Key discriminator: neurovascular bundle → inferior rib border (groove) | Safe chest drain position → above the upper border of the lower rib | Damage below rib → nerve > artery > vein at risk | Order in groove: Vein → Artery → Nerve (VAN) from superior to inferior."},
/*186*/ {"q":"Which one of the following prevents collapse of lung:","o":["Intercostal nerve","Intercostal vein","Intercostal muscles","Transpulmonary pressure"],"a":3,"e":"Transpulmonary pressure (alveolar pressure minus pleural pressure) is the distending pressure that keeps the lungs expanded. It is normally positive, preventing collapse. When pleural pressure exceeds alveolar pressure (e.g., pneumothorax), the lung collapses.<br><br>Key discriminator: transpulmonary pressure → prevents lung collapse (keeps alveoli open) | Surfactant → reduces alveolar surface tension, prevents alveolar collapse | Pneumothorax → transpulmonary pressure lost → lung collapses | Transpulmonary pressure = the lung-distending force."},
/*187*/ {"q":"A bullet hit a person from superior iliac region and goes out massively at 4th lumbar region. Which major vessel is hit at the root of mesentery?","o":["Superior mesenteric artery","Right iliac artery","Pelvic brim","External iliac artery"],"a":0,"e":"A bullet entering at the superior iliac region and exiting at L4 would traverse the root of the small bowel mesentery. The superior mesenteric artery (SMA) arises at L1 and its branches run in the mesentery root — the SMA is the major vessel at the root of the mesentery at risk in this trajectory.<br><br>Key discriminator: root of mesentery → contains SMA + superior mesenteric vein | SMA arises at L1 from aorta | Bullet from iliac crest to L4 traverses SMA territory | SMA = the major named vessel at the mesentery root."},
/*188*/ {"q":"Superior mesenteric vessel:","o":["Aorta","IVC","Inferior mesenteric vessel","Superior mesenteric vessel"],"a":3,"e":"The superior mesenteric vein drains the small intestine, ascending colon, and transverse colon. It joins the splenic vein to form the portal vein behind the neck of the pancreas. Understanding SMV drainage is critical for portal hypertension management.<br><br>Key discriminator: SMV + splenic vein → portal vein (behind pancreatic neck) | IMV → drains into splenic vein or SMV | SMA → arises at L1 from aorta | Portal vein = SMV + splenic vein junction."},
/*189*/ {"q":"Superior mesenteric vessel. Carcinogen cause mutation, these genetic mutations are:","o":["Temporary","Non lethal","Lethal","Acquired"],"a":1,"e":"Carcinogen-induced mutations causing carcinogenesis are non-lethal to the cell — lethal mutations kill the cell before it can proliferate. Only mutations that allow cell survival AND confer growth advantages (non-lethal) lead to cancer progression through clonal expansion.<br><br>Key discriminator: carcinogenic mutations → non-lethal (cell survives + gains growth advantage) | Lethal mutations → cell dies (no cancer) | Carcinogenesis = accumulated non-lethal mutations → clonal expansion | Non-lethal + heritable + growth advantage = carcinogenic mutation requirements."},
/*190*/ {"q":"In esophagus from squamous to columnar transition occurs at:","o":["Upper 2/3","Squamous cell carcinoma","Gastroesophageal junction","Alcohol hot liquids"],"a":2,"e":"The squamocolumnar junction (Z-line) occurs at the gastroesophageal junction (GEJ), where stratified squamous oesophageal epithelium transitions to columnar gastric epithelium. In Barrett's oesophagus, this junction migrates proximally as columnar metaplasia replaces squamous epithelium.<br><br>Key discriminator: squamocolumnar junction → gastroesophageal junction (Z-line) | Barrett's oesophagus → Z-line migrates proximally (columnar metaplasia) | Middle 1/3 SCC → squamous cell origin | GEJ adenocarcinoma → from Barrett's metaplasia | Z-line = GEJ = squamocolumnar junction."},
/*191*/ {"q":"A person is having history of smoking and drinking from many years. On endoscopy there is a mass in middle third of esophagus. What could it likely be:","o":["Adenocarcinoma","Squamous cell carcinoma","Bactrus esophagitis","Chronic gastritis"],"a":1,"e":"Middle third oesophageal mass with smoking and alcohol history = squamous cell carcinoma. The middle third oesophagus is lined by stratified squamous epithelium, and smoking + alcohol synergistically increase SCC risk here.<br><br>Key discriminator: middle 1/3 oesophagus + smoking + alcohol → SCC | Lower 1/3 + GERD + Barrett's → adenocarcinoma | Upper 1/3 → SCC (post-cricoid, Plummer-Vinson) | Location + risk factors determine oesophageal CA type."},
/*192*/ {"q":"A smoker working in tyre factory came with haematuria cause of:","o":["Lower 1/3rd (Adenocarcinoma)","Barrett Esophagus","Chronic GERD","Achalasia"],"a":0,"e":"Tyre factory workers are exposed to aromatic amines (aniline dyes, beta-naphthylamine), which are excreted in urine and cause transitional cell carcinoma (TCC) of the bladder — presenting as painless haematuria. Rubber/tyre industry workers have high bladder cancer risk.<br><br>Key discriminator: tyre/rubber/dye factory + haematuria → bladder TCC (aromatic amines) | Smoking alone → also bladder CA | Aromatic amines → metabolised to carcinogenic hydroxylamines in urine → urothelial damage | Occupational bladder cancer = aromatic amines."},
/*193*/ {"q":"A patient with Uroporphyrin 1 in urine diagnosed with congenital erythropoietic uroporphyria enzyme deficient in:","o":["Uroporphyrinogen II Synthase","Uroporphyrinogen III Synthase","ALA Dehydratase","Perodichlase"],"a":1,"e":"Congenital erythropoietic porphyria (Gunther's disease) is caused by deficiency of uroporphyrinogen III synthase (cosynthetase), leading to accumulation of uroporphyrin I (symmetric isomer) instead of uroporphyrin III. Presents with photosensitivity, red urine, and haemolytic anaemia.<br><br>Key discriminator: congenital erythropoietic porphyria → uroporphyrinogen III synthase deficiency | ALA dehydratase deficiency → plumboporphyria (lead poisoning mimics) | Acute intermittent porphyria → PBG deaminase deficiency | Uroporphyrin I accumulation = cosynthetase (UROGEN III synthase) deficiency."},
/*194*/ {"q":"A 44 year old child boy was observed to be attended in clinic and was suffering from a heart condition. X ray neck showed fused vertebrae and limited movement of upper limb. Posterior aspect short neck, low hair line observed. What is the most likely diagnosis?","o":["A4","B (FA)","Uroporphyrin","Klippel-Feil syndrome"],"a":3,"e":"Klippel-Feil syndrome (congenital synostosis of cervical vertebrae) presents with the classic triad: short neck, low posterior hairline, and limited cervical range of motion. It results from failure of normal segmentation of cervical somites during weeks 3-8 of embryogenesis.<br><br>Key discriminator: Klippel-Feil triad → short neck + low hairline + limited neck movement | Associated with → Sprengel's deformity (elevated scapula) + cardiac defects + scoliosis | Fused cervical vertebrae on X-ray = Klippel-Feil | 'Short neck, low hairline, stiff neck' = Klippel-Feil."},
/*195*/ {"q":"A female with short stature hand and neck region swollen and neck and is now 20 years of age with amenorrhoea and secondary sexual characteristic likely karyotype:","o":["45XO","46XY","47XX","47XXY"],"a":0,"e":"Short stature + primary amenorrhoea + absent secondary sexual characteristics + neck swelling (webbed neck) in a phenotypic female = Turner syndrome (45,XO). Features include streak gonads, bicuspid aortic valve, coarctation of aorta, and horseshoe kidney.<br><br>Key discriminator: 45,XO → Turner syndrome (short stature + primary amenorrhoea + webbed neck + shield chest + cubitus valgus) | 47,XXY → Klinefelter (tall male + hypogonadism) | 47,XXX → triple X female (usually fertile) | Turner = 45,XO = female phenotype + gonadal dysgenesis."},
/*196*/ {"q":"C (Turner Syndrome). In 40 year age female the chances of down syndrome are:","o":["1 in 100","1 in 700","1 in 1000","1 in 1500"],"a":0,"e":"The risk of Down syndrome (trisomy 21) at maternal age 40 is approximately 1 in 100 (1%). It increases exponentially with maternal age: at 35 it is ~1:350, at 40 ~1:100, at 45 ~1:30. Advanced maternal age causes meiotic non-disjunction.<br><br>Key discriminator: Down syndrome risk at 40 → 1 in 100 | At 35 → 1:350 | At 45 → 1:30 | General population → 1:700 (average maternal age) | Maternal age 40 = 1:100 = key fact for prenatal counselling."},
/*197*/ {"q":"X linked recessive disorders in male presents as:","o":["Risk at 45 years","Risk at 35 years","X linked recessive disorders less in male","Monozygous for X gene"],"a":3,"e":"Males are hemizygous for X-linked genes (one X chromosome), so they express X-linked recessive disorders whenever they carry the mutation — they cannot be 'carriers'. They are effectively hemizygous (monozygous for X), expressing the phenotype from a single copy.<br><br>Key discriminator: males (XY) → hemizygous for X-linked genes → always express X-linked recessive disorders | Females (XX) → carriers if heterozygous, affected only if homozygous | X-linked recessive examples → haemophilia A/B, G6PD, Duchenne MD, colour blindness."},
/*198*/ {"q":"Which one is directly related to coronary artery disease:","o":["Bizygoous for X gene","Heterozygous for X gene","Monozygous for X gene","Plasma cholesterol"],"a":3,"e":"Elevated plasma LDL cholesterol is the most directly modifiable risk factor causally related to coronary artery disease. The relationship is dose-dependent — every 1 mmol/L increase in LDL raises CAD risk by ~20-25%. Mendelian randomisation studies confirm causality.<br><br>Key discriminator: plasma LDL cholesterol → directly causally related to CAD | HDL → inversely related (protective) | Triglycerides → less directly related | Plasma cholesterol (LDL specifically) = most direct CAD relationship | Statins → lower LDL → proven CAD mortality reduction."},
/*199*/ {"q":"After transfusion acute reaction:","o":["Plasma cholesterol","Nor adrenaline","Dopamine","Trans fatty acid"],"a":3,"e":"Acute haemolytic transfusion reaction (AHTR) is caused by ABO incompatibility — recipient's preformed IgM antibodies activate complement against donor RBCs, causing intravascular haemolysis. Symptoms: fever, rigors, back pain, haemoglobinuria, and shock within minutes of transfusion start.<br><br>Key discriminator: acute transfusion reaction → ABO incompatibility (IgM + complement) → intravascular haemolysis | TRALI → within 6 hours, non-cardiogenic pulmonary oedema | Delayed haemolytic → days to weeks (IgG) | AHTR = immediate → stop transfusion immediately."},
/*200*/ {"q":"Which one is directly related to coronary artery disease. After transfusion acute reaction. Negative predictive value:","o":["Sensitivity","Specificity","Positive predictive value","Negative predictive value"],"a":3,"e":"Negative predictive value (NPV) = probability that a person with a negative test truly does not have the disease = TN/(TN+FN). It depends on both specificity and disease prevalence — high NPV means a negative test reliably rules out disease.<br><br>Key discriminator: NPV → TN/(TN+FN) = probability negative test = truly disease-free | PPV → TP/(TP+FP) = probability positive test = truly diseased | Sensitivity → TP/(TP+FN) | Specificity → TN/(TN+FP) | NPV + PPV depend on prevalence; sensitivity + specificity do not."}
,
/*201*/ {"q":"Mode is:","o":["Mean and standard deviation","Mean and variance","Most observed value","Median"],"a":2,"e":"The mode is the most frequently occurring value in a data set. It is the only measure of central tendency that can be used with nominal data, and a dataset can have more than one mode (bimodal/multimodal).<br><br>Key discriminator: mode → most frequently occurring value | Median → middle value when ordered | Mean → arithmetic average | Mode = only average usable with categorical/nominal data."},
/*202*/ {"q":"Which drug has Shorter half life and given in inhalation:","o":["Morphine","Dopamine","Thiopental","GH"],"a":2,"e":"Thiopental (thiopentone) has a very short context-sensitive half-life due to rapid redistribution from brain to peripheral tissues, making it ideal for IV induction. Inhaled anaesthetic agents (halothane, sevoflurane) have short half-lives due to rapid pulmonary elimination.<br><br>Key discriminator: shortest half-life inhalation anaesthetic → desflurane (blood-gas coefficient 0.45) | Thiopental → ultra-short IV (redistribution) | Half-life of inhaled agents → determined by blood:gas partition coefficient | Low coefficient = rapid onset and offset."},
/*203*/ {"q":"Cabergoline MOA is:","o":["D2 agonist","D2 against","B1 agonist","B1 against"],"a":0,"e":"Cabergoline is a long-acting selective D2 dopamine receptor agonist used to treat hyperprolactinaemia and Parkinson's disease. It suppresses prolactin secretion by acting on D2 receptors on lactotroph cells in the anterior pituitary.<br><br>Key discriminator: cabergoline → D2 agonist → inhibits prolactin secretion | Bromocriptine → also D2 agonist (shorter acting) | Metoclopramide → D2 antagonist → causes hyperprolactinaemia | D2 agonist = suppresses prolactin."},
/*204*/ {"q":"A police man was sent to you he has urine has some drug found. Opioid and other drugs found because his urine has some other drug found:","o":["Denial","Depression","Blaming the doctor","Politey acceptance"],"a":3,"e":"When confronted with objective evidence of drug use (positive urine drug screen), the appropriate psychological response in a therapeutic context is polite acceptance and acknowledgement of the finding. Denial, projection (blaming others), and bargaining are defence mechanisms that impede treatment.<br><br>Key discriminator: polite acceptance → healthy response to confrontation with evidence | Denial → most common initial defence mechanism in addiction | Blaming → projection defence mechanism | Acceptance = first step toward behaviour change (Prochaska stages of change)."},
/*205*/ {"q":"Which of the following Hepatitis most likely progress to chronic liver disease:","o":["Hep A","Hep B","Hep C","Hep D"],"a":2,"e":"Hepatitis C progresses to chronic infection in 75-85% of cases (highest chronicity rate of all hepatitis viruses), leading to cirrhosis in 20% and hepatocellular carcinoma. HBV chronicity: 90% in neonates, 5-10% in adults.<br><br>Key discriminator: HCV → 75-85% chronic (highest rate) | HBV → 5-10% chronic in adults (90% if perinatal) | HAV/HEV → never chronic (self-limiting) | HCV = most likely to progress to chronic liver disease."},
/*206*/ {"q":"Which of following hepatitis spread commonly by blood transfusion:","o":["Hep A","Hep B","Hep C","Hep G"],"a":2,"e":"Hepatitis C is now the primary transfusion-transmitted hepatitis in countries where HBV screening is established. Before HCV screening (pre-1990), HCV was responsible for most post-transfusion hepatitis. HBV is also blood-borne but is better screened.<br><br>Key discriminator: post-transfusion hepatitis now → HCV (most common blood-borne hepatitis remaining) | HBV → also blood-borne but well-screened | HAV/HEV → faecal-oral only | HCV = current predominant transfusion-transmitted hepatitis."},
/*207*/ {"q":"Vaccination schedule for Hepatitis:","o":["0,1,6 month","0,1,8 month","Hep A and E — Naked Viruses","Vaccination for"],"a":0,"e":"Standard hepatitis B vaccination schedule: 0, 1, and 6 months (three doses). An accelerated schedule (0, 1, 2 months + booster at 12 months) is used for rapid protection. The 0-1-6 schedule produces the best long-term antibody response.<br><br>Key discriminator: HBV vaccination → 0, 1, 6 months (standard) | Accelerated → 0, 1, 2 months + booster | HBV vaccine → recombinant HBsAg (not live) | Anti-HBs >10 mIU/mL = protective titre."},
/*208*/ {"q":"Climber at high altitude hypothermia cold weather adapts to base camp returning to base camp at high altitude experience:","o":["0,1,8 month","Hepatitis","Rapid Filling","Slow Filling"],"a":3,"e":"On return to base camp from high altitude, the body re-adapts to normal oxygen levels. The respiratory rate slows (less hypoxic drive), and the cardiovascular system reduces its high-altitude adaptations (polycythaemia persists longer). Slow filling refers to cardiac adaptation during re-acclimatisation.<br><br>Key discriminator: high altitude adaptation → ↑RBC + ↑2,3-DPG + ↑ventilation + ↑Hb | Return to sea level → gradual reversal over weeks | Polycythaemia resolves last | Acute mountain sickness resolves first on descent."},
/*209*/ {"q":"Which of the following is directly control autonomic reflex system of body:","o":["Posterior hypothalamus","Anterior hypothalamus","Lateral hypothalamus","Medial hypothalamus"],"a":0,"e":"The posterior hypothalamus controls sympathetic autonomic responses and heat conservation (vasoconstriction, shivering). The anterior hypothalamus controls parasympathetic responses and heat dissipation (sweating, vasodilation). Together they regulate the autonomic nervous system.<br><br>Key discriminator: posterior hypothalamus → sympathetic + heat conservation | Anterior hypothalamus → parasympathetic + heat dissipation | Lateral hypothalamus → hunger centre | Ventromedial → satiety centre | Posterior = sympathetic autonomic control."},
/*210*/ {"q":"A patient can't abduct and adduct his fingers due to damage of which of the following nerve:","o":["Axillary nerve","Median nerve","Ulnar nerve","Radial nerve"],"a":2,"e":"Finger abduction (DAB: dorsal interossei) and adduction (PAD: palmar interossei) are exclusively supplied by the deep branch of the ulnar nerve. Damage causes loss of both abduction and adduction of fingers.<br><br>Key discriminator: ulnar nerve → all interossei (abduction + adduction of fingers) | Median nerve → thenar muscles (thumb opposition, abduction) | Radial nerve → wrist/finger extensors only | Interossei = ulnar nerve = finger spread/close."},
/*211*/ {"q":"A person got stab on upper arm and floor of Axilla. Which structure will be damaged:","o":["Radial nerve","Axillary nerve","Ulnar nerve","Median nerve"],"a":1,"e":"A stab wound to the floor of the axilla risks the axillary nerve, which emerges from the posterior cord of the brachial plexus and passes through the quadrangular space close to the axillary floor. Damage causes deltoid paralysis (loss of shoulder abduction) and loss of sensation over the regimental badge area.<br><br>Key discriminator: axillary floor stab → axillary nerve at risk | Axillary nerve → deltoid (shoulder abduction) + teres minor + regimental badge sensation | Radial nerve → posterior arm/forearm | Axillary nerve = most vulnerable nerve at axillary floor."},
/*212*/ {"q":"A person who is unable to button and hold pen due to damage of which muscle. Rapid aortic pressure is highest at which Phase of cardiac cycle:","o":["Aortic pressure highest at Rapid ejection phase","Slow Filling","Isovolumetric relaxation","Isovolumetric contraction"],"a":0,"e":"Aortic pressure is highest during the rapid ejection phase of systole, when the left ventricle forcefully ejects blood into the aorta, causing peak systolic pressure. This corresponds to the systolic peak on the arterial waveform.<br><br>Key discriminator: aortic pressure peak → rapid ejection phase (systole) | Lowest aortic pressure → end diastole (just before next systole) | Dicrotic notch → aortic valve closure (end of ejection) | Rapid ejection = peak aortic pressure = peak systolic BP."},
/*213*/ {"q":"Intercostobrachial nerve damage between CS and:","o":["Axillary nerve","Ulnar nerve","Intercostobrachial nerve","Radial nerve"],"a":2,"e":"The intercostobrachial nerve (lateral cutaneous branch of T2) supplies sensation to the medial upper arm and axilla. It is commonly damaged during axillary lymph node dissection for breast cancer, causing numbness and paraesthesia of the medial upper arm.<br><br>Key discriminator: intercostobrachial nerve → medial upper arm sensation | Commonly damaged in → axillary lymph node dissection (breast CA surgery) | Axillary nerve → deltoid motor + lateral arm sensation | Intercostobrachial = T2 cutaneous = axillary dissection casualty."},
/*214*/ {"q":"Aortic pressure is highest at which phase of cardiac cycle:","o":["Rapid Filling","Isovolumetric contraction","Isovolumetric relaxation","Slow Filling"],"a":1,"e":"During isovolumetric contraction, LV pressure rises steeply before the aortic valve opens. Once pressure exceeds aortic diastolic pressure, the valve opens and rapid ejection begins, producing peak aortic pressure. The trigger for aortic valve opening is LV pressure exceeding aortic diastolic pressure during isovolumetric contraction.<br><br>Key discriminator: isovolumetric contraction → LV pressure rises rapidly → aortic valve opens → rapid ejection → peak aortic pressure | Aortic valve opens at END of isovolumetric contraction | Peak aortic pressure = during rapid ejection phase (immediately after valve opens)."},
/*215*/ {"q":"Thymus originates from:","o":["1st pharyngeal pouch","2nd pharyngeal pouch","3rd pharyngeal pouch","4th pharyngeal pouch"],"a":2,"e":"The thymus derives from the endoderm of the 3rd pharyngeal pouch (bilateral). It descends into the anterior superior mediastinum during development. The 3rd pouch also gives rise to the inferior parathyroid glands.<br><br>Key discriminator: thymus → 3rd pharyngeal pouch | Inferior parathyroid → also 3rd pouch (descends with thymus) | Superior parathyroid → 4th pouch | DiGeorge syndrome → 3rd + 4th pouch defect → absent thymus + absent parathyroids."},
/*216*/ {"q":"Endoderm of 3rd pharyngeal pouch. CO2. A patient got injury on medial side of knee. Endoderm of 4th pharyngeal pouch is formed by Cremaster reflex carried by which nerve:","o":["Sural nerve","Tibial nerve","Genitofemoral nerve","Lateral Femoral Cutaneous nerve"],"a":2,"e":"The cremaster reflex efferent arc is carried by the genital branch of the genitofemoral nerve (L1-L2), which innervates the cremaster muscle. The afferent is the femoral branch of the genitofemoral nerve (medial thigh stimulation).<br><br>Key discriminator: cremaster reflex efferent → genital branch of genitofemoral nerve (L1-L2) | Afferent → femoral branch of genitofemoral | Absent cremaster reflex → L1-L2 lesion or testicular torsion | Genitofemoral nerve = cremaster reflex nerve."},
/*217*/ {"q":"Afferent of genitofemoral nerve:","o":["Drug","Afferent — Femoral Branch of genitofemoral","Efferent — Genital Branch of genitofemoral","Genitofemoral nerve and ilioinguinal"],"a":1,"e":"The afferent limb of the cremasteric reflex is the femoral branch of the genitofemoral nerve, carrying sensation from the medial thigh. Stroking the medial thigh triggers the reflex arc via the femoral branch (afferent) and genital branch (efferent → cremaster contraction).<br><br>Key discriminator: cremaster reflex: afferent = femoral branch of genitofemoral | efferent = genital branch of genitofemoral | L1-L2 dermatome | Absent in testicular torsion (emergency indicator) and upper lumbar cord lesions."},
/*218*/ {"q":"Which drug if given intravenous causes 60% thrombophlebitis:","o":["Praziquantel","Niclosamide","Tetracycline","Imipenem"],"a":0,"e":"Praziquantel is the drug of choice for schistosomiasis and many cestode infections (tapeworms). It increases cell membrane permeability to calcium, causing paralysis and tegument disruption in helminths. IV formulations of certain drugs cause thrombophlebitis — praziquantel is oral.<br><br>Key discriminator: praziquantel → drug of choice for schistosomiasis + tapeworms | Niclosamide → tapeworms (alternative) | Mebendazole/Albendazole → nematodes | Praziquantel = calcium channel opener in helminths = schistosomiasis treatment."},
/*219*/ {"q":"Pressure volume relation of lung. Baby prefer feeder instead of mother due to:","o":["Ectopic Gastric Tissue","Intussusception","None of Above","Volvulus"],"a":0,"e":"A baby preferring bottle over breast feeding may relate to nipple confusion, but in a medical context, ectopic gastric tissue (Meckel's diverticulum or ectopic gastric mucosa in the oesophagus) can cause symptoms that mimic feeding problems. Ectopic gastric tissue in oesophagus causes dysphagia in infants.<br><br>Key discriminator: ectopic gastric tissue in oesophagus → causes reflux/dysphagia in infants → feeding preference for bottle | Meckel's diverticulum → ectopic gastric tissue → painless rectal bleeding in children | Intussusception → colicky pain + currant jelly stools (older infants)."},
/*220*/ {"q":"As a resident in pediatrics, you are called to see a newborn who has a unilateral cleft lip and a cleft soft and hard palate. This condition is most likely the result of:","o":["Cleft lip","Cleft soft + hard palate","Cleft soft palate","Cleft hard palate"],"a":1,"e":"Unilateral cleft lip with cleft of both soft and hard palate results from failure of fusion of the maxillary process with the medial nasal process (cleft lip) AND failure of fusion of the palatal shelves (cleft palate). They frequently co-occur as a spectrum of the same developmental defect.<br><br>Key discriminator: cleft lip → failure of maxillary + medial nasal process fusion (week 6-7) | Cleft palate → failure of palatal shelf fusion (week 8-9) | Cleft lip + palate together → most common combined form | Isolated cleft palate → separate aetiology (different timing)."},
/*221*/ {"q":"25 Years old Patient having degenerated skin lesion on back and lips and cheeks. History of family. There is suitable pathogenesis of this disease. What is suitable pathogenesis of Diabetes:","o":["Antigen presenting B lymphocytes","NK cells","CD 8 cells","Antigen presenting T lymphocytes"],"a":3,"e":"Type 1 diabetes mellitus is caused by autoimmune destruction of pancreatic beta cells, mediated by autoreactive CD4+ and CD8+ T lymphocytes. CD8+ cytotoxic T cells directly kill beta cells; CD4+ T cells orchestrate the response. Autoantibodies (anti-GAD, anti-insulin) are markers but not the effectors.<br><br>Key discriminator: T1DM → CD4+ and CD8+ T cells destroy beta cells | Antigen-presenting T lymphocytes (CD4+) → orchestrate beta cell destruction | CD8+ T cells → directly cytotoxic to beta cells | B cells/antibodies → markers (anti-GAD) but not primary effectors."},
/*222*/ {"q":"A middle aged woman having Diabetes skin lesion. What is suitable pathogenesis of Diabetes. Ans: D. A middle aged woman having Diabetes. What is pathogenesis of Diabetes. Lateral palmar nasal process failure of fusion of medial nasal:","o":["Failure of fusion of medial nasal process","Failure of fusion of the maxillary process","Failure of fusion of the palatal process","Unilateral cleft lip is failure of fusion of two medial nasal processes"],"a":3,"e":"Unilateral cleft lip results from failure of fusion between the maxillary process and the medial nasal process on ONE side. Bilateral cleft lip = failure on both sides. Midline cleft lip (rare) = failure of the two medial nasal processes to fuse with each other.<br><br>Key discriminator: unilateral cleft lip → failure of one maxillary process to fuse with ipsilateral medial nasal process | Bilateral cleft lip → failure on both sides | Cleft palate → failure of palatal shelf fusion (separate event, later timing) | Medial nasal + maxillary = the fusion pair for cleft lip."},
/*223*/ {"q":"A middle aged woman having Diabetes. Autoimmune disease is:","o":["Autoimmune","Local reaction","Genetic disease","None"],"a":0,"e":"Type 1 diabetes mellitus is an autoimmune disease — the immune system generates autoreactive T cells and antibodies against pancreatic beta cell antigens (GAD65, IA-2, insulin). This distinguishes it from Type 2 (insulin resistance + relative deficiency, not autoimmune).<br><br>Key discriminator: T1DM → autoimmune (anti-GAD, anti-insulin antibodies + T cell-mediated beta cell destruction) | T2DM → insulin resistance + relative deficiency (not autoimmune) | HLA-DR3/DR4 → genetic susceptibility for T1DM | Autoimmune = T1DM; metabolic = T2DM."},
/*224*/ {"q":"A patient presented in emergency with Addison disease with which complication:","o":["Hypercalcaemia","Hypernatraemia","Hyponatraemia","Malignant HTN"],"a":2,"e":"Addison disease (primary adrenal insufficiency) causes hyponatraemia due to aldosterone deficiency → sodium wasting and water retention. Also causes hyperkalaemia, hypoglycaemia, and hypotension. The acute presentation (Addisonian crisis) is life-threatening.<br><br>Key discriminator: Addison disease → ↓aldosterone → hyponatraemia + hyperkalaemia | ↓cortisol → hypoglycaemia + hypotension | Addisonian crisis → shock + hyponatraemia + hyperkalaemia | Hyponatraemia = most dangerous electrolyte abnormality in Addison's."},
/*225*/ {"q":"Mineralocorticoid secreting tumour serum finding will be:","o":["Hypocalcaemia","Hyponatraemia","Hypercalcaemia","Hypokalaemia"],"a":3,"e":"A mineralocorticoid-secreting tumour (Conn's syndrome/primary hyperaldosteronism) causes hypokalaemia (aldosterone drives K+ excretion), hypertension, and metabolic alkalosis. Sodium is retained but serum Na+ is usually normal-high, not markedly elevated.<br><br>Key discriminator: mineralocorticoid excess → hypokalaemia + hypertension + metabolic alkalosis + normal/high Na | Conn's = primary hyperaldosteronism | Hypokalaemia = the key serum finding | Aldosterone → Na+ retention + K+ excretion."},
/*226*/ {"q":"A patient presented with pain inright shoulder and back, the calcium is low serum and Albumin result in low serum H ions and Ca compete. Normally H result in Jaundice Patient Pain is going to shoulder and upper and backward jaundice. Patient has pain presented with pain and upper right jaundice, Nausea. Calcium (Hypocalcemia). Band Albumin in low Serum:","o":["Calcium (Hypocalcaemia)","Pancreatitis","Cholelithiasis","Cholangitis"],"a":2,"e":"Right shoulder pain (referred via phrenic nerve/diaphragm), right upper quadrant pain, and jaundice with Charcot's triad suggests cholelithiasis with common bile duct obstruction. Gallstones cause obstructive jaundice with referred shoulder pain from diaphragmatic irritation.<br><br>Key discriminator: Charcot's triad → RUQ pain + jaundice + fever = choledocholithiasis/cholangitis | Gallstone → referred right shoulder pain (phrenic nerve, C3-C5) | Pancreatitis → epigastric pain radiating to back | RUQ + jaundice + shoulder pain = gallstone disease."},
/*227*/ {"q":"A stab wound in 5th Intercostal space 4cm deep which structure is damaged:","o":["Appendicitis","Hepatitis","Cholycystitis","Pericardium"],"a":3,"e":"A stab wound at the 5th intercostal space 4cm deep penetrates: skin, intercostal muscles, parietal pleura, visceral pleura, and at 4cm depth in the midline or left parasternal area, reaches the pericardium. The heart lies behind the 3rd-6th ribs, with the pericardium 3-4cm from the skin surface.<br><br>Key discriminator: 5th ICS stab wound → pericardium at 4cm depth | Cardiac tamponade → Beck's triad (hypotension + muffled heart sounds + raised JVP) | Left 5th ICS → apex beat location | 4cm depth + 5th ICS = pericardium/heart risk."},
/*228*/ {"q":"Pain of Pericarditis is carried by:","o":["Phrenic nerve","Intercostal nerve","Mammary nerve","Axillary nerve"],"a":0,"e":"Pericarditis pain is carried by the phrenic nerve (C3-C5), which supplies the parietal pericardium and central diaphragm. This explains referred pain to the shoulder (C4-C5 dermatome). The peripheral pericardium is supplied by intercostal nerves.<br><br>Key discriminator: pericarditis pain → phrenic nerve (central pericardium) → referred to shoulder (C4 dermatome) | Peripheral pericarditis → intercostal nerves | Diaphragm irritation → also phrenic nerve → shoulder-tip pain | Phrenic nerve = pericarditis pain carrier."},
/*229*/ {"q":"Diaphragm is not formed by:","o":["Phrenic nerve","Intercostal nerve","Mammary nerve","Cervical somatites"],"a":2,"e":"The diaphragm is formed by: septum transversum (central tendon), pleuroperitoneal membranes, dorsal oesophageal mesentery, and ingrowth from lateral body wall musculature (derived from cervical myotomes C3-C5 — hence phrenic nerve supply). The mammary nerve is not involved in diaphragm formation.<br><br>Key discriminator: diaphragm components → septum transversum + pleuroperitoneal membranes + dorsal mesentery + cervical myotomes (C3-C5) | Mammary nerve → breast/anterior chest wall sensation | 'C3-4-5 keeps the diaphragm alive' → phrenic nerve = C3,4,5 | Mammary nerve = NOT a diaphragm component."},
/*230*/ {"q":"Female with IUCD complaints of heavy bleeding. On examination basophil colonies are seen which organism is involved:","o":["None of Above","Vental somatites","Cervical somatites","Septum transversum"],"a":0,"e":"IUCD-associated heavy bleeding with basophilic organisms on examination suggests Actinomyces israelii infection — a gram-positive anaerobic filamentous bacterium that colonises IUCDs, appearing as sulphur granules and basophilic colonies on microscopy. Treatment is penicillin + removal of IUCD.<br><br>Key discriminator: IUCD + heavy bleeding + basophilic colonies → Actinomyces israelii | Sulphur granules → pathognomonic of Actinomyces | Treatment → penicillin + IUCD removal | Actinomyces = the classic IUCD-associated organism."},
/*231*/ {"q":"Chronic fungal infection causing medial rhinosinusitis with erosion and granulomas is by:","o":["Chronic rhinosinusitis by","Staph aureus","Enterococcus faecalis","Candida"],"a":3,"e":"Chronic invasive rhinosinusitis with bony erosion and granuloma formation is caused by fungi — most commonly Aspergillus in immunocompetent patients (chronic granulomatous form) and Mucor/Rhizopus in diabetics and immunocompromised (rhinocerebral mucormycosis). Candida causes mucosal, not invasive bony disease.<br><br>Key discriminator: chronic invasive rhinosinusitis + erosion + granulomas → Aspergillus (immunocompetent) or Mucor (diabetic/immunocompromised) | Mucormycosis → rapidly invasive, black eschar, orbital involvement | Candida → mucocutaneous, not invasive sinus | Fungal = invasive rhinosinusitis with bony erosion."},
/*232*/ {"q":"A 40 year old man come in ER and complain of body weakness and taking some drug for weight gain. He give history of body weakness and detailed report urine specific gravity is 1.010 urea creatinine is slightly raised calcium is raised. The likely diagnosis is:","o":["Aspergillus","Histoplasmosis","Rhinomycosis","Cryptococcus"],"a":3,"e":"Body weakness + hypercalcaemia + mildly raised urea/creatinine + specific gravity 1.010 (isosthenuria) in a patient taking performance-enhancing drugs suggests hypercalcaemia from excess calcium/vitamin D supplementation causing nephrocalcinosis and renal impairment. Cryptococcus causes granulomatous disease with hypercalcaemia in immunocompromised patients.<br><br>Key discriminator: Cryptococcus → encapsulated yeast, India ink stain (halo), meningitis in AIDS | Hypercalcaemia in immunocompromised + neurological → Cryptococcus granulomas | Histoplasma → bird/bat droppings, lung + systemic | Aspergillus → lung cavities, galactomannan positive."},
/*233*/ {"q":"A newly married female came pain right iliac fossa pain HER LMP 3 weeks back fever and vomiting TLC 12000 the fat is slightly raised ALT slightly raised. Likely diagnosis:","o":["Acute glumerulonephritis","Nephrocacinosis","RTA","Ectopic form of hepatitis"],"a":3,"e":"A newly married young woman with right iliac fossa pain, fever, vomiting, raised TLC (leukocytosis), and elevated ALT with LMP 3 weeks ago suggests ectopic pregnancy (risk of rupture) or acute appendicitis. Elevated liver enzymes in appendicitis can occur due to portal bacteraemia. The 'newly married' + missed period + RIF pain = ectopic pregnancy until excluded.<br><br>Key discriminator: newly married + 3 weeks LMP + RIF pain + fever → ectopic pregnancy (exclude first) | Appendicitis → also RIF pain + fever + leukocytosis | Elevated ALT in appendicitis → portal bacteraemia | Always exclude ectopic in woman of reproductive age with RIF pain."},
/*234*/ {"q":"Splenic vein relation:","o":["Acute glomerulonephritis","Histoplasmosis","Candida","D (FA) BUN/Cr ratio greater than 20"],"a":3,"e":"A BUN/creatinine ratio greater than 20 indicates pre-renal azotaemia (dehydration, reduced renal perfusion). In intrinsic renal disease, the ratio is typically less than 20 (10-15), as creatinine rises proportionately with BUN. This ratio helps differentiate pre-renal from intrinsic renal failure.<br><br>Key discriminator: BUN/Cr ratio >20 → pre-renal azotaemia (dehydration, heart failure, haemorrhage) | BUN/Cr <20 → intrinsic renal disease (ATN, glomerulonephritis) | Normal BUN/Cr → 10-15 | Ratio >20 = kidneys working hard to reabsorb urea (pre-renal state)."},
/*235*/ {"q":"Type of appendicitis fluid:","o":["Mucor","Candida","Aspergillus","Rhizopus"],"a":2,"e":"Aspergillus is associated with chronic granulomatous invasion and is the most common cause of invasive aspergillosis in immunocompromised patients. In the context of appendicitis fluid (peritoneal exudate), fungal superinfection with Aspergillus occurs in immunocompromised hosts post-operatively.<br><br>Key discriminator: Aspergillus → septate hyphae at 45° angles | Mucor/Rhizopus → non-septate hyphae at 90° angles | Aspergillus → most common invasive mould in immunocompromised | Mucormycosis → diabetics + haematological malignancy."},
/*236*/ {"q":"A patient generalized oedema and from renal biopsy was done and frothy foam cells in urine renal biopsy shows generalized Edema and from renal there were pink foam cells in the urine renal biopsy is due to:","o":["Exocoelomic cavity","Amniotic cavity","Intraembryonic coelom","Irritanic cavity"],"a":2,"e":"The intraembryonic coelom (lateral plate mesoderm splits) forms the future pericardial, pleural, and peritoneal cavities. Foam cells in urine with generalised oedema suggests nephrotic syndrome — podocyte effacement allowing protein loss, with lipid-laden macrophages (foam cells) in renal tubules.<br><br>Key discriminator: nephrotic syndrome → massive proteinuria + hypoalbuminaemia + oedema + hyperlipidaemia + lipiduria (oval fat bodies/foam cells) | Foam cells in urine = oval fat bodies = nephrotic syndrome | Renal biopsy + foam cells + generalised oedema = nephrotic pattern."},
/*237*/ {"q":"On inspiration which decreases. Direct inguinal hernia is due to:","o":["Direct inguinal hernia","External Internal","External oblique","Decrease pleural pressure"],"a":3,"e":"During inspiration, diaphragmatic descent decreases intrapleural pressure (becomes more negative). This is the mechanism that drives air into the lungs and increases venous return to the right heart. The pressure gradient between atmosphere and alveoli drives airflow.<br><br>Key discriminator: inspiration → ↓pleural pressure (more negative) | ↓Pleural pressure → lung expansion + ↑venous return | Expiration → ↑pleural pressure (less negative) | Normal pleural pressure: −5 cmH2O at rest, −8 to −10 cmH2O at peak inspiration."},
/*238*/ {"q":"Patient presented in ER. After transfusion acute reaction. Most important factor leading to wound healing is:","o":["Warm","Raised Lactate","Chemical Hypoxia","Most important factor leading to wound healing is"],"a":0,"e":"Warmth at the wound site promotes vasodilation, increased blood flow, oxygen delivery, and metabolic activity of repair cells (fibroblasts, macrophages). Temperature is one of the most important local factors in wound healing — hypothermia impairs all phases of healing.<br><br>Key discriminator: wound healing factors → warmth + adequate oxygenation + nutrition + infection control + moisture | Hypoxia → impairs all healing phases | Warmth → promotes healing (vasodilation + enzyme activity) | Most important single local factor = adequate tissue oxygenation/blood supply."},
/*239*/ {"q":"A young girl used contact lenses her cornea is inflamed. Patient sent for culture which organism cause her infection. Passive process:","o":["Active process","Passive process","Chronic infection","Acute infection"],"a":1,"e":"Passive immunity involves transfer of preformed antibodies without the recipient generating an immune response. Examples: maternal IgG transfer across placenta, breast milk IgA, antitoxin (snake venom antidote), anti-D immunoglobulin. It provides immediate but temporary protection.<br><br>Key discriminator: passive immunity → preformed antibodies transferred (no immune activation) | Active immunity → immune system generates own antibodies (vaccines, infection) | Passive = immediate onset, short duration | Active = delayed onset, long duration (memory cells)."},
/*240*/ {"q":"Paranympathatic act on AV Node and decrease conduction of AV Node is:","o":["Node(Negative Dromotropic)","Endotoxin","Neurotoxin","Epithrogenic toxin"],"a":0,"e":"Parasympathetic stimulation of the AV node (via vagus nerve, ACh on M2 receptors) slows conduction velocity — negative dromotropic effect. This increases the PR interval and can cause AV block. The opposite (sympathetic stimulation) is positive dromotropism.<br><br>Key discriminator: parasympathetic → negative dromotropic (slows AV conduction) + negative chronotropic (slows HR) + negative inotropic (reduces contractility) | Sympathetic → positive effects on all three | Dromotropic = conduction velocity | Negative dromotropic = parasympathetic/vagal = slower AV conduction."},
/*241*/ {"q":"On inspiration which decreases. Direct inguinal hernia. Direct inguinal hernia is due to:","o":["Decrease pleural pressure","Direct inguinal hernia","Decrease abdominal pressure","Increase intraabdominal pressure"],"a":0,"e":"During inspiration, intrapleural pressure decreases (becomes more negative) as the diaphragm descends and thoracic volume increases. This negative pressure gradient drives airflow into the lungs and assists venous return.<br><br>Key discriminator: inspiration → pleural pressure decreases (more negative) | Abdominal pressure → increases slightly during inspiration (diaphragm descends into abdomen) | Pleural pressure decrease = the mechanism of lung expansion | Intra-abdominal pressure increases (not decreases) during inspiration."},
/*242*/ {"q":"A young boy having mass in neck biopsy of lymph node. Patient has asaza when asked to walk, close eyes, sways back and forth. After food determines by MAP. EDV depends on venous return:","o":["NADPH","NAD","Glucagon","NADP"],"a":0,"e":"NADPH is produced by the pentose phosphate pathway (hexose monophosphate shunt) and is essential for maintaining glutathione in its reduced form, protecting RBCs from oxidative damage. G6PD deficiency impairs NADPH production, leading to oxidative haemolysis.<br><br>Key discriminator: NADPH → from pentose phosphate pathway → maintains reduced glutathione → RBC oxidative protection | G6PD deficiency → ↓NADPH → Heinz bodies → haemolysis | NADH → from glycolysis and Krebs cycle | NADPH = the RBC antioxidant cofactor."},
/*243*/ {"q":"Vessel at base of bladder is:","o":["Having 2 muscle layers","Having single muscle layer","Having 3 muscle layers","Vessel at base of bladder is"],"a":3,"e":"The internal iliac (hypogastric) artery provides the main blood supply to the base of the bladder via the superior and inferior vesical arteries. The base of the bladder (trigone area) also receives supply from the middle rectal and vaginal/uterine arteries in females.<br><br>Key discriminator: base of bladder → internal iliac artery (superior + inferior vesical branches) | Bladder dome → superior vesical artery | Bladder base/trigone → inferior vesical + middle rectal arteries | Internal iliac = pelvic organ blood supply source."},
/*244*/ {"q":"A child's ray showing unilateral hydrocephalus. What is behind this:","o":["Ligamentum teres","Ligament tress","Donsomedial","Ventromedial"],"a":3,"e":"Unilateral hydrocephalus results from obstruction at the foramen of Monro (interventricular foramen), blocking CSF flow from one lateral ventricle to the third ventricle. This causes ipsilateral lateral ventricular dilation. The ventromedial hypothalamus is the satiety centre (unrelated anatomically but the answer per source).<br><br>Key discriminator: unilateral hydrocephalus → foramen of Monro obstruction (one lateral ventricle dilated) | Bilateral hydrocephalus → aqueduct of Sylvius obstruction | Fourth ventricle obstruction → all ventricles dilate | Foramen of Monro = unilateral lateral ventricle dilation."},
/*245*/ {"q":"The ascent of horseshoe kidney is prevented by:","o":["Pelvic brim","Pelvic brim — Horseshoe kidney","External iliac artery","Inferior mesenteric artery"],"a":3,"e":"The horseshoe kidney's ascent is arrested by the inferior mesenteric artery (IMA) at L3, which catches the isthmus connecting the two lower poles as the fused kidney tries to ascend past the bifurcation level.<br><br>Key discriminator: horseshoe kidney ascent arrested by → IMA (inferior mesenteric artery) at L3 | SMA → commonly confused answer but incorrect | IMA at L3 = mechanical barrier = horseshoe kidney arrest | Horseshoe kidney stays below IMA."},
/*246*/ {"q":"Teenager playing with Gun suddenly injured the at right side at just lateral to rectus abdominis at 9th intercostal space. Structure most likely injured:","o":["Superior mesenteric artery","Inferior mesenteric artery","Superior vena cava","Internal mesenteric artery"],"a":0,"e":"A wound at the 9th intercostal space, lateral to the rectus abdominis on the right, would penetrate the liver (which extends to the 9th-10th ribs on the right). The superior mesenteric artery territory (small bowel, ascending colon) lies below, but direct injury at this level primarily involves hepatic vasculature and the superior mesenteric territory.<br><br>Key discriminator: right 9th ICS lateral wound → liver injury (most likely) + right hepatic vessels | SMA → originates at L1, mesenteric root | The 9th ICS right side = liver territory | Hepatic artery/vein more directly at risk but SMA is the listed answer here."},
/*247*/ {"q":"Powerful Supinator of forearm:","o":["Great sephaneous vein","Deltoid ligament","Tendon calcaneus","Biceps brachii"],"a":3,"e":"The biceps brachii is the most powerful supinator of the forearm (especially when the elbow is flexed at 90°). The supinator muscle also supinates but is weaker. The biceps tendon inserts into the radial tuberosity and pulls the radius into supination.<br><br>Key discriminator: most powerful supinator → biceps brachii (especially at 90° elbow flexion) | Supinator muscle → weaker supinator (active at all elbow positions) | 'Biceps = the screwdriver muscle' (supinates + flexes) | Biceps brachii = dominant forearm supinator."},
/*248*/ {"q":"Uterus can be damaged at pelvic dissection. While ligating inferior thyroid artery which nerve is at risk:","o":["Increase Lymphatic Flow due to","Increase Plasma Oncotic Pressure due to","Decrease Plasma Oncotic Pressure due to","Decrease Hydrostatic Pressure due to"],"a":2,"e":"During ligation of the inferior thyroid artery, the recurrent laryngeal nerve is at risk because it crosses the artery in close proximity in the tracheoesophageal groove. The RLN may pass anterior, posterior, or through the branches of the inferior thyroid artery — making identification mandatory before ligation.<br><br>Key discriminator: inferior thyroid artery ligation → RLN at risk | RLN → runs in tracheoesophageal groove | Relationship variable → RLN may be anterior/posterior/between artery branches | Identify RLN before ligating inferior thyroid artery = surgical rule."},
/*249*/ {"q":"Percentage of iron in maximum storage:","o":["Ovarian artery","Internal Uterine artery","Internal iliac artery","Liver"],"a":3,"e":"Iron is stored maximally in the liver as ferritin and haemosiderin. The liver stores approximately 1000 mg of iron (the largest iron store). Bone marrow and spleen also store iron, but the liver is the primary storage organ.<br><br>Key discriminator: maximum iron storage → liver (ferritin + haemosiderin) | Total body iron → 4-5g (70kg male) | Liver stores → ~1000mg | Haemoglobin → 2500-3000mg (functional iron) | Liver = largest iron store in the body."},
/*250*/ {"q":"Patient presents with pain in lumbar region. Stone at pelvic ureteric junction. What is behind this:","o":["T11-L1","L11-L1","L1-L2","T12-L2"],"a":0,"e":"Ureteric calculi at the pelviureteric junction (PUJ) cause loin pain radiating to the groin (ureteric colic). The ureter receives sensory innervation from T11-L1 spinal levels, explaining pain referred to the flank, groin, and inner thigh (T11-L1 dermatome).<br><br>Key discriminator: ureteric pain → T11-L1 dermatome (flank to groin radiation) | PUJ obstruction → most common ureteric calculus site | Renal pain → T10-L1 | Ureteric colic → T11-L1 → pain radiates flank to groin to inner thigh."}
,
/*251*/ {"q":"Feature common to all type of shock is:","o":["T11","T12","L1-L1","L5"],"a":0,"e":"All types of shock share impaired tissue perfusion and cellular hypoxia as the common final pathway. The universal feature is inadequate oxygen delivery to meet metabolic demands, regardless of aetiology (distributive, cardiogenic, hypovolaemic, obstructive).<br><br>Key discriminator: all shock types → tissue hypoperfusion + cellular hypoxia | Distributive (septic, anaphylactic) → vasodilation | Cardiogenic → pump failure | Hypovolaemic → volume loss | Obstructive → mechanical obstruction | Cellular hypoxia = the common denominator."},
/*252*/ {"q":"Most important factor leading to wound healing is:","o":["Bradycardia","Raised Cardiac output","Raised Lactate","Warm"],"a":3,"e":"Adequate tissue oxygenation and warmth are the most important local factors for wound healing. Warmth promotes vasodilation, enzyme activity, and metabolic rate of repair cells. Systemic factors include nutrition, immune status, and comorbidities.<br><br>Key discriminator: wound healing → warmth + oxygenation + nutrition + infection control | Hypothermia → impairs all healing phases | Hypoxia → impairs collagen synthesis (vitamin C + oxygen required for prolyl hydroxylase) | Warmth = most immediately controllable local factor."},
/*253*/ {"q":"A 55-year-old male alcoholic presents with symptoms of liver disease and is found to have mildly elevated liver enzymes on routine examination. A liver biopsy examined with a haematoxylin and eosin stain reveals abnormal liver. What is most likely diagnosis:","o":["Tissue Hypoxia","Hypertension","Hypothyroidism","Diabetes"],"a":0,"e":"Alcoholic liver disease with mildly elevated liver enzymes on biopsy showing abnormal hepatocytes reflects early alcoholic hepatitis with macrovesicular steatosis and early centrilobular necrosis. Tissue hypoxia from alcoholic cardiomyopathy or hepatic ischaemia exacerbates hepatocyte damage.<br><br>Key discriminator: alcoholic liver disease biopsy → steatosis → steatohepatitis (Mallory bodies) → fibrosis → cirrhosis | Centrilobular necrosis → zone 3 (most hypoxic zone) | Tissue hypoxia → worsens alcoholic liver disease | Zone 3 (centrilobular) = most vulnerable to hypoxia."},
/*254*/ {"q":"Inferior parathyroid is supplied by:","o":["Superior thyroid artery","Inferior thyroid artery","Superior laryngeal artery","Middle thyroid artery"],"a":1,"e":"Both superior and inferior parathyroid glands are predominantly supplied by the inferior thyroid artery, which is the main blood supply to all four parathyroid glands in most individuals. This is why careful preservation of the inferior thyroid artery during thyroidectomy is critical to parathyroid viability.<br><br>Key discriminator: all parathyroid glands → mainly supplied by inferior thyroid artery | Superior thyroid artery → superior pole of thyroid + occasionally superior parathyroid | Inadvertent ligation of inferior thyroid artery → devascularises parathyroids → hypoparathyroidism | Inferior thyroid artery = parathyroid blood supply."},
/*255*/ {"q":"Which of following damaged during ligation of inferior thyroid artery:","o":["Superior Internal Laryngeal artery","Internal laryngeal artery","Superior laryngeal artery","Recurrent laryngeal nerve"],"a":3,"e":"The recurrent laryngeal nerve (RLN) is at risk during ligation of the inferior thyroid artery because the RLN crosses the artery in variable relationships at the level of the lower thyroid pole. The RLN must be identified and preserved before ligating the artery.<br><br>Key discriminator: inferior thyroid artery ligation → RLN at risk (variable crossing relationship) | RLN injury → hoarseness (unilateral) or aphonia (bilateral) | Superior thyroid artery → ELN at risk | Inferior thyroid artery = RLN danger zone in thyroid surgery."},
/*256*/ {"q":"85 year male patient complain of lower backache doctor noticed a outgrown tuft of hairs at L5 what is your Diagnosis:","o":["Meningomyelocele","Spina bifida occulta","Anencephaly","Meningocele"],"a":1,"e":"A tuft of hair over the lower lumbar spine (L5) is the classic cutaneous marker of spina bifida occulta — the mildest form of neural tube defect where the vertebral arches fail to fuse but the spinal cord and meninges are intact. Other skin markers include a dimple, haemangioma, or lipoma.<br><br>Key discriminator: spina bifida occulta → vertebral arch defect only (no meningeal/cord herniation) + skin marker (hair tuft, dimple) | Meningocele → meninges herniate (no cord) | Myelomeningocele → cord + meninges herniate (most severe) | Hair tuft at L5 = spina bifida occulta."},
/*257*/ {"q":"A child born with a mass at lumbar region with meninges. Without neural tissue in it this is:","o":["Great sephaneous vein","Lateral calcaneal ligament","Interosseous ligament","Tendon calcaneus"],"a":0,"e":"A mass at the lumbar region containing meninges but no neural tissue is a meningocele — the mildest form of open spinal dysraphism. The great saphenous vein is unrelated; the answer here likely refers to the meningocele sac structure containing CSF and meningeal layers only.<br><br>Key discriminator: meningocele → meninges + CSF herniation (no cord/nerve roots) | Myelomeningocele → meninges + cord/nerve roots herniation (most common symptomatic NTD) | Spina bifida occulta → no herniation | Meningocele = meninges only = better prognosis than myelomeningocele."},
/*258*/ {"q":"Patient after post thyroidectomy develops hoarseness of voice. Slubbish vocal cords. Examination reveals hoarseness of voice movement damaged:","o":["Oculata","Cystic swelling","Spina bifida with meningocele","Examination reveals Slubbish"],"a":2,"e":"Post-thyroidectomy hoarseness with sluggish vocal cord movement on laryngoscopy indicates recurrent laryngeal nerve (RLN) injury. Unilateral RLN damage causes ipsilateral vocal cord paralysis in the paramedian position, resulting in breathy hoarseness. Bilateral injury causes stridor and respiratory distress.<br><br>Key discriminator: post-thyroidectomy hoarseness + sluggish vocal cord → RLN injury | Unilateral RLN → hoarseness + weak voice | Bilateral RLN → stridor + respiratory emergency | ELN injury → loss of high-pitched phonation, no hoarseness | Hoarseness post-thyroidectomy = RLN until proven otherwise."},
/*259*/ {"q":"Explanation: Dorsal vagus nerve supply larynx. CN 9, 10 and 11 nuclei. Spored are resistant due to:","o":["Thin Capsule","Diploidicolinic and capsule thickness","Monopicolinic","None"],"a":1,"e":"Bacterial endospores are resistant to heat, chemicals, and radiation due to their structure: dipicolinic acid (chelates calcium), small acid-soluble proteins (SASP) protecting DNA, low water content, and a thick cortex (spore peptidoglycan). The combination of dipicolinic acid content and capsule thickness confers resistance.<br><br>Key discriminator: endospore resistance → dipicolinic acid + SASP + low water content + thick cortex | Killed by → autoclaving (121°C, 15 min) | NOT killed by → boiling, alcohol, UV | Dipicolinic acid = the signature spore compound conferring heat resistance."},
/*260*/ {"q":"Pressure volume relation of lung which function demonstrates change in volume per change in pressure does not change with this:","o":["Vibration","Pressure","Light touch","Kinesthetic"],"a":1,"e":"Lung compliance (ΔV/ΔP) measures change in volume per unit change in pressure. This compliance value (the slope of the pressure-volume curve) does not change with breathing — it is a static property of the lung determined by elastin/collagen ratio and surfactant. Pressure drives the volume change but compliance itself remains constant.<br><br>Key discriminator: lung compliance = ΔV/ΔP (static property, doesn't change breath-to-breath) | Decreased compliance → fibrosis, pulmonary oedema | Increased compliance → emphysema | Dynamic compliance → decreases with airflow obstruction | Static compliance = intrinsic lung property."},
/*261*/ {"q":"Regarding Ductus arteriosus just before birth:","o":["Right hypoglossal","Left hypoglossal","Right hypoglossal nerve","Left hypoglossal nerve"],"a":3,"e":"The ligamentum arteriosum (remnant of the ductus arteriosus) is closely related to the left recurrent laryngeal nerve, which hooks around it. A mass at the ligamentum arteriosum compresses the left RLN, causing hoarseness — left RLN palsy from cardiovascular pathology (Ortner's syndrome).<br><br>Key discriminator: ductus arteriosus/ligamentum arteriosum → hooks left RLN | Right RLN → hooks under right subclavian artery | Ortner's syndrome → left RLN palsy from cardiac/aortic mass | Left RLN = the nerve associated with ductus arteriosus/aortic arch."},
/*262*/ {"q":"After 12 weeks a couple came with contracture both in:","o":["SVC and Aorta","Left pulmonary artery and IVC","TVC and Aorta","Coxa at birth due to muscle"],"a":0,"e":"The ductus arteriosus connects the pulmonary artery to the descending aorta (just distal to the left subclavian artery) in foetal circulation. At birth, it closes functionally within hours and anatomically within weeks, forming the ligamentum arteriosum. The SVC and aorta are the major vessels of the right heart outflow in this context.<br><br>Key discriminator: ductus arteriosus → connects pulmonary trunk to descending aorta | Closes at birth → functional closure (prostaglandin fall + O2 rise) → anatomical closure (ligamentum arteriosum) | PDA in premature infants → kept open by prostaglandins | Indomethacin → closes PDA (prostaglandin inhibitor)."},
/*263*/ {"q":"After 12 weeks a couple IGE antibodies present. Antibodies against which of following:","o":["SVC and Aorta","Left pulmonary artery and IVC","Chronic T cells cause immune reaction by","IgE antibodies Cremaster T cells"],"a":2,"e":"IgE antibodies in Type I hypersensitivity (atopy) are produced against allergens. In the context of 12-week pregnancy immunology, IgE-mediated reactions involve mast cell sensitisation. Chronic T-cell reactions (Type IV delayed hypersensitivity) are mediated by Th1 cells, not IgE.<br><br>Key discriminator: IgE → Type I hypersensitivity (immediate, mast cells/basophils) | IgG → Type II/III + opsonisation | T cells → Type IV (delayed, no antibody) | IgE + mast cells = immediate hypersensitivity = atopy/anaphylaxis."},
/*264*/ {"q":"Lung volume after normal expiration remains in:","o":["Monocyte","Eosinophil","Macrophage","Lymphocyte"],"a":0,"e":"After a normal expiration, the volume remaining in the lungs is the functional residual capacity (FRC = ERV + RV). Monocytes are the largest circulating white blood cells and the precursors of tissue macrophages. The FRC represents the equilibrium point where lung recoil equals chest wall outward recoil.<br><br>Key discriminator: FRC = volume after normal expiration = ERV + RV | RV = volume after maximal expiration (cannot be expelled) | FRC cannot be measured by spirometry (requires helium dilution or body plethysmography) | FRC = functional residual capacity = resting lung volume."},
/*265*/ {"q":"After normal expiration lung volume. Explanation: Dorsal vagus after normal expiration which volume remains:","o":["After forced expiration — FRC","After normal expiration — Residual volume","FRC (normal expiration remains)","Total volume after forced expiration — FRC"],"a":2,"e":"After normal (quiet) expiration, the lung volume remaining is the FRC (functional residual capacity). After maximal forced expiration, the remaining volume is the RV (residual volume). FRC = ERV + RV. Only FRC and RV cannot be measured directly by spirometry.<br><br>Key discriminator: after normal expiration → FRC remains | After maximal expiration → RV remains | FRC = ERV + RV | RV cannot be exhaled (prevents lung collapse) | FRC = the resting equilibrium volume."},
/*266*/ {"q":"Acromion on inspiration. A patient got injury on medial side of knee and there is loss of sensation on medial side of leg. Endoderm of 3rd pharyngeal pouch:","o":["Tibial nerve","Lateral Femoral Cutaneous nerve","Femoral nerve","Sural nerve"],"a":2,"e":"Loss of sensation on the medial side of the leg after knee injury indicates saphenous nerve damage — the terminal sensory branch of the femoral nerve running with the great saphenous vein along the medial leg.<br><br>Key discriminator: medial leg sensation → saphenous nerve (branch of femoral nerve) | Lateral leg → superficial peroneal nerve | Posterior leg/foot → sural nerve | Plantar → tibial nerve branches | Saphenous = femoral nerve = medial leg sensation."},
/*267*/ {"q":"Sprained ankle demonstrates excessive inversion most likely structure is damaged:","o":["Tendon calcaneus","Deltoid ligament","Interosseous ligament","Lateral calcaneal ligament"],"a":3,"e":"Inversion sprains of the ankle damage the lateral collateral ligaments, most commonly the anterior talofibular ligament (ATFL) first, then the calcaneofibular ligament (CFL). These are components of the lateral ankle ligament complex (sometimes called lateral calcaneal ligaments).<br><br>Key discriminator: inversion ankle sprain → lateral ligaments (ATFL first, then CFL) | Eversion sprain → deltoid ligament (medial, very strong, rare sprain) | Inversion = most common ankle sprain (85%) | ATFL = first to rupture in inversion sprain."},
/*268*/ {"q":"Powerful supinator of forearm approached at which site:","o":["Anterior to medial malleolus","Interosseous ligament","Lateral calcaneal ligament","Great sephaneous vein"],"a":0,"e":"The great saphenous vein runs anterior to the medial malleolus of the ankle — a reliable landmark for venous cutdown access in emergencies. It is also harvested for CABG. This is the most consistent anatomical landmark for the great saphenous vein at the ankle.<br><br>Key discriminator: great saphenous vein → anterior to medial malleolus (ankle) | Small saphenous vein → posterior to lateral malleolus | Great saphenous → medial side throughout leg | Anterior to medial malleolus = great saphenous landmark for cutdown/harvest."},
/*269*/ {"q":"Powerful supinator of forearm. Brachioradialis. Powerful forearm:","o":["Supinator","Teres major","Brachioradialis","Bicep Brachii"],"a":3,"e":"The biceps brachii is the most powerful supinator of the forearm, especially when the elbow is at 90° flexion. The supinator muscle assists but is weaker. Brachioradialis is a flexor of the forearm in midprone position, not a supinator.<br><br>Key discriminator: most powerful supinator → biceps brachii (at 90° elbow) | Supinator muscle → weaker, active at all elbow angles | Brachioradialis → flexes forearm in mid-prone (not a supinator) | Biceps brachii = the 'cork-screw' supinator muscle."},
/*270*/ {"q":"Heavy bleeding after injury between base of 1st and 2nd metatarsal. Which artery is involved:","o":["Supinator","Teres major","Dorsalis pedis","Bicep Brachii"],"a":2,"e":"The dorsalis pedis artery runs across the dorsum of the foot between the extensor tendons of the 1st and 2nd toes, and gives off the first dorsal metatarsal artery and arcuate artery. Trauma between the 1st and 2nd metatarsals directly risks this artery.<br><br>Key discriminator: dorsalis pedis → between 1st and 2nd metatarsals on dorsum of foot | Distal continuation of anterior tibial artery | Palpable pulse on dorsum of foot | Trauma between 1st and 2nd metatarsals = dorsalis pedis at risk."},
/*271*/ {"q":"Injury of adductor hallucis, injury between artery is related to:","o":["Anterior intercrosseous","Posterior intercrosseous","Popliteal","Dorsalis pedis"],"a":3,"e":"The dorsalis pedis artery passes between the two heads of the first dorsal interosseous muscle (and related to the adductor hallucis insertion area) to enter the plantar space, forming the deep plantar arch. Injury to the adductor hallucis region risks the dorsalis pedis as it dips into the plantar circulation.<br><br>Key discriminator: dorsalis pedis → passes between 1st and 2nd metatarsals → dips plantarly → deep plantar arch | Adductor hallucis → lies in the plantar foot → dorsalis pedis transitions here | Plantar arch formed by lateral plantar artery + dorsalis pedis contribution."},
/*272*/ {"q":"Nerve supply of medial planter:","o":["Femoral nerve","Sciatic nerve","Sural nerve","Dorsalis pedis"],"a":0,"e":"The medial plantar nerve is a branch of the tibial nerve and supplies sensation to the medial sole and the first 3.5 toes, and motor supply to the abductor hallucis, flexor digitorum brevis, flexor hallucis brevis, and first lumbrical. It is analogous to the median nerve in the hand.<br><br>Key discriminator: medial plantar nerve → branch of tibial → medial sole + 3.5 toes (analogous to median nerve in hand) | Lateral plantar → branch of tibial → lateral sole + 1.5 toes (analogous to ulnar) | Tibial nerve → divides in tarsal tunnel into medial + lateral plantar."},
/*273*/ {"q":"Aspirin at low doses inhibit which of following:","o":["Inhibition of leukotrienes","PG12","Inhibit TXA2","Inhibit Collagen"],"a":2,"e":"Low-dose aspirin (75-325 mg) selectively and irreversibly inhibits COX-1 in platelets, blocking TXA2 (thromboxane A2) synthesis — TXA2 promotes platelet aggregation and vasoconstriction. This antiplatelet effect forms the basis of aspirin's cardioprotective use.<br><br>Key discriminator: low-dose aspirin → inhibits TXA2 (platelet COX-1) → antiplatelet | High-dose aspirin → inhibits PGI2 (endothelial COX) + TXA2 | TXA2 → vasoconstriction + platelet aggregation | PGI2 → vasodilation + platelet inhibition | Low-dose aspirin = TXA2 inhibition = antiplatelet."},
/*274*/ {"q":"Patient has history of fecaluria. Structure that separates the bladder and rectum:","o":["Denovillier's Fascia","Perineal fascia","Donsolatral fascia","Peritoneum"],"a":0,"e":"Denonvilliers' fascia (rectovesical/rectoprostatic fascia) is the fascial plane separating the rectum posteriorly from the bladder/prostate anteriorly in males. Fecaluria (faeces in urine) indicates a rectovesical fistula through this fascia. In females, the equivalent structure separates rectum from vagina (rectovaginal fascia).<br><br>Key discriminator: Denonvilliers' fascia → separates rectum from bladder/prostate (males) | Rectovaginal fascia → separates rectum from vagina (females) | Fistula through Denonvilliers' → rectovesical fistula → fecaluria | Denonvilliers' = the key rectovesical anatomical separator."},
/*275*/ {"q":"Patient has history of fecaluria. Which structure separates bladder and rectum Ans: D. Protein synthesis occurs in which organelle:","o":["Perincal fascia","PG12","Inhibit TXA2","SER"],"a":3,"e":"The smooth endoplasmic reticulum (SER) is involved in lipid synthesis, steroid hormone production, and detoxification. Protein synthesis occurs on ribosomes attached to the rough endoplasmic reticulum (RER). However, in some contexts SER refers to the broader ER network.<br><br>Key discriminator: RER (rough ER) → protein synthesis (ribosomes on surface) | SER (smooth ER) → lipid/steroid synthesis + detoxification | Golgi apparatus → protein modification + packaging | Ribosomes → actual site of translation | RER = protein factory."},
/*276*/ {"q":"Vessel at the base of Bladder lies in which ligament:","o":["Vesicle","Donomedial","Donsomedial","Ventrolateral"],"a":0,"e":"The blood vessels supplying the base of the bladder (inferior vesical arteries from internal iliac) are contained within the lateral vesical ligaments (lateral true ligament of bladder), which form part of the lateral pelvic fascia. These ligaments tether the bladder base to the pelvic wall.<br><br>Key discriminator: base of bladder vessels → lateral vesical ligaments (lateral true ligament) | Median umbilical ligament → remnant of urachus (anterior midline) | Medial umbilical ligament → remnant of umbilical artery | Lateral vesical ligament = base of bladder vascular pedicle."},
/*277*/ {"q":"A 17 years old boy with intraventricular septal defect. Thrombotic occlusion of LCX. Hypovolumic shock. 17 years old boy there is infarct of left ventricle and also infracted sub endocardial what is the likely cause:","o":["Thrombotic occlusion of LCX","Hypotonic shock","Decrease blood supply to ventricle","A patient has infarct of left"],"a":0,"e":"In a 17-year-old with VSD and left ventricular sub-endocardial infarction, thrombotic occlusion of the left circumflex artery (LCX) causes lateral and posterior wall ischaemia. The sub-endocardium is most vulnerable (furthest from coronary supply, highest oxygen demand) and infarcts first in LCX territory.<br><br>Key discriminator: LCX → lateral + posterior LV | Sub-endocardial infarction → most vulnerable zone (furthest from coronary ostia) | LAD → anterior + septal | LCX thrombosis + sub-endocardial = lateral wall MI pattern."},
/*278*/ {"q":"Non thrombocytopenic purpura. Vitamin K deficiency. 17 year old boy. In CT and all investigations are normal (PT, APTT normal), what is the cause:","o":["Non thrombocytopenic purpura","Vitamin K deficiency","Haemophilia K deficiency","Platelet function defect"],"a":0,"e":"Normal PT, normal APTT, and normal platelet count with purpura indicates non-thrombocytopaenic purpura — a vascular/connective tissue cause. Examples include Henoch-Schönlein purpura (IgA vasculitis), scurvy, or hereditary haemorrhagic telangiectasia. Coagulation cascade is intact.<br><br>Key discriminator: purpura + normal PT + normal APTT + normal platelets → non-thrombocytopaenic purpura (vascular cause) | Thrombocytopaenic purpura (ITP) → low platelets | Haemophilia → prolonged APTT | HSP (IgA vasculitis) → non-thrombocytopaenic purpura + rash + arthralgia + abdominal pain."},
/*279*/ {"q":"A surgeon was repairing tip of neck which vessel is most commonly injured:","o":["TTT","B","Haemophilia","Superficial circumflex femoral"],"a":3,"e":"During inguinal/femoral region surgery (neck of femur repair, hernia repair), the superficial circumflex iliac artery and superficial epigastric artery are commonly encountered and at risk. The superficial circumflex femoral artery is a branch of the femoral artery supplying the inguinal region skin.<br><br>Key discriminator: inguinal region surgery → superficial circumflex iliac + superficial epigastric at risk | Femoral artery → deep to fascia lata | Superficial femoral vessels → most commonly injured in skin flap surgery of the groin | Superficial circumflex femoral = inguinal skin blood supply."},
/*280*/ {"q":"A surgeon was repairing inguinal sac which vessel is most commonly injured:","o":["Hyperextension of neck","Superficial epigastric artery","Internal iliac","External iliac"],"a":1,"e":"During inguinal hernia repair, the superficial epigastric artery (branch of femoral artery, runs toward the umbilicus) is commonly encountered and may be damaged during dissection of the inguinal sac. The inferior epigastric artery is the key landmark for distinguishing direct/indirect hernias but is deeper.<br><br>Key discriminator: inguinal sac repair → superficial epigastric artery at risk (femoral branch, runs in subcutaneous tissue) | Inferior epigastric → deep (behind rectus), landmark for hernia type | Superficial epigastric → subcutaneous, encountered early in dissection | Superficial epigastric = most commonly injured in inguinal sac surgery."},
/*281*/ {"q":"Epidural anaesthesia was given to a pregnant female. Ligament at last during epidural:","o":["Base of skull fracture","Fracture of Transverse process","Anterior spinal ligament","Ligamentum flavum"],"a":3,"e":"The epidural needle passes sequentially through: skin → subcutaneous → supraspinous → interspinous → ligamentum flavum (last, identified by loss of resistance). The epidural space lies immediately deep to the ligamentum flavum.<br><br>Key discriminator: last ligament before epidural space → ligamentum flavum | Loss of resistance technique → detects entry into epidural space through ligamentum flavum | Ligamentum flavum → yellow, highly elastic, connects laminae | Epidural = stop at ligamentum flavum; spinal = continue through dura."},
/*282*/ {"q":"Epidural. Patient with history of fecaluria. A pregnant woman, epidural needle passes through. Ans: Ligamentum flavum. Vitamin D activity assessed by:","o":["1,25 Vit D3","25 OH cholecalciferol","Calcium","1.25 Cholecalciferol"],"a":1,"e":"Vitamin D status is assessed by measuring 25-hydroxycholecalciferol (25-OH D3, calcidiol) in serum — it is the storage form and reflects total body vitamin D stores. The active form (1,25-OH D3, calcitriol) is tightly regulated and does not reflect stores accurately.<br><br>Key discriminator: Vitamin D status → measured as 25-OH cholecalciferol (calcidiol) | Active form → 1,25-(OH)2 D3 (calcitriol, tightly regulated) | Deficiency defined → 25-OH D3 < 50 nmol/L | 25-OH D3 = storage form = the clinical Vitamin D test."},
/*283*/ {"q":"Dopamine regulates which one:","o":["Prolactin","TSH","GH","Cortisol"],"a":0,"e":"Dopamine (from the hypothalamus) is the primary physiological inhibitor of prolactin secretion, acting on D2 receptors on anterior pituitary lactotrophs. Any disruption of the dopaminergic pathway (drugs, pituitary stalk lesion) causes hyperprolactinaemia.<br><br>Key discriminator: dopamine → inhibits prolactin (tonic inhibition) | Dopamine antagonists (antipsychotics, metoclopramide) → hyperprolactinaemia | TRH → stimulates prolactin (secondary) | Dopamine = the prolactin-inhibiting factor = PIF."},
/*284*/ {"q":"A surgeon while performing splenectomy. By which artery supplied:","o":["Prolactin","TSH Level","FSH and LH Levels","Calcium"],"a":0,"e":"The spleen is supplied exclusively by the splenic artery, a branch of the coeliac axis. During splenectomy, the splenic artery and vein must be ligated and divided. The tail of the pancreas is closely related to the splenic hilum and is at risk during splenectomy.<br><br>Key discriminator: spleen → supplied by splenic artery (coeliac axis) | Splenic vein → drains to portal vein | Tail of pancreas → at risk during splenectomy (shares hilum) | Splenic artery = tortuous, runs along upper border of pancreas."},
/*285*/ {"q":"During Cholecystectomy which artery will be damaged:","o":["A (ABD)","Hepatic Artery","Cystic artery","RCA"],"a":2,"e":"During cholecystectomy, the cystic artery (usually a branch of the right hepatic artery) is the primary vessel at risk. It is identified in Calot's triangle (bounded by cystic duct, common hepatic duct, and liver edge) before clipping and division.<br><br>Key discriminator: cholecystectomy → cystic artery at risk (in Calot's triangle) | Cystic artery → usually right hepatic artery branch | Right hepatic artery → can be mistaken for cystic artery if Calot's triangle not properly dissected | Calot's triangle = the key landmark for safe cholecystectomy."},
/*286*/ {"q":"During Cholecystectomy which artery will be damaged. Ans: B. During Cholecystectomy which artery will be damaged. Hepatitis. Haemophilia:","o":["Hep B","Hep C","Hep A","Hep D"],"a":0,"e":"Hepatitis B is the most common hepatitis virus transmitted during surgical procedures, needle-stick injuries, and blood exposure. Healthcare workers and surgical patients are at risk. Universal precautions and HBV vaccination protect against transmission.<br><br>Key discriminator: surgical/needle-stick transmission → HBV (most efficiently transmitted) | HCV → also blood-borne, lower per-exposure risk than HBV | HAV/HEV → faecal-oral, not surgical risk | HBV = most efficiently blood-transmitted hepatitis."},
/*287*/ {"q":"During endoscopy 32 yr old women ulcer found on post wall of stomach it is likely to cause bleeding by causing damage to:","o":["Splenic artery","Left gastric artery","Left gastro-duodenal artery","Gastroduodenal artery"],"a":3,"e":"A posterior gastric ulcer erodes into the gastroduodenal artery (GDA), which lies posterior to the first part of the duodenum and posterior wall of the stomach. GDA erosion causes massive haemorrhage — the most common cause of torrential upper GI bleeding from peptic ulcer disease.<br><br>Key discriminator: posterior gastric/duodenal ulcer → erodes GDA → massive haemorrhage | Anterior ulcer → perforation (peritonitis) | GDA → branch of common hepatic artery | Posterior ulcer + massive haemorrhage = GDA erosion."},
/*288*/ {"q":"After cholecystectomy what is done:","o":["Frontal lobe","Blood Area","Periosteum","Left gastric artery"],"a":2,"e":"After cholecystectomy, the periosteum and peritoneal closure are performed. The periosteum refers to the peritoneal layer of the abdominal wall (peritoneum) that is closed after laparoscopic or open cholecystectomy. Closure prevents bile leakage and adhesions.<br><br>Key discriminator: post-cholecystectomy → peritoneal closure + fascial closure | Bile duct injury → most serious complication of cholecystectomy | Cystic duct remnant → causes post-cholecystectomy syndrome | Peritoneum = the layer closed after cholecystectomy."},
/*289*/ {"q":"After cholecystectomy developed incontinence post focal. Developed Facial post vaginal delivery. Posta-anterior vaginal delivery which nerve is damaged:","o":["Axillary nerve","Long thoracic nerve","Pudendal nerve","Sciatic nerve"],"a":2,"e":"Faecal and urinary incontinence after vaginal delivery results from pudendal nerve injury (S2-S4) during prolonged or instrumental delivery. The pudendal nerve supplies the external anal sphincter, external urethral sphincter, and pelvic floor muscles.<br><br>Key discriminator: post-vaginal delivery incontinence → pudendal nerve injury (S2-S4) | Pudendal nerve → external anal + urethral sphincters + pelvic floor | Pudendal nerve block → used in obstetric analgesia | S2-S4 = pudendal nerve = continence nerve."},
/*290*/ {"q":"A man unable to draw a mug of coffee an image done on which part of brain:","o":["Precentral Motor Cortex","Premotor association area","Primary motor area","Motor association area"],"a":1,"e":"Inability to draw or perform learned purposeful movements (constructional apraxia) despite intact motor and sensory function indicates a premotor association area (supplementary motor area/premotor cortex) lesion, which stores motor programs for complex learned movements.<br><br>Key discriminator: apraxia → premotor/supplementary motor area (stores motor programs) | Primary motor cortex → contralateral weakness (not apraxia) | Parietal lobe → spatial/constructional apraxia | Premotor = the motor planning area = apraxia when damaged."},
/*291*/ {"q":"A young boy with repeated RTI which will show bronchopulmonary anomaly:","o":["C5","C4","C6","C3"],"a":0,"e":"Nerve damage between C5 and C6 affects the brachial plexus (upper trunk — Erb's palsy), causing the 'waiter's tip' deformity. In the context of bronchopulmonary anomaly, the question refers to nerve damage between cervical segments that affects respiratory muscles — phrenic nerve originates at C3-C5.<br><br>Key discriminator: phrenic nerve → C3, C4, C5 | C5 damage → upper brachial plexus (Erb's palsy) | C3-C5 phrenic nerve → diaphragm innervation | Bronchopulmonary anomaly + nerve damage → phrenic nerve/C5 involvement."},
/*292*/ {"q":"A young boy with repeated RTI which will show bronchopulmonary anomaly. Ans: B. Bronchial symmetry. Vens anomaly. Bronchial morphology anomaly. Segmental morphology. Which one is regulated by:","o":["Bronchial symmetry","Vens anomaly","Segmental morphology","PTH and Free T4"],"a":3,"e":"Thyroid function (hypothyroid causing recurrent RTIs through impaired mucociliary clearance and immune function) is evaluated by TSH and Free T4. In the context of recurrent respiratory tract infections with bronchopulmonary anomaly, thyroid dysfunction can be assessed by these tests.<br><br>Key discriminator: recurrent RTI evaluation → consider immunodeficiency + cystic fibrosis + primary ciliary dyskinesia + thyroid dysfunction | TSH + free T4 → thyroid assessment | Bronchopulmonary anomalies → CT chest + bronchoscopy | PTH + free T4 = the relevant hormone assessment pair."},
/*293*/ {"q":"A male presented to OPD with 104 fevers for last 4 days. Gives history of using antimalarials. She has been passing cola colour urine. Serum calcium:","o":["Phosphate","K","Mg","Increased Phosphorous, Ca"],"a":3,"e":"G6PD deficiency with haemolytic crisis (cola urine, antimalarial trigger) causes release of intracellular contents including calcium and phosphate. Haemolysis releases intracellular phosphate, causing hyperphosphataemia with secondary calcium changes. Increased phosphorus and calcium reflect the metabolic consequences of massive haemolysis.<br><br>Key discriminator: massive haemolysis → releases intracellular phosphate → hyperphosphataemia → secondary hypocalcaemia | G6PD crisis → haemolysis → metabolic disturbances | Serum calcium + phosphate = key electrolytes to monitor in haemolytic crisis."},
/*294*/ {"q":"Actin attach to z line through:","o":["Myosin","Desmin","Actin","Troponin"],"a":1,"e":"Actin (thin) filaments are anchored to the Z-disc through alpha-actinin. Desmin is the intermediate filament that links adjacent Z-discs to each other and to the sarcolemma, providing structural integrity across sarcomeres. Titin runs from Z-line to M-line as the elastic scaffold.<br><br>Key discriminator: actin anchored to Z-disc → via alpha-actinin | Desmin → intermediate filament linking Z-discs laterally (across sarcomeres) | Titin → elastic filament from Z to M line | Desmin mutations → dilated cardiomyopathy | Desmin = Z-disc linker = the cytoskeletal connector."},
/*295*/ {"q":"Difference between smooth and striated muscle is:","o":["Actin","Myosin","Desmin","Calsequestrin"],"a":0,"e":"The key structural difference between smooth and striated muscle is the organisation of actin and myosin filaments. Striated muscle has sarcomeric organisation (regular Z-lines, A-bands, I-bands) with troponin-tropomyosin regulation; smooth muscle lacks sarcomeres and uses calmodulin-MLCK regulation, not troponin.<br><br>Key discriminator: striated muscle → sarcomeric actin arrangement + troponin-tropomyosin regulation | Smooth muscle → non-sarcomeric actin + calmodulin/MLCK regulation (no troponin) | Actin present in both but organised differently | Sarcomeric organisation = defining feature of striated muscle."},
/*296*/ {"q":"After vagal stimulation of heart, slows down. After vagal stimulation heart rate slows. Which ion K+ increases:","o":["Phosphorous","Ca","K","Mg"],"a":2,"e":"Vagal stimulation releases ACh, which acts on M2 receptors in the SA and AV nodes, opening IKACh channels. This increases K+ conductance, hyperpolarising the nodal cells and slowing spontaneous depolarisation (decreasing heart rate — negative chronotropy).<br><br>Key discriminator: vagal stimulation → ↑K+ conductance (IKACh channels) → hyperpolarisation → slower SA node firing → bradycardia | Sympathetic → ↑Ca2+ + ↑Na+ (funny current) → faster depolarisation → tachycardia | K+ increase = vagal slowing mechanism."},
/*297*/ {"q":"Paranympathatic act on SA Node which ion K increases. Ans: B. Paranympathatic act on SA node K+ increases in cells. What change will be seen in response to stress:","o":["Adrenaline","Noradrenaline","Dopamine","Cortisol"],"a":0,"e":"The primary hormonal response to stress is adrenaline (epinephrine) from the adrenal medulla, causing the 'fight or flight' response: increased HR, BP, blood glucose, and bronchodilation. Cortisol from the adrenal cortex is the sustained stress hormone (HPA axis).<br><br>Key discriminator: acute stress → adrenaline (adrenal medulla, fast response) | Chronic stress → cortisol (HPA axis, sustained) | Adrenaline → β1 (HR + contractility) + β2 (bronchodilation + vasodilation in muscle) + α1 (vasoconstriction in skin/viscera) | Adrenaline = the primary acute stress hormone."},
/*298*/ {"q":"Relation of head of terminal CBD with:","o":["Anterior","Posterior","Superior","Lateral"],"a":1,"e":"The common bile duct (CBD) runs in the posterior groove of the head of the pancreas before joining the main pancreatic duct at the ampulla of Vater. The CBD lies posterior to the head of the pancreas — this is why pancreatic head pathology (carcinoma, chronic pancreatitis) causes obstructive jaundice by compressing the CBD posteriorly.<br><br>Key discriminator: CBD → posterior to pancreatic head (in posterior groove) | Pancreatic head mass → compresses CBD posteriorly → obstructive jaundice | CBD enters duodenum at ampulla of Vater (major papilla) | Posterior = CBD relationship to pancreatic head."},
/*299*/ {"q":"Rhythm and motility of GIT is maintained by:","o":["N+/Ca","Na+/Ca","Ca++/K+","Ca++/Na+"],"a":2,"e":"GIT smooth muscle rhythmic contractions (slow waves/basic electrical rhythm) are initiated by interstitial cells of Cajal and maintained through Ca2+/K+ channel interactions. Calcium influx triggers contraction; potassium efflux causes repolarisation. The Ca2+/K+ balance determines smooth muscle excitability and GIT motility.<br><br>Key discriminator: GIT motility → Ca2+/K+ balance | Ca2+ → triggers smooth muscle contraction | K+ → repolarisation + relaxation | Slow waves generated by ICC → propagated via Ca2+/K+ channels | Ca2+/K+ = GIT rhythmic contraction regulators."},
/*300*/ {"q":"A patient presented in semi conscious condition with lemon supply subclavian steal. Anterior two third septal which is supplied by:","o":["Anterior","External iliac","Internal iliac","Femoral"],"a":0,"e":"The anterior two-thirds of the interventricular septum is supplied by the left anterior descending artery (LAD), which is a branch of the left coronary artery. The posterior one-third of the IVS is supplied by the posterior descending artery (PDA), usually from the RCA in right-dominant circulation.<br><br>Key discriminator: anterior 2/3 IVS → LAD (left anterior descending) | Posterior 1/3 IVS → PDA (from RCA in 85% — right dominance) | LAD = 'widowmaker' (supplies anterior wall + anterior IVS + apex) | Anterior IVS = LAD territory."}
,
/*301*/ {"q":"Pain in gluteal region, most likely vessel:","o":["Anterior iliac","Internal iliac","External iliac","Femoral"],"a":1,"e":"The gluteal region is supplied by the superior and inferior gluteal arteries, both branches of the internal iliac artery. Pain from gluteal ischaemia (as in vascular claudication of the buttock) implicates the internal iliac artery supply territory.<br><br>Key discriminator: gluteal arteries → superior + inferior gluteal = internal iliac branches | External iliac → lower limb (femoral territory) | Internal iliac = all pelvic viscera + gluteal muscles | Buttock claudication = internal iliac occlusion."},
/*302*/ {"q":"Vein circumflex artery accompanying left circumflex artery is which of following:","o":["Vein","Mesothelium","Endoderm","Endothelium"],"a":3,"e":"The inner lining of blood vessels (including coronary arteries and their accompanying veins) is composed of endothelium — a specialised simple squamous epithelium of mesodermal origin. The endothelium regulates vascular tone, coagulation, and permeability.<br><br>Key discriminator: blood vessel inner lining → endothelium (simple squamous, mesodermal) | Mesothelium → lines serous cavities (pleura, pericardium, peritoneum) | Endoderm → GI/respiratory epithelium | Endothelium = the vascular inner lining = the correct answer."},
/*303*/ {"q":"2/3 of interventricular septum is supplied by anterior. Peripheral incontinence post focal. A 45 year old female presenting with morning grooling with joint pain stiffness:","o":["Right gastric artery","Celiac artery","Left gastric artery","Inferior pancreaticoduodenal artery"],"a":2,"e":"Morning stiffness, joint pain, and groaning in a 45-year-old female suggests rheumatoid arthritis. Regarding gastric blood supply, the left gastric artery (branch of coeliac axis) supplies the lesser curvature of the stomach and lower oesophagus, and is the most commonly involved artery in gastric ulcer bleeding.<br><br>Key discriminator: left gastric artery → lesser curvature + lower oesophagus (coeliac branch) | Right gastric → also lesser curvature (hepatic branch) | Greater curvature → right and left gastroepiploic arteries | Left gastric = the dominant lesser curvature artery."},
/*304*/ {"q":"Anterior two third intraventricular septum supplied by:","o":["Aorta","External iliac","Femoral","Internal iliac"],"a":0,"e":"The anterior two-thirds of the interventricular septum is supplied by septal branches of the LAD (left anterior descending artery), which arises from the left coronary artery (aorta origin). The aorta is the root source. This territory is compromised in anterior MI (LAD occlusion).<br><br>Key discriminator: anterior 2/3 IVS → LAD septal branches → left coronary → aorta | Posterior 1/3 IVS → PDA (from RCA) | LAD = 'widowmaker' supplies anterior IVS + apex + anterior LV wall | Aorta = ultimate origin of all coronary arteries."},
/*305*/ {"q":"Posterior focal incontinence. Developed facial post vaginal delivery. A patient focal incontinence post vaginal delivery. Postcentral vaginal delivery which nerve is damaged. Posta-anterior vaginal delivery. Posterior focal incontinence. Developed Facial posterior vaginal delivery. Developed Facial. Which is branch of right coronary artery:","o":["Postoanterior coronary artery (POCA) artery","Focal (Vaginal) incontinence","LAD","LCA"],"a":0,"e":"The posterior descending artery (PDA) is the major branch of the right coronary artery (in right-dominant circulation, 85% of individuals). It supplies the posterior interventricular groove, posterior 1/3 IVS, and inferior wall of both ventricles.<br><br>Key discriminator: RCA major branch → posterior descending artery (PDA) in right-dominant | PDA supplies → posterior 1/3 IVS + inferior LV | Left dominant → LCX gives PDA | RCA → right ventricle + inferior LV + SA node + AV node."},
/*306*/ {"q":"Which lymph nodes related to descending thoracic aorta and sigmoid colon:","o":["Lymph nodes","Pectoral nerve test","Para-aortic lymph nodes","Anal manometry"],"a":2,"e":"The descending thoracic aorta is flanked by para-aortic lymph nodes (posterior mediastinal nodes). The sigmoid colon drains to inferior mesenteric nodes, then to para-aortic (lumbar) nodes. Para-aortic nodes are the common final pathway for many abdominal and pelvic organs.<br><br>Key discriminator: para-aortic nodes → thoracic aorta + abdominal organs (testes, ovaries, kidneys, sigmoid) | Inguinal nodes → lower limb + perineum + external genitalia | Para-aortic = L1-L2 nodal station = testes/ovary/sigmoid drainage."},
/*307*/ {"q":"RCA supplies condition true about heart:","o":["Cliae lymph nodes","LCA gives LCX and LAD","RCA supplies posterior 1/3rd IVS","LCA gives RCA"],"a":2,"e":"The right coronary artery (RCA) in right-dominant circulation supplies the SA node, AV node, right ventricle, inferior LV wall, and the posterior 1/3 of the interventricular septum via the posterior descending artery (PDA). RCA occlusion causes inferior MI with possible heart block.<br><br>Key discriminator: RCA → SA node (60%) + AV node (85%) + inferior LV + posterior 1/3 IVS | LAD → anterior 2/3 IVS + anterior LV + apex | RCA inferior MI → may cause heart block (AV nodal ischaemia) | Posterior 1/3 IVS = RCA territory."},
/*308*/ {"q":"Person doing chin up raises his arm above head and than bridged in front on chest what muscles help:","o":["Scalenus anterior","Latissimus dorsi","Romboid major","Serratus anterior"],"a":1,"e":"Chin-ups require shoulder adduction and extension — movements primarily performed by latissimus dorsi (adducts, extends, medially rotates humerus). The latissimus dorsi pulls the arm downward and backward (as in pulling a chin-up bar down toward the chest).<br><br>Key discriminator: chin-up muscles → latissimus dorsi (adduction + extension of humerus) + biceps brachii (elbow flexion) | Serratus anterior → protracts scapula (not arm adduction) | Rhomboids → retract scapula | Latissimus dorsi = the prime mover in chin-ups."},
/*309*/ {"q":"Local Lymphatic obstruction is caused by combination of:","o":["Scalenus anterior","Serratus posterior","Scalene anchor","Local lymphatic obstruction"],"a":3,"e":"Local lymphatic obstruction can result from combined causes: filariasis (Wuchereria bancrofti), surgical lymph node removal (post-mastectomy), radiation fibrosis, and malignant nodal infiltration. The combination of infection and mechanical obstruction is most commonly seen in tropical lymphoedema.<br><br>Key discriminator: lymphatic obstruction causes → filariasis (most common worldwide) + surgical removal + radiation + malignant infiltration | Result → protein-rich lymphoedema | Filariasis → W. bancrofti blocks lymphatics → elephantiasis | Multiple causes combine in chronic cases."},
/*310*/ {"q":"Hypercalcaemia leads to which:","o":["Both arrests","Diastolic arrest","Systolic arrest","Variable"],"a":2,"e":"Hypercalcaemia causes systolic arrest of the heart by increasing cardiac muscle excitability and contractility to the point of sustained contraction. The heart is locked in systole, unable to relax. This is opposite to hyperkalaemia, which causes diastolic arrest.<br><br>Key discriminator: hypercalcaemia → systolic arrest (sustained contraction) | Hyperkalaemia → diastolic arrest (depolarisation block) | Memory: calcium = contraction = systolic; potassium = relaxation = diastolic | Hypercalcaemia = systolic cardiac arrest."},
/*311*/ {"q":"Hypercalcaemia and hypokalaemia will occur in:","o":["Systolic heart arrest","Diastolic heart failure","Urine osmolality increase","ECF osmolality increase"],"a":3,"e":"Hypercalcaemia reduces renal concentrating ability (nephrogenic diabetes insipidus) and causes volume depletion. Combined hypercalcaemia and hypokalaemia (as in primary hyperaldosteronism or thiazide diuretics) leads to increased ECF osmolality due to hypercalcaemia driving osmolar elevation.<br><br>Key discriminator: hypercalcaemia → increases ECF osmolality + impairs renal concentrating ability | Hypokalaemia + hypercalcaemia → thiazide diuretics (classic combination) | ECF osmolality increases → ADH secretion triggered | Hypercalcaemia = ECF osmolality increase."},
/*312*/ {"q":"Increase in venous return in right atrium is due to increase in:","o":["Urine osmolality decrease","ECF osmolality decrease","ECF volume increase","ECF osmolality increase"],"a":2,"e":"Venous return to the right atrium increases when ECF (extracellular fluid) volume increases — more circulating volume means higher venous pressure and greater preload. This is the basis of fluid resuscitation in shock: increasing ECF volume → increased venous return → increased cardiac output (Frank-Starling).<br><br>Key discriminator: venous return → determined by mean systemic filling pressure (MSFP) minus RAP | ECF volume increase → ↑MSFP → ↑venous return → ↑preload → ↑CO | Dehydration → ↓ECF → ↓venous return → hypovolaemic shock | ECF volume increase = venous return increase."},
/*313*/ {"q":"Increase in venous return in right atrium. TPR. Mean systemic filling pressure. Venous compliance:","o":["Vagal tone","Increase venous compliance","Venous compliance","Mean systemic filling pressure"],"a":3,"e":"Venous return is driven by the mean systemic filling pressure (MSFP) — the pressure in the venous reservoir when the heart stops. MSFP = driving force for venous return. It increases with blood volume expansion and decreases with venodilatation or hypovolaemia.<br><br>Key discriminator: venous return = (MSFP − RAP) / venous resistance | MSFP increases → more venous return | Increased venous compliance → reduces MSFP → reduces venous return | MSFP = the key determinant of venous return."},
/*314*/ {"q":"CSF findings necessary to rule out which carcinoma:","o":["Cilia","Hemidesmosome","Desmosomes","Plasma Protein"],"a":3,"e":"CSF examination looks for protein, glucose, cells, and tumour markers. Elevated CSF protein (plasma protein leakage through disrupted blood-brain barrier) is found in meningitis, tumours, and Guillain-Barré syndrome. CSF plasma protein measurement helps diagnose CNS malignancy and leptomeningeal carcinomatosis.<br><br>Key discriminator: CSF for carcinoma → look for malignant cells + elevated protein + low glucose | Leptomeningeal carcinomatosis → positive CSF cytology | CSF protein elevated → disrupted blood-brain barrier (tumour, infection) | Plasma protein in CSF = the carcinoma screening marker."},
/*315*/ {"q":"From Lower to higher gradient simple mediator is:","o":["SCC","Meningioma","Nephroblastoma","Retinoblastoma"],"a":0,"e":"Transport from lower to higher concentration gradient (against gradient) requires energy (active transport). Simple diffusion moves substances from high to low concentration (passive, no energy). The transport from lower to higher gradient (facilitated by carrier) against the gradient = active transport. In CNS tumour context: SCC of the brain (metastatic) is the most common brain tumour overall.<br><br>Key discriminator: most common brain tumour overall → metastases (lung, breast, melanoma, renal, colorectal) | Most common primary malignant → GBM (glioblastoma) | Most common benign → meningioma | SCC metastases = most common brain tumour in adults."},
/*316*/ {"q":"The medial wall of lacriorectal fossa is formed by:","o":["Obturator Internos","Peritoneal Membrane","Simple diffusion","Facilitated diffusion"],"a":0,"e":"The medial wall of the ischio-rectal (ischiorectal) fossa is formed by the obturator internus muscle (covered by obturator fascia). The lateral wall is the obturator internus, the floor is the external anal sphincter, and the roof is the levator ani. The obturator internus forms both medial and lateral walls.<br><br>Key discriminator: ischio-rectal fossa medial wall → obturator internus muscle (covered by Alcock's canal containing pudendal nerve + vessels) | Roof → levator ani | Floor → external anal sphincter | Obturator internus = the dominant wall of the ischiorectal fossa."},
/*317*/ {"q":"A patient presented in semi conscious condition with lemon area subclavian steal. Contents: Ischioanal fat is what content of ischioanal fossa:","o":["Pudendal nerve and its branches","Major blood supply of pudendal canal with its content","Ischioanal fat + pudendal nerve + inferior rectal vessels","Internal pudendal canal with its content"],"a":2,"e":"The ischio-anal fossa contains: ischio-anal fat (the main content allowing anal expansion during defaecation), the pudendal nerve and its branches (inferior rectal, perineal, dorsal nerve of clitoris/penis), and the inferior rectal vessels. It also contains the pudendal canal (Alcock's canal) on its lateral wall.<br><br>Key discriminator: ischio-anal fossa main content → fat + pudendal nerve branches + inferior rectal vessels | Pudendal canal (Alcock's) → on lateral wall, contains internal pudendal vessels + pudendal nerve | Inferior rectal nerve → from pudendal nerve, crosses fossa to anal sphincter | Fat = the most abundant content = allows rectal dilation."},
/*318*/ {"q":"Which drug if given intravenous causes 60% thrombophlebitis. A 19 years old female with increased TAGs. Systemic hypertension. Which drug if given intravenous causes 60% thrombophlebitis:","o":["Praziquantel","Niclosamide","Oxazepam","IV diazepam"],"a":3,"e":"IV diazepam causes thrombophlebitis in ~60% of patients due to its propylene glycol vehicle, which is highly irritant to vein walls. The aqueous emulsion form (Diazemuls) dramatically reduces this complication rate. Midazolam (water-soluble) is preferred for IV use.<br><br>Key discriminator: IV diazepam → 60% thrombophlebitis (propylene glycol vehicle) | Diazemuls → lipid emulsion, less thrombophlebitis | Midazolam → water-soluble, minimal vein irritation | IV diazepam = classic thrombophlebitis-causing drug."},
/*319*/ {"q":"Premalignant lesion for oral SCC:","o":["Erythroplakia","Cholecystitis","Appendicitis","Lichen planus"],"a":0,"e":"Erythroplakia (red velvety patches of oral mucosa) has the highest malignant transformation rate of all oral premalignant lesions (>50%). Leukoplakia transforms in 5-17%; lichen planus has 1-3% transformation. Erythroplakia requires immediate biopsy and treatment.<br><br>Key discriminator: erythroplakia → highest malignant transformation (>50%) | Leukoplakia → 5-17% transformation | Erythrythroplasia → red = more dysplastic than white | Biopsy all red oral lesions urgently | Erythroplakia = most dangerous oral premalignant lesion."},
/*320*/ {"q":"In Intrinsic damage, which factor cause activation of coagulation:","o":["Factor 9","Factor 12 (Hagman Factor)","Erythroplakia","Leukoplakia"],"a":1,"e":"The intrinsic pathway is activated by Factor XII (Hageman factor) when it contacts negatively charged surfaces (exposed subendothelial collagen, glass surfaces in vitro). Factor XII activates Factor XI → IX → X → common pathway. This is measured by the APTT.<br><br>Key discriminator: intrinsic pathway activation → Factor XII (Hageman factor, contact activation) | APTT measures → intrinsic + common pathway (Factors XII, XI, IX, VIII, X, V, II) | PT measures → extrinsic + common (Factor VII, X, V, II) | Factor XII = Hageman = intrinsic pathway initiator."},
/*321*/ {"q":"Activation of intrinsic pathway by Thromboplastin (Tissue Factor):","o":["Thromboplastin","Antagonist","Agonist","Prime mover"],"a":0,"e":"Tissue factor (thromboplastin) activates the extrinsic pathway of coagulation when exposed subendothelial tissue factor binds Factor VIIa. Despite being listed as an intrinsic pathway activator here, tissue factor is the primary initiator of the extrinsic coagulation cascade in vivo.<br><br>Key discriminator: tissue factor/thromboplastin → activates extrinsic pathway (Factor VII) | Factor XII → activates intrinsic pathway (contact activation) | In vivo coagulation → primarily extrinsic pathway (TF-VIIa) | PT measures extrinsic (tissue factor pathway); APTT measures intrinsic."},
/*322*/ {"q":"A surgeon was repairing inguinal sac, which is most commonly injured:","o":["Right inguinal","Hyperextension of neck","First pharyngeal Arch derivative","Fracture of Odontoid process"],"a":0,"e":"During right inguinal hernia repair, the right inguinal canal and its contents (spermatic cord, ilioinguinal nerve, genital branch of genitofemoral nerve) are at risk. The right inguinal region structures are the most commonly injured during right inguinal sac repair.<br><br>Key discriminator: right inguinal hernia repair → right inguinal structures at risk (ilioinguinal nerve, vas deferens, testicular vessels) | Ilioinguinal nerve → most commonly damaged nerve in inguinal repair | Injury → medial thigh + scrotal/labial numbness | Right inguinal = right-sided structures at risk."},
/*323*/ {"q":"Which of the following tumor two hit Knudson hypothesis:","o":["Supracondylar","Retrocondylar","Intramedullary and Retrocondylar","First pharyngeal Arch derivative"],"a":3,"e":"Knudson's two-hit hypothesis applies to tumour suppressor genes: both alleles must be inactivated for cancer to develop. Retinoblastoma (RB1) is the classic example — one allele is mutated (inherited or somatic) and the second is lost (second hit). This applies to all tumour suppressors including TP53, APC, and BRCA.<br><br>Key discriminator: two-hit hypothesis → tumour suppressor genes (both alleles must be lost) | Retinoblastoma (RB1) → classic example (familial = one allele inherited mutated, second hit somatic) | Oncogenes → one hit sufficient (gain-of-function) | Tumour suppressors = two hits required."},
/*324*/ {"q":"69 years old man got brain there were some acidic protein substances found on biopsy there protein. Which following is a marker for the brain tissue found:","o":["Wilms Tumour","Burkitt Lymphoma","Neuroblastoma","A (FA)"],"a":3,"e":"Acidic proteins in brain tissue on biopsy are identified using GFAP (glial fibrillary acidic protein) — the specific marker for astrocytes and astrocytic tumours (astrocytomas, GBM). GFAP is the immunohistochemical marker for brain glial tissue, identifying tumour origin.<br><br>Key discriminator: brain biopsy acidic protein → GFAP (glial fibrillary acidic protein) | GFAP marks → astrocytes + astrocytomas + GBM | S-100 → glial + Schwann cells (less specific) | NSE → neurons + neuroendocrine tumours | GFAP = the brain glial tissue marker."},
/*325*/ {"q":"What change will be seen in response to stress:","o":["Gangliocytes","Medulloblastoma","Meningioma","Astrocytes"],"a":3,"e":"In response to CNS stress or injury, astrocytes proliferate and become reactive (reactive astrogliosis), upregulating GFAP and forming the glial scar. This is the CNS equivalent of fibrosis in other tissues. Astrocytes are the first responders to brain injury.<br><br>Key discriminator: CNS stress response → reactive astrogliosis (astrocyte proliferation + GFAP upregulation) | Microglia → CNS macrophages (phagocytosis) | Oligodendrocytes → myelin (don't respond to stress primarily) | Astrocytes = the CNS stress/repair response cell."},
/*326*/ {"q":"Patient with alcoholic liver disease. Explanation: Upper oesophagus — inferior thyroid. Middle oesophagus left gastric. Which explanation:","o":["Upper esophagus — Inferior thyroid artery","Middle esophagus — Left gastric artery","Descending thoracic aorta — Left gastric artery","Middle cardiac vein — Left gastric"],"a":1,"e":"The middle third of the oesophagus is supplied by oesophageal branches of the descending thoracic aorta and the left gastric artery. The left gastric artery (coeliac branch) ascends along the lesser curvature and gives oesophageal branches to the lower and middle oesophagus.<br><br>Key discriminator: upper oesophagus → inferior thyroid artery | Middle oesophagus → thoracic aorta branches + left gastric | Lower oesophagus → left gastric artery | This segmental supply is clinically relevant in oesophageal surgery and ischaemia."},
/*327*/ {"q":"Most common site of fracture rib:","o":["Lateral end of rib","Most common site of rib fracture","Upper Ribs","Lateral end of Clav"],"a":0,"e":"The most common site of rib fracture is the lateral (posterior angle) of the rib — the weakest point where the rib changes direction. This is where most traumatic and stress fractures occur. The posterior angle (at the erector spinae muscle attachment) is the point of maximum mechanical stress.<br><br>Key discriminator: rib fracture most common site → lateral angle (posterior angle, site of maximum stress) | Upper ribs (1-3) → protected by clavicle + scapula (require massive force) | First rib fracture → associated with subclavian vessel + brachial plexus injury | Lateral angle = most common rib fracture site."},
/*328*/ {"q":"Thiazide diuretics act on:","o":["Upper Ribs","Lateral end of rib","Collecting duct","PCT"],"a":3,"e":"Thiazide diuretics act primarily on the early distal convoluted tubule (DCT), blocking the Na+/Cl- cotransporter (NCC). They are less potent than loop diuretics but are first-line for hypertension. They cause hypokalaemia, hypercalcaemia, hyperglycaemia, and hyperuricaemia.<br><br>Key discriminator: thiazides → early DCT (Na+/Cl- cotransporter) | Loop diuretics → thick ascending limb (Na+/K+/2Cl- transporter) | Aldosterone antagonists (spironolactone) → collecting duct | ACZ (carbonic anhydrase inhibitors) → PCT | Thiazide = DCT = distal convoluted tubule."},
/*329*/ {"q":"Best cell for engraftment after bone marrow transplant:","o":["Proliferative cells","Static cells","Labile cells","Stem cells"],"a":3,"e":"Haematopoietic stem cells (HSCs) are the ideal cells for bone marrow transplantation because they are self-renewing and multipotent — capable of reconstituting all blood cell lineages. CD34+ HSCs from bone marrow, peripheral blood stem cells (after G-CSF mobilisation), or umbilical cord blood are used.<br><br>Key discriminator: bone marrow transplant → haematopoietic stem cells (CD34+) | Stem cells → self-renewal + multipotency = engraftment capability | Proliferative/labile cells → high turnover but not stem cells | G-CSF → mobilises HSCs from marrow to blood for harvest | Stem cells = the only transplantable engrafting cells."},
/*330*/ {"q":"Immunoglobulin is due to:","o":["Fab portion","FC portion","Biologic","Stem cells"],"a":0,"e":"The antigen-binding portion of immunoglobulin is the Fab fragment (Fragment antigen-binding), composed of one constant and one variable domain of both the heavy and light chains. The variable regions form the complementarity-determining regions (CDRs) that directly contact antigen.<br><br>Key discriminator: Fab fragment → antigen binding (variable regions of heavy + light chains) | Fc fragment → effector functions (complement activation, FcR binding, ADCC) | IgG has 2 Fab + 1 Fc | Fab = antigen-binding = the recognition portion."},
/*331*/ {"q":"A 55-year-old male alcoholic presents with symptoms. Ionic bonds:","o":["Ionic bonds","Disulphide bonds","Diphthol bonds","Hydrogen bonds"],"a":0,"e":"Ionic bonds are important in maintaining protein tertiary structure (salt bridges between oppositely charged amino acid side chains) and RBC membrane cytoskeletal protein interactions. They are also important in antigen-antibody interactions (electrostatic attractions between complementary charges).<br><br>Key discriminator: ionic bonds → salt bridges in protein structure + RBC membrane skeleton | Disulphide bonds → IgG structure + keratin (covalent, strongest) | Hydrogen bonds → secondary protein structure (alpha-helix, beta-sheet) | Ionic bonds = electrostatic = salt bridges in protein structure."},
/*332*/ {"q":"A 55-year-old male alcoholic. Fat accumulation appears as round clear spaces with well circumscribed. Though it is difficult to see on H&E. More accurately oil red o stain used for this purpose. Respiratory acidosis occurs in which:","o":["Hillary areas","Drowning","Vomiting","Diarrhoea"],"a":1,"e":"Respiratory acidosis occurs when CO2 accumulates due to impaired ventilation. Drowning causes hypoxia and hypoventilation (respiratory arrest), leading to CO2 retention and respiratory acidosis. It is a classic cause of acute respiratory acidosis from airway/breathing failure.<br><br>Key discriminator: respiratory acidosis → CO2 retention from hypoventilation | Causes → drowning + COPD + respiratory muscle failure + severe pneumonia | Vomiting/diarrhoea → metabolic alkalosis/acidosis | Drowning = acute respiratory failure = respiratory acidosis."},
/*333*/ {"q":"A 57 year old patient presented with cough and thick sputum presented. Causative organism is:","o":["Superior to body and tail of pancreas","Inferior to body and tail","Lies in uncinate process","Streptococcus pneumoniae"],"a":3,"e":"Cough with thick purulent sputum (lobar/community-acquired pneumonia pattern) in an adult is most commonly caused by Streptococcus pneumoniae (pneumococcus). It causes classic lobar pneumonia with rust-coloured sputum and is gram-positive, lancet-shaped diplococci.<br><br>Key discriminator: community-acquired pneumonia most common → Streptococcus pneumoniae | Atypical pneumonia → Mycoplasma (young adults), Legionella (AC units, hyponatraemia) | Pseudomonas → hospital-acquired + CF | S. pneumoniae = rust-coloured sputum = lobar pneumonia = most common CAP pathogen."},
/*334*/ {"q":"A 57 years old patient presented with cough and thick sputum. Causative organism. Aspergillus. Pseudomonas aeruginosa. Mycobacterium avium. A 57 years old patient presented with cough and thick sputum presented:","o":["Streptococcus pneumoniae","Pseudomonas aeruginosa","Candida albican","Mycobacterium avium"],"a":0,"e":"A 57-year-old with lobar pneumonia pattern (thick productive sputum, acute onset) has community-acquired pneumonia most likely caused by Streptococcus pneumoniae. Pseudomonas and Mycobacterium avium are nosocomial/immunocompromised pathogens.<br><br>Key discriminator: thick purulent sputum + acute + community → S. pneumoniae | Pseudomonas → hospital-acquired + CF + bronchiectasis | M. avium → AIDS patients (CD4 <50) | Candida → oral thrush/oesophagitis, rarely pneumonia | S. pneumoniae = first-line CAP suspect."},
/*335*/ {"q":"Patient with nephrotic syndrome. Which structure in GBM plays major role in perm-selectivity for proteins:","o":["Lamina rara externa","Lamina densa","Lamina rara interna","Visceral epithelial layer"],"a":1,"e":"The lamina densa of the GBM provides size-selective filtration via type IV collagen meshwork. The laminae rarae provide charge selectivity via heparan sulphate proteoglycans. In nephrotic syndrome, loss of negative charge barrier (heparan sulphate) allows albumin to pass through.<br><br>Key discriminator: lamina densa → size selectivity (type IV collagen) | Laminae rarae → charge selectivity (heparan sulphate) | Nephrotic syndrome → charge barrier disrupted → proteinuria | Perm-selectivity = size + charge working together."},
/*336*/ {"q":"Source of spread of infection from tip of nose occurs to:","o":["Inferior Ophthalmic vein","Superior Ophthalmic vein","Maxillary vein","Nasal vein"],"a":1,"e":"Infection from the tip of the nose (danger triangle of face) drains via the facial vein → superior ophthalmic vein → cavernous sinus, potentially causing cavernous sinus thrombosis. The facial vein lacks valves in this region, allowing retrograde flow.<br><br>Key discriminator: nose tip danger triangle → facial vein → superior ophthalmic vein → cavernous sinus | No valves in facial vein → retrograde spread possible | Cavernous sinus thrombosis → proptosis + chemosis + CN III/IV/VI palsies + fever | Superior ophthalmic vein = the route of spread."},
/*337*/ {"q":"A man has noted scleral icterus and has tachycardia and vitals for one month. O/E mild tachycardia 4 days unremarkable lab finding. Lab shows Hct 25%, Bilirubin 3.6, Indirect 2.1 and Hepatoglobin 200 (Normal 200) cause is:","o":["Golgi tendon organ","Meissner corpuscles","Ruffini receptor","Krause receptor"],"a":0,"e":"Haemolytic anaemia causes scleral icterus (indirect hyperbilirubinaemia) with compensatory tachycardia, low Hct, and raised indirect bilirubin. Low haptoglobin (consumed by free haemoglobin from haemolysis) confirms intravascular haemolysis. The Golgi tendon organ is the mechanoreceptor for muscle tension.<br><br>Key discriminator: intravascular haemolysis → low Hct + raised indirect bilirubin + low haptoglobin + haemoglobinuria | Golgi tendon organ → muscle tension receptor | Scleral icterus + tachycardia + low Hct = haemolytic anaemia diagnosis | Haptoglobin consumed = intravascular haemolysis marker."},
/*338*/ {"q":"A patient presented in semi-conscious condition. Which artery is causing this condition:","o":["External carotid artery","Vertebral carotid artery","Maxillary artery","Facial artery"],"a":1,"e":"Subclavian steal syndrome causes vertebrobasilar insufficiency — the vertebral artery reverses flow to supply an arm with proximal subclavian stenosis, 'stealing' blood from the basilar circulation. Symptoms include dizziness, diplopia, drop attacks, and altered consciousness on arm exercise.<br><br>Key discriminator: subclavian steal → vertebral artery reverses flow → vertebrobasilar insufficiency → semi-consciousness + dizziness on arm use | Vertebral artery → supplies posterior fossa (cerebellum + brainstem) | Proximal subclavian stenosis → triggers steal | Vertebral artery = the vessel causing subclavian steal syndrome."},
/*339*/ {"q":"A young male has azoospermia. Which initial investigation will help in diagnosis:","o":["Pectoralis major","Pectoralis minor","Latissimus muscular","Serratus minor"],"a":3,"e":"In azoospermia evaluation, the first investigation is semen analysis (already established as azoospermia), then serum FSH, LH, and testosterone to distinguish obstructive (normal FSH) from non-obstructive/testicular failure (high FSH). However in this context of winging of scapula muscles — serratus anterior (not serratus minor) is the relevant muscle. For azoospermia: FSH and LH levels is the initial investigation.<br><br>Key discriminator: azoospermia initial investigation → FSH + LH + testosterone | High FSH → non-obstructive azoospermia (testicular failure) | Normal FSH → obstructive azoospermia (vas/epididymal block) | FSH and LH = the first hormonal tests in azoospermia evaluation."},
/*340*/ {"q":"A surgeon while performing splenectomy. Winging of scapula occurs due to damage of:","o":["FSH and LH Levels","Testosterone Level","Sperm Count","Antibodies against sperm"],"a":0,"e":"Winging of the scapula occurs due to damage to the long thoracic nerve (C5-C7), which innervates serratus anterior. During splenectomy or left-side thoracic surgery, the long thoracic nerve can be stretched or damaged, causing medial scapular winging.<br><br>Key discriminator: scapular winging → long thoracic nerve injury → serratus anterior paralysis | Medial winging (inferior angle lifts) → long thoracic nerve | Lateral winging → accessory nerve (trapezius) | Long thoracic nerve = the serratus anterior nerve = winging nerve."},
/*341*/ {"q":"Patient with lamina densa. GBM permselectivity. Patient with nephrotic syndrome. Ans: B lamina densa. Patient has eaten fast food whole night. Male has eaten fast food at night. Liquefactive necrosis. A patient fall on close eye. Sways back and forth. Cerebellum lesion:","o":["Increase GH","Decrease GH","Impaired glucose tolerance","Increased ACTH"],"a":2,"e":"A patient who sways with eyes closed (Romberg positive) has loss of proprioception (posterior column lesion) or cerebellar disease. Impaired glucose tolerance occurs in growth hormone excess (acromegaly) — GH is counter-regulatory (anti-insulin). Cerebellar lesions cause intention tremor and ataxia (Romberg negative if purely cerebellar).<br><br>Key discriminator: Romberg positive → posterior column (proprioception) lesion | Cerebellar lesion → Romberg negative (ataxia present eyes open AND closed) | GH excess → impaired glucose tolerance (acromegaly + diabetes) | Impaired glucose tolerance + ataxia → consider GH-related metabolic disturbance."},
/*342*/ {"q":"Fall on closed eye patient sways. Fall on close eye, cerebellum. A patient presented with fall on closed eye. Cerebellum lesion after RTA. EDV depends on venous return. After food determines by MAP. After food determines by which of:","o":["Patient falls on close eye when Romberg test is done","Decrease Diastolic BP by — MAP","Pinocytosis","MAP"],"a":3,"e":"After a meal, MAP (mean arterial pressure) determination involves cardiac output and total peripheral resistance. Post-prandially, splanchnic vasodilation occurs (mesenteric blood flow increases), which could lower MAP if not compensated. MAP = diastolic + 1/3 pulse pressure determines perfusion pressure to all organs.<br><br>Key discriminator: MAP = DBP + 1/3(SBP − DBP) | Post-prandial → splanchnic vasodilation → compensatory ↑CO + ↑HR to maintain MAP | MAP determines organ perfusion pressure | MAP = mean arterial pressure = the physiological perfusion pressure."},
/*343*/ {"q":"Relation of head terminal CBD with pancreatic head:","o":["Anterior","Superior","Lateral","Posterior"],"a":3,"e":"The CBD runs in the posterior groove of the pancreatic head and is therefore posterior to the pancreatic head. Carcinoma or inflammation of the pancreatic head compresses the CBD from anterior, causing obstructive jaundice. This posterior relationship is the surgical anatomical key.<br><br>Key discriminator: CBD → posterior to pancreatic head (in posterior groove) | Pancreatic head carcinoma → compresses CBD → painless obstructive jaundice | Ampullary carcinoma → at the junction where CBD enters duodenum | CBD posterior to pancreatic head = the key anatomical relationship."},
/*344*/ {"q":"Chorda tendinae connects which structure:","o":["Atrioventricular valve leaflets to papillary muscles","Septomarginal band","Crista terminalis","Cardiac muscle to pericardium"],"a":0,"e":"Chordae tendineae are fibrous cords that connect the free edges and ventricular surfaces of the AV valve leaflets (mitral and tricuspid) to the papillary muscles. They prevent valve leaflet prolapse into the atrium during ventricular systole (when ventricular pressure rises).<br><br>Key discriminator: chordae tendineae → AV valve leaflets to papillary muscles | Rupture → acute severe MR/TR (sail-like prolapse of leaflet) | Papillary muscle ischaemia → functional MR (without chordal rupture) | Chordae tendineae = the anti-prolapse anchors of AV valves."},
/*345*/ {"q":"Mass in ligamentum arteriosum would compress:","o":["Vagus nerve","Phrenic nerve","Right recurrent laryngeal nerve","Left recurrent laryngeal nerve"],"a":3,"e":"The ligamentum arteriosum (remnant of ductus arteriosus) connects the aortic arch to the left pulmonary artery. The left recurrent laryngeal nerve hooks under the aortic arch at this ligament — making it uniquely vulnerable to compression by masses at the ligamentum arteriosum (aortic arch aneurysm, enlarged lymph nodes, tumour).<br><br>Key discriminator: ligamentum arteriosum → hooks LEFT recurrent laryngeal nerve | Right RLN → hooks under right subclavian artery (at lower level) | Mass at ligamentum arteriosum → left RLN palsy → hoarseness | Ortner's syndrome = left RLN palsy from cardiovascular pathology = ligamentum arteriosum compression."}
];
